def test_admin_metrics_source_coverage(api_server_count: int) -> dict[str, object]:
    instance_ids = [f"hai-test-api-{index + 1}" for index in range(max(1, int(api_server_count or 1)))]
    return {
        "ok": True,
        "expected_api_server_count": max(1, int(api_server_count or 1)),
        "successful_source_count": len(instance_ids),
        "distinct_instance_count": len(instance_ids),
        "instance_ids": instance_ids,
        "problems": [],
    }


def quality_result_contract_fixture(expected_mall_id="shop001", checked=3):
    expected_product_url_prefix = f"https://{expected_mall_id}.example.test/product"
    observed_items = []
    for index in range(checked):
        product_id = f"Q{index + 1:03d}"
        section = "top" if index < 3 else "items"
        product_url = f"{expected_product_url_prefix}/{product_id}"
        observed_items.append(
            {
                "section": section,
                "index": index if section == "top" else index - 3,
                "product_id": product_id,
                "mall_id": expected_mall_id,
                "product_url": product_url,
                "product_url_safe": True,
                "product_url_contains_product_id": True,
                "product_url_matches_expected_prefix": True,
                "mall_id_matches_request": True,
            }
        )
    return {
        "ok": True,
        "expected_mall_id": expected_mall_id,
        "expected_product_url_prefix": expected_product_url_prefix,
        "checked": checked,
        "top_count": min(checked, 3),
        "item_count": max(checked - 3, 0),
        "product_url_missing_count": 0,
        "product_url_unsafe_count": 0,
        "product_url_product_id_mismatch_count": 0,
        "product_url_prefix_mismatch_count": 0,
        "mall_id_missing_count": 0,
        "mall_id_mismatch_count": 0,
        "mall_ids": [expected_mall_id] if checked else [],
        "product_ids": [item["product_id"] for item in observed_items],
        "observed_items": observed_items,
        "problems": [],
    }


