def make_png_bytes(width: int = 16, height: int = 16) -> bytes:
    from PIL import Image

    buffer = io.BytesIO()
    Image.new("RGB", (width, height), color=(12, 120, 110)).save(buffer, format="PNG")
    return buffer.getvalue()


def make_transparent_png_bytes(width: int = 32, height: int = 32) -> bytes:
    from PIL import Image

    buffer = io.BytesIO()
    Image.new("RGBA", (width, height), color=(255, 255, 255, 0)).save(buffer, format="PNG")
    return buffer.getvalue()


def make_jpeg_bytes(width: int = 32, height: int = 32) -> bytes:
    from PIL import Image

    buffer = io.BytesIO()
    Image.new("RGB", (width, height), color=(20, 80, 140)).save(buffer, format="JPEG")
    return buffer.getvalue()


def make_oriented_jpeg_bytes(width: int = 20, height: int = 40, orientation: int = 6) -> bytes:
    from PIL import Image

    buffer = io.BytesIO()
    image = Image.new("RGB", (width, height), color=(20, 80, 140))
    exif = image.getexif()
    exif[274] = orientation
    image.save(buffer, format="JPEG", exif=exif)
    return buffer.getvalue()


PNG_BYTES = make_png_bytes()


class HaeorumSearchServiceTest(unittest.TestCase):
    def make_settings(self, log_path: Path) -> Settings:
        return Settings(
            engine_backend="local",
            index_name="test-products",
            search_log_path=log_path,
            product_url_template="https://{mall_id}.example.test/product/{product_id}",
        )

    def make_service(self, products: list[ProductDocument], log_path: Path) -> AISearchService:
        return AISearchService(LocalSearchEngine(products), self.make_settings(log_path))

    def test_text_search_returns_active_top3_and_categories(self) -> None:
        with tempfile.TemporaryDirectory() as temp_dir:
            service = self.make_service(
                [
                    ProductDocument(
                        product_id="P001",
                        name="검정 3단 자동 우산",
                        category="우산",
                        price=8500,
                        status="active",
                        keywords=["검정", "3단", "자동"],
                    ),
                    ProductDocument(
                        product_id="P002",
                        name="고급 장우산",
                        category="우산",
                        price=12000,
                        status="active",
                    ),
                    ProductDocument(
                        product_id="P003",
                        name="비노출 우산",
                        category="우산",
                        status="inactive",
                        display_yn="N",
                    ),
                    ProductDocument(
                        product_id="P004",
                        name="블랙 스텐 텀블러",
                        category="텀블러",
                        status="active",
                    ),
                ],
                Path(temp_dir) / "search.jsonl",
            )

            result = service.search(SearchRequest(mall_id="shop001", q="검은 우산", limit=10))

            self.assertEqual("text", result.meta.query_type.value)
            self.assertEqual("P001", result.top[0].product_id)
            self.assertNotIn("P003", [item.product_id for item in result.top + result.items])
            self.assertIn("우산", result.suggested_categories)
            self.assertTrue(result.top[0].product_url.endswith("/product/P001"))

    def test_text_search_tolerates_single_character_typos(self) -> None:
        with tempfile.TemporaryDirectory() as temp_dir:
            service = self.make_service(
                [
                    ProductDocument(
                        product_id="P001",
                        name="검정 3단 자동 우산",
                        category="우산",
                        status="active",
                    ),
                    ProductDocument(
                        product_id="P002",
                        name="스테인리스 텀블러",
                        category="텀블러",
                        status="active",
                    ),
                ],
                Path(temp_dir) / "search.jsonl",
            )

            result = service.search(SearchRequest(mall_id="shop001", q="우싼", limit=10))

            self.assertEqual("P001", result.top[0].product_id)
            self.assertIn("우산", result.suggested_categories)

    def test_korean_fuzzy_match_requires_same_initial_character(self) -> None:
        self.assertGreater(
            text_relevance_score(
                "우싼",
                ProductDocument(product_id="P001", product_name="우산", category="우산", status="active"),
            ),
            0,
        )
        self.assertEqual(
            0,
            text_relevance_score(
                "다리미",
                ProductDocument(product_id="P002", product_name="뷰리미 마사지기", category="건강가전", status="active"),
            ),
        )

    def test_local_fuzzy_match_is_stable_under_parallel_queries(self) -> None:
        products = [
            ProductDocument(
                product_id=f"P{index:03d}",
                product_name=f"검정 3단 자동 우산 {index}",
                category="우산",
                status="active",
                mall_id="shop001",
            )
            for index in range(80)
        ]
        engine = LocalSearchEngine(products)
        query = EngineQuery(q="우싼", mall_id="shop001", limit=10)

        with ThreadPoolExecutor(max_workers=32) as executor:
            results = list(executor.map(lambda _index: engine.search(query), range(160)))

        self.assertEqual(160, len(results))
        self.assertTrue(all(result and result[0].document.product_id == "P000" for result in results))

    def test_text_rerank_prepares_query_terms_once_for_candidate_window(self) -> None:
        hits = [
            EngineHit(
                ProductDocument(
                    product_id=f"P{index:03d}",
                    product_name=f"검정 우산 후보 {index}",
                    category="우산",
                    status="active",
                ),
                score=0.95 - (index * 0.01),
            )
            for index in range(1, 8)
        ]
        query = EngineQuery(q="검은 우산", limit=3, query_synonyms={"검은": ("검정", "블랙")})

        with patch("app.engine.build_text_relevance_query", wraps=engine_module.build_text_relevance_query) as prepared:
            reranked = engine_module.rerank_text_hits(query, hits)

        self.assertEqual(1, prepared.call_count)
        self.assertEqual([f"P{index:03d}" for index in range(1, 4)], [hit.document.product_id for hit in reranked[:3]])
        self.assertTrue(all("lexical" in hit.source_scores for hit in reranked))

    def test_text_to_image_evidence_rerank_penalizes_unrelated_visual_candidates(self) -> None:
        hits = [
            EngineHit(
                ProductDocument(
                    product_id="P001",
                    product_name="홍보용 정사각 각티슈 50매",
                    category="각티슈/롤티슈",
                    status="active",
                ),
                score=0.64,
                source_scores={"marqo": 0.64, "gemini_image_vector": 0.64},
            ),
            EngineHit(
                ProductDocument(
                    product_id="P002",
                    product_name="[거울메모지] 디자인 폴더 거울 메모",
                    category="점착메모지",
                    status="active",
                ),
                score=0.61,
                source_scores={"marqo": 0.61, "gemini_image_vector": 0.61},
            ),
        ]
        query = EngineQuery(q="포스트잇", inferred_categories=("점착메모지",), limit=2)

        reranked = engine_module.rerank_text_to_image_hits(query, hits)

        self.assertEqual(["P002", "P001"], [hit.document.product_id for hit in reranked])
        self.assertGreater(reranked[0].source_scores["text_evidence"], 0)
        self.assertEqual(0, reranked[1].source_scores["text_evidence"])

    def test_text_search_logs_normalized_query_and_searches_common_corrections(self) -> None:
        with tempfile.TemporaryDirectory() as temp_dir:
            log_path = Path(temp_dir) / "search.jsonl"
            service = self.make_service(
                [
                    ProductDocument(
                        product_id="P001",
                        name="스테인리스 텀블러",
                        category="텀블러",
                        status="active",
                    ),
                    ProductDocument(
                        product_id="P002",
                        name="검정 우산",
                        category="우산",
                        status="active",
                    ),
                ],
                log_path,
            )

            result = service.search(SearchRequest(mall_id="shop001", q="텐블러", limit=10))

            self.assertEqual("P001", result.top[0].product_id)
            log_entry = json.loads(log_path.read_text(encoding="utf-8").splitlines()[0])
            self.assertEqual("텐블러", log_entry["q"])
            self.assertEqual("텀블러", log_entry["normalized_query"])

    def test_category_intent_infers_promotional_categories_and_logs_them(self) -> None:
        with tempfile.TemporaryDirectory() as temp_dir:
            log_path = Path(temp_dir) / "search.jsonl"
            service = self.make_service(
                [
                    ProductDocument(
                        product_id="P001",
                        name="호텔 라인 답례품",
                        category="타올",
                        status="active",
                    ),
                    ProductDocument(
                        product_id="P002",
                        name="호텔 라인 머그",
                        category="텀블러",
                        status="active",
                    ),
                ],
                log_path,
            )

            result = service.search(SearchRequest(mall_id="shop001", q="호텔 수건", limit=10))

            self.assertEqual(("타올",), infer_category_intents("호텔 수건", limit=1))
            self.assertEqual("P001", result.top[0].product_id)
            self.assertGreater(result.top[0].source_scores["category_intent"], 0)
            self.assertEqual("타올", result.suggested_categories[0])
            log_entry = json.loads(log_path.read_text(encoding="utf-8").splitlines()[0])
            self.assertEqual(["타올"], log_entry["inferred_categories"])

    def test_repeated_query_normalization_uses_bounded_lru_cache(self) -> None:
        for function in [normalize_query_spacing, normalize_query_text, build_search_query, infer_category_intents]:
            function.cache_clear()

        for _ in range(8):
            self.assertEqual("텀블러", normalize_query_text("텐블러"))
            self.assertEqual("텀블러 텐블러", build_search_query("텐블러", "텀블러"))
            self.assertEqual("우산", normalize_query_text("우싼"))
            self.assertEqual("우산 우싼", build_search_query("우싼", "우산"))
            self.assertEqual("에코백", normalize_query_text("에코빽"))
            self.assertEqual(("타올",), infer_category_intents("호텔 수건", limit=1))
            self.assertEqual(("부채",), infer_category_intents("노란부채", limit=1))
            self.assertEqual(("달력",), infer_category_intents("카렌다", limit=1))

        self.assertGreaterEqual(normalize_query_text.cache_info().hits, 7)
        self.assertGreaterEqual(build_search_query.cache_info().hits, 7)
        self.assertGreaterEqual(infer_category_intents.cache_info().hits, 7)
        self.assertEqual(4096, normalize_query_text.cache_info().maxsize)
        self.assertEqual(4096, infer_category_intents.cache_info().maxsize)

