    def test_local_engine_handles_search_while_products_change(self) -> None:
        engine = LocalSearchEngine(
            [
                ProductDocument(product_id="P001", name="검정 우산", category="우산", status="active"),
                ProductDocument(product_id="P002", name="스텐 텀블러", category="텀블러", status="active"),
            ]
        )

        def search_once(_: int) -> list[str]:
            return [hit.document.product_id for hit in engine.search(EngineQuery(q="우산", limit=10))]

        def mutate_products(_: int) -> int:
            indexed = 0
            for index in range(25):
                product_id = f"PX{index:03d}"
                result = engine.upsert_products(
                    [ProductDocument(product_id=product_id, name=f"추가 우산 {index}", category="우산", status="active")]
                )
                indexed += int(result["indexed"])
                engine.delete_products([product_id])
            return indexed

        with ThreadPoolExecutor(max_workers=8) as pool:
            search_futures = [pool.submit(search_once, index) for index in range(100)]
            mutation_futures = [pool.submit(mutate_products, index) for index in range(4)]

        self.assertTrue(all("P001" in future.result() for future in search_futures))
        self.assertEqual([25, 25, 25, 25], [future.result() for future in mutation_futures])
        self.assertEqual("P001", engine.search(EngineQuery(q="우산", limit=10))[0].document.product_id)

