    def test_local_engine_reuses_expanded_record_terms_for_custom_synonyms(self) -> None:
        engine = LocalSearchEngine(
            [
                ProductDocument(product_id="P001", name="검정 우산", category="우산", status="active"),
                ProductDocument(product_id="P002", name="스텐 텀블러", category="텀블러", status="active"),
            ]
        )
        query_synonyms = {
            **{f"동의어{index}": (f"대체{index}", f"표현{index}") for index in range(200)},
            "우산": ("umbrella", "장우산"),
            "텀블러": ("tumbler",),
        }

        first = engine.search(EngineQuery(q="우산", limit=10, query_synonyms=query_synonyms))
        cache_size_after_first = len(engine._expanded_terms_cache)
        second = engine.search(EngineQuery(q="텀블러", limit=10, query_synonyms=query_synonyms))

        self.assertEqual("P001", first[0].document.product_id)
        self.assertEqual("P002", second[0].document.product_id)
        self.assertGreater(cache_size_after_first, 0)
        self.assertEqual(cache_size_after_first, len(engine._expanded_terms_cache))

        self.assertEqual([], engine.search(EngineQuery(q="플라스크", limit=10, query_synonyms=query_synonyms)))
        digest_before_mutation = engine._expanded_terms_synonym_digests[id(query_synonyms)]
        query_synonyms["텀블러"] = ("tumbler", "플라스크")
        mutated = engine.search(EngineQuery(q="플라스크", limit=10, query_synonyms=query_synonyms))

        self.assertEqual("P002", mutated[0].document.product_id)
        self.assertNotEqual(digest_before_mutation, engine._expanded_terms_synonym_digests[id(query_synonyms)])

        engine.upsert_products([ProductDocument(product_id="P003", name="흰 우산", category="우산", status="active")])

        self.assertEqual(0, len(engine._expanded_terms_cache))

