    def test_local_engine_uses_mall_bucket_for_strict_mall_filter(self) -> None:
        products = [
            ProductDocument(
                product_id=f"P{index:04d}",
                name="공통 우산",
                category="우산",
                status="active",
                mall_id=f"shop{index:04d}",
            )
            for index in range(1, 1701)
        ]
        engine = LocalSearchEngine(products)
        visited = 0
        original_match = engine_module.product_matches_prepared_filters

        def counting_match(product: ProductDocument, filters: engine_module.PreparedProductFilters) -> bool:
            nonlocal visited
            visited += 1
            return original_match(product, filters)

        with patch("app.engine.product_matches_prepared_filters", side_effect=counting_match), patch(
            "app.engine.prepare_product_filters",
            wraps=engine_module.prepare_product_filters,
        ) as prepare:
            hits = engine.search(
                EngineQuery(
                    q="우산",
                    mall_id="shop0420",
                    category="우산",
                    strict_mall_filter=True,
                    limit=10,
                )
            )

        self.assertEqual(["P0420"], [hit.document.product_id for hit in hits])
        self.assertEqual(1, visited)
        self.assertEqual(1, prepare.call_count)
        self.assertEqual(1700, engine.health()["mall_buckets"])

        delete_result = engine.delete_products([product_document_id("shop0420", "P0420")])

        self.assertEqual(1, delete_result["deleted"])
        self.assertEqual([], engine.search(EngineQuery(q="우산", mall_id="shop0420", strict_mall_filter=True, limit=10)))
        self.assertEqual(1699, engine.health()["mall_buckets"])

