    def test_limit_applies_to_related_items_after_top3(self) -> None:
        with tempfile.TemporaryDirectory() as temp_dir:
            service = self.make_service(
                [
                    ProductDocument(
                        product_id=f"P{index:03d}",
                        name=f"검정 우산 {index}",
                        category="우산",
                        status="active",
                    )
                    for index in range(1, 9)
                ],
                Path(temp_dir) / "search.jsonl",
            )

            result = service.search(SearchRequest(mall_id="shop001", q="우산", limit=2))

            self.assertEqual(["P001", "P002", "P003"], [item.product_id for item in result.top])
            self.assertEqual(["P004", "P005"], [item.product_id for item in result.items])
            self.assertEqual(2, result.meta.limit)
            self.assertEqual(0, result.meta.offset)
            self.assertTrue(result.meta.has_more)
            self.assertEqual(2, result.meta.next_offset)

            next_page = service.search(SearchRequest(mall_id="shop001", q="우산", limit=2, offset=2))

            self.assertEqual(["P001", "P002", "P003"], [item.product_id for item in next_page.top])
            self.assertEqual(["P006", "P007"], [item.product_id for item in next_page.items])
            self.assertEqual(2, next_page.meta.offset)
            self.assertTrue(next_page.meta.has_more)
            self.assertEqual(4, next_page.meta.next_offset)

            last_page = service.search(SearchRequest(mall_id="shop001", q="우산", limit=2, offset=4))

            self.assertEqual(["P008"], [item.product_id for item in last_page.items])
            self.assertFalse(last_page.meta.has_more)
            self.assertIsNone(last_page.meta.next_offset)

