    def test_search_refetches_when_product_group_variants_exhaust_initial_candidates(self) -> None:
        class RecordingLocalSearchEngine(LocalSearchEngine):
            def __init__(self, products):  # type: ignore[no-untyped-def]
                super().__init__(products)
                self.query_limits: list[int] = []

            def search(self, query: EngineQuery):  # type: ignore[no-untyped-def]
                self.query_limits.append(query.limit)
                return super().search(query)

        with tempfile.TemporaryDirectory() as temp_dir:
            products = [
                ProductDocument(
                    product_id=f"P{index:03d}",
                    name=f"검정 우산 옵션 {index}",
                    category="우산",
                    status="active",
                    product_group_id="G-UMBRELLA",
                )
                for index in range(1, 31)
            ]
            products.extend(
                ProductDocument(
                    product_id=f"P{index:03d}",
                    name=f"검정 우산 고유 {index}",
                    category="우산",
                    status="active",
                    product_group_id=f"G-UNIQUE-{index:03d}",
                )
                for index in range(31, 37)
            )
            settings = self.make_settings(Path(temp_dir) / "search.jsonl")
            engine = RecordingLocalSearchEngine(products)
            service = AISearchService(engine, settings, cache=MemorySearchCache(0))

            result = service.search(SearchRequest(mall_id="shop001", q="검정 우산", limit=2))

            self.assertEqual([12, 72], engine.query_limits)
            self.assertEqual(["P001", "P031", "P032"], [item.product_id for item in result.top])
            self.assertEqual(["P033", "P034"], [item.product_id for item in result.items])
            self.assertTrue(result.meta.has_more)
            self.assertEqual(2, result.meta.next_offset)
            log_entry = json.loads((Path(temp_dir) / "search.jsonl").read_text(encoding="utf-8").splitlines()[0])
            self.assertEqual(2, log_entry["engine_search_attempts"])
            self.assertEqual(1, log_entry["engine_adaptive_refetches"])
            self.assertEqual([12, 72], log_entry["engine_candidate_limits"])
            self.assertEqual([12, 36], log_entry["engine_raw_candidate_counts"])
            self.assertEqual([1, 7], log_entry["engine_collapsed_candidate_counts"])
            self.assertEqual(72, log_entry["engine_final_candidate_limit"])
            self.assertEqual(36, log_entry["engine_final_raw_candidate_count"])
            self.assertEqual(7, log_entry["engine_final_collapsed_candidate_count"])
            self.assertFalse(log_entry["engine_underfilled_after_max_candidates"])

    def test_mixed_search_uses_default_weights_and_image_hash(self) -> None:
        image = validate_image_bytes(PNG_BYTES, max_bytes=1024)
        image_b64 = base64.b64encode(PNG_BYTES).decode("ascii")
        with tempfile.TemporaryDirectory() as temp_dir:
            log_path = Path(temp_dir) / "search.jsonl"
            service = self.make_service(
                [
                    ProductDocument(
                        product_id="P010",
                        name="블랙 스텐 텀블러",
                        category="텀블러",
                        status="active",
                        keywords=["블랙", "텀블러"],
                        extra={"image_hash": image.sha256, "image_tags": ["black", "tumbler"]},
                    ),
                    ProductDocument(
                        product_id="P011",
                        name="화이트 보온병",
                        category="텀블러",
                        status="active",
                        keywords=["화이트", "보온병"],
                        extra={"image_tags": ["white", "tumbler"]},
                    ),
                ],
                log_path,
            )

            result = service.search(SearchRequest(mall_id="shop001", q="검은색", image_base64=image_b64, limit=10))

            self.assertEqual("text_image", result.meta.query_type.value)
            self.assertAlmostEqual(0.4, result.meta.text_weight)
            self.assertAlmostEqual(0.6, result.meta.image_weight)
            self.assertEqual("P010", result.top[0].product_id)
            self.assertGreater(result.top[0].source_scores["image"], 0.99)
            log_entry = json.loads(log_path.read_text(encoding="utf-8").splitlines()[0])
            self.assertAlmostEqual(0.4, log_entry["text_weight"])
            self.assertAlmostEqual(0.6, log_entry["image_weight"])
            self.assertGreater(log_entry["top_source_scores"]["image"], 0.99)
            self.assertEqual(image.sha256, log_entry["image_hash"])
            self.assertEqual(image.perceptual_hash, log_entry["image_perceptual_hash"])
            self.assertEqual(image.size_bytes, log_entry["image_size_bytes"])
            self.assertEqual(image.width, log_entry["image_width"])
            self.assertEqual(image.height, log_entry["image_height"])
            self.assertEqual(image.normalized, log_entry["image_normalized"])
            self.assertEqual(list(image.quality_warnings), log_entry["image_quality_warnings"])

