    def test_search_request_rejects_invalid_weights(self) -> None:
        with self.assertRaises(ValueError):
            SearchRequest(mall_id="shop001", q="우산", text_weight=-0.1)

        with self.assertRaises(ValueError):
            SearchRequest(mall_id="shop001", q="우산", image_base64="AAAA", text_weight=0, image_weight=0)

        with self.assertRaises(ValueError):
            SearchRequest(mall_id="shop001", q="우산", offset=-1)

        with self.assertRaises(ValueError):
            SearchRequest(mall_id="shop001", q="우산", min_price=2000, max_price=1000)

        with self.assertRaises(ValueError):
            SearchRequest(mall_id="shop001", q="우산", quantity=0)

        with self.assertRaisesRegex(ValueError, "text_weight must be finite"):
            SearchRequest(mall_id="shop001", q="우산", text_weight=float("nan"))

        with self.assertRaisesRegex(ValueError, "max_price must be finite"):
            SearchRequest(mall_id="shop001", q="우산", max_price=float("inf"))

