    def test_public_openapi_contract_includes_json_and_multipart_search(self) -> None:
        schema = load_public_openapi_schema()
        search_post = schema["paths"]["/api/ai-search"]["post"]
        click_post = schema["paths"]["/api/click-log"]["post"]
        insights_get = schema["paths"]["/admin/search-insights"]["get"]
        sync_log_get = schema["paths"]["/admin/sync-log"]["get"]
        request_content = search_post["requestBody"]["content"]
        unsafe_credential_fields = {
            "api_key",
            "apiKey",
            "apikey",
            "api-key",
            "x-api-key",
            "admin_key",
            "admin-key",
            "x-admin-key",
        }

        self.assertIn("application/json", request_content)
        self.assertIn("multipart/form-data", request_content)
        json_examples = request_content["application/json"]["examples"]
        self.assertIn("text", json_examples)
        self.assertIn("image", json_examples)
        self.assertIn("mixed", json_examples)
        self.assertIn("image_base64", json_examples["image"]["value"])
        multipart_examples = request_content["multipart/form-data"]["examples"]
        self.assertIn("image", multipart_examples)
        self.assertIn("mixed", multipart_examples)
        self.assertIn("site_id_alias", multipart_examples)
        self.assertIn("image", multipart_examples["mixed"]["value"])
        self.assertEqual("shop001", multipart_examples["site_id_alias"]["value"]["site_id"])
        multipart_schema = request_content["multipart/form-data"]["schema"]
        self.assertFalse(multipart_schema["additionalProperties"])
        self.assertFalse(schema["components"]["schemas"]["SearchRequest"]["additionalProperties"])
        self.assertFalse(schema["components"]["schemas"]["ClickLogRequest"]["additionalProperties"])
        self.assertEqual(set(MULTIPART_SEARCH_FIELDS), set(multipart_schema["properties"]))
        self.assertFalse(unsafe_credential_fields & set(schema["components"]["schemas"]["SearchRequest"]["properties"]))
        self.assertFalse(unsafe_credential_fields & set(schema["components"]["schemas"]["ClickLogRequest"]["properties"]))
        self.assertFalse(unsafe_credential_fields & set(multipart_schema["properties"]))
        for operation in [search_post, click_post]:
            description = operation["description"]
            self.assertIn("X-API-Key", description)
            self.assertIn("api-key", description)
            self.assertIn("x-api-key", description)
            self.assertIn("admin_key", description)
            self.assertIn("x-admin-key", description)
        self.assertIn("site_id", multipart_schema["properties"])
        click_schema = schema["components"]["schemas"]["ClickLogRequest"]
        self.assertEqual(["product_id"], click_schema["required"])
        click_identity_any_of = [set(option["required"]) for option in click_schema["anyOf"]]
        self.assertIn({"mall_id"}, click_identity_any_of)
        self.assertIn({"site_id"}, click_identity_any_of)
        self.assertEqual("binary", multipart_schema["properties"]["image"]["format"])
        self.assertIn("최소 가로/세로", multipart_schema["properties"]["image"]["description"])
        self.assertIn(
            "HAEORUM_MIN_IMAGE_DIMENSION",
            schema["components"]["schemas"]["SearchRequest"]["properties"]["image_base64"]["description"],
        )
        for field_name in ["print_method", "material", "color", "min_price", "max_price", "quantity", "order_qty", "max_delivery_days"]:
            self.assertIn(field_name, schema["components"]["schemas"]["SearchRequest"]["properties"])
            self.assertIn(field_name, multipart_schema["properties"])
        self.assertIn({"required": ["image"]}, multipart_schema["anyOf"])
        response_schema = search_post["responses"]["200"]["content"]["application/json"]["schema"]
        self.assertEqual("#/components/schemas/SearchResponse", response_schema["$ref"])
        self.assertEqual("#/components/responses/Forbidden", search_post["responses"]["403"]["$ref"])
        self.assertEqual("#/components/responses/BadGateway", search_post["responses"]["502"]["$ref"])
        self.assertEqual("#/components/responses/ServiceUnavailable", search_post["responses"]["503"]["$ref"])
        self.assertEqual("#/components/responses/BadRequest", click_post["responses"]["400"]["$ref"])
        self.assertEqual("#/components/responses/Forbidden", click_post["responses"]["403"]["$ref"])
        self.assertEqual("#/components/responses/RateLimited", click_post["responses"]["429"]["$ref"])
        self.assertNotIn("PublicApiKeyQuery", schema["components"]["securitySchemes"])
        self.assertIn("header", schema["components"]["securitySchemes"]["PublicApiKey"]["in"])
        self.assertIn("URL query string", schema["components"]["securitySchemes"]["PublicApiKey"]["description"])
        self.assertIn("공개 API request body", schema["components"]["securitySchemes"]["AdminApiKey"]["description"])
        self.assertEqual(
            "#/components/schemas/SearchInsightsReport",
            insights_get["responses"]["200"]["content"]["application/json"]["schema"]["$ref"],
        )
        insight_params = {parameter["name"] for parameter in insights_get["parameters"]}
        self.assertTrue({"limit", "min_searches", "slow_text_ms", "slow_image_ms", "slow_mixed_ms"}.issubset(insight_params))
        self.assertIn(
            "mixed_weight_performance",
            schema["components"]["schemas"]["SearchInsightsReport"]["properties"],
        )
        for field_name in ["latency_ms", "query_type_latency_ms", "cache_latency_ms", "slow_queries", "slow_search_samples"]:
            self.assertIn(field_name, schema["components"]["schemas"]["SearchInsightsReport"]["properties"])
        self.assertEqual("최근 동기화/색인 로그 조회", sync_log_get["summary"])
        self.assertEqual(
            "array",
            sync_log_get["responses"]["200"]["content"]["application/json"]["schema"]["type"],
        )

