    def test_api_smoke_validates_search_response_contract(self) -> None:
        item = {
            "product_id": "P001",
            "name": "검정 3단 자동 우산",
            "category": "우산",
            "price": 8500,
            "image_url": "https://image.example.test/p001.jpg",
            "product_url": "https://shop001.example.test/product/P001",
            "score": 0.91,
            "score_percent": 91.0,
            "mall_id": "shop001",
            "source_scores": {"text": 0.91},
        }
        response = {
            "top": [item],
            "items": [{**item, "product_id": "P002", "product_url": "https://shop001.example.test/product/P002"}],
            "suggested_categories": ["우산"],
            "meta": {
                "query_type": "text",
                "elapsed_ms": 100.0,
                "engine": "marqo",
                "limit": 20,
                "offset": 0,
                "has_more": False,
                "next_offset": None,
                "mall_id": "shop001",
                "text_weight": 1.0,
                "image_weight": None,
                "low_confidence": False,
                "notice": None,
            },
        }

        details = validate_api_smoke_search_response(response, "text", "text search", "shop001")
        self.assertTrue(details["response_contract_ok"])
        self.assertEqual("shop001", details["expected_mall_id"])
        self.assertEqual("shop001", details["meta_mall_id"])
        self.assertEqual(["shop001", "shop001"], details["result_mall_ids"])
        self.assertEqual("text", details["query_type"])
        self.assertEqual("marqo", details["engine"])
        self.assertEqual(1, details["top_count"])
        self.assertEqual(1, details["item_count"])

        prefix_details = validate_api_smoke_search_response(
            response,
            "text",
            "text search",
            "shop001",
            "https://shop001.example.test/product",
        )
        self.assertEqual("https://shop001.example.test/product", prefix_details["expected_product_url_prefix"])
        self.assertEqual(0, prefix_details["product_url_prefix_mismatch_count"])
        self.assertEqual(
            ["https://shop001.example.test/product/P001", "https://shop001.example.test/product/P002"],
            prefix_details["result_product_urls"],
        )

        wrong_meta_mall_id = {**response, "meta": {**response["meta"], "mall_id": "shop999"}}
        with self.assertRaisesRegex(AssertionError, "meta mall_id must match requested mall_id"):
            validate_api_smoke_search_response(wrong_meta_mall_id, "text", "text search", "shop001")

        missing_top_mall_id = {**response, "top": [{**item, "mall_id": None}]}
        with self.assertRaisesRegex(AssertionError, r"top\[0\] mall_id must be a non-empty string"):
            validate_api_smoke_search_response(missing_top_mall_id, "text", "text search", "shop001")

        wrong_top_mall_id = {**response, "top": [{**item, "mall_id": "shop999"}]}
        with self.assertRaisesRegex(AssertionError, r"top\[0\] mall_id must match requested mall_id"):
            validate_api_smoke_search_response(wrong_top_mall_id, "text", "text search", "shop001")

        bad_response = {**response, "top": [{"product_id": "P001"}]}
        with self.assertRaisesRegex(AssertionError, "missing fields"):
            validate_api_smoke_search_response(bad_response, "text", "text search")

        bad_meta = {**response, "meta": {"query_type": "image"}}
        with self.assertRaisesRegex(AssertionError, "meta missing fields"):
            validate_api_smoke_search_response(bad_meta, "text", "text search")

        bad_pagination = {**response, "meta": {**response["meta"], "has_more": True, "next_offset": None}}
        with self.assertRaisesRegex(AssertionError, "next_offset is required"):
            validate_api_smoke_search_response(bad_pagination, "text", "text search")

        bad_next_offset = {**response, "meta": {**response["meta"], "has_more": True, "next_offset": 2}}
        with self.assertRaisesRegex(AssertionError, "next_offset must equal offset plus"):
            validate_api_smoke_search_response(bad_next_offset, "text", "text search")

        too_many_related = {
            **response,
            "items": [{**item, "product_id": "P002"}, {**item, "product_id": "P003"}],
            "meta": {**response["meta"], "limit": 1},
        }
        with self.assertRaisesRegex(AssertionError, "must not exceed meta.limit"):
            validate_api_smoke_search_response(too_many_related, "text", "text search")

        bad_weight = {**response, "meta": {**response["meta"], "text_weight": -0.1}}
        with self.assertRaisesRegex(AssertionError, "text_weight must be non-negative"):
            validate_api_smoke_search_response(bad_weight, "text", "text search")

        bad_source_scores = {**response, "top": [{**item, "source_scores": "text=0.91"}]}
        with self.assertRaisesRegex(AssertionError, "source_scores"):
            validate_api_smoke_search_response(bad_source_scores, "text", "text search")

        bad_price = {**response, "top": [{**item, "price": -1}]}
        with self.assertRaisesRegex(AssertionError, "price must be finite and non-negative"):
            validate_api_smoke_search_response(bad_price, "text", "text search")

        unsafe_url = {**response, "top": [{**item, "image_url": "https://token@images.example.test/p001.jpg"}]}
        with self.assertRaisesRegex(AssertionError, "safe public"):
            validate_api_smoke_search_response(unsafe_url, "text", "text search")

        wrong_product_url = {
            **response,
            "items": [{**item, "product_id": "P002", "product_url": "https://shop001.example.test/product/P999"}],
        }
        with self.assertRaisesRegex(AssertionError, "product_url must contain product_id"):
            validate_api_smoke_search_response(wrong_product_url, "text", "text search", "shop001")

        wrong_product_url_prefix = {
            **response,
            "top": [{**item, "product_url": "https://other-shop.example.test/product/P001"}],
        }
        with self.assertRaisesRegex(AssertionError, "product URL prefix"):
            validate_api_smoke_search_response(
                wrong_product_url_prefix,
                "text",
                "text search",
                "shop001",
                "https://shop001.example.test/product",
            )

        bad_score = {**response, "top": [{**item, "score_percent": 101}]}
        with self.assertRaisesRegex(AssertionError, "score_percent must be 0..100"):
            validate_api_smoke_search_response(bad_score, "text", "text search")

        repeated_top_item = {**response, "items": [item]}
        with self.assertRaisesRegex(AssertionError, "related items must exclude top"):
            validate_api_smoke_search_response(repeated_top_item, "text", "text search")

        duplicate_categories = {**response, "suggested_categories": ["우산", "우산"]}
        with self.assertRaisesRegex(AssertionError, "suggested_categories must be unique"):
            validate_api_smoke_search_response(duplicate_categories, "text", "text search")

    def test_api_smoke_rejects_sensitive_markers_in_admin_logs(self) -> None:
        args = type(
            "Args",
            (),
            {
                "api_key": "public-key-123",
                "admin_key": "admin-key-456",
                "invalid_api_key": "invalid-public-key-789",
                "invalid_admin_key": "invalid-admin-key-012",
            },
        )()
        image_payload = "data:image/png;base64," + base64.b64encode(PNG_BYTES).decode("ascii")
        markers = sensitive_log_markers(args, [image_payload])

        self.assertIn("public-key-123", markers)
        self.assertIn("admin-key-456", markers)
        self.assertIn(image_payload, markers)
        self.assertIn(image_payload.split(",", 1)[1], markers)
        details = assert_no_sensitive_log_markers(
            [{"type": "search", "api_key": "[REDACTED]", "image_base64": "[REDACTED]"}],
            markers,
            "search_log",
        )
        self.assertTrue(details["sensitive_log_redaction_ok"])

        with self.assertRaisesRegex(AssertionError, "unredacted sensitive marker"):
            assert_no_sensitive_log_markers([{"header": "public-key-123"}], markers, "search_log")
        with self.assertRaisesRegex(AssertionError, "fixed_patterns"):
            assert_no_sensitive_log_markers([{"image_base64": image_payload}], [], "search_log")

