    def test_upload_reader_rejects_oversized_stream_before_full_read(self) -> None:
        class FakeUpload:
            def __init__(self, raw: bytes):
                self.raw = bytearray(raw)
                self.read_sizes: list[int] = []

            async def read(self, size: int = -1) -> bytes:
                self.read_sizes.append(size)
                if not self.raw:
                    return b""
                if size < 0:
                    size = len(self.raw)
                chunk = bytes(self.raw[:size])
                del self.raw[:size]
                return chunk

        accepted = asyncio.run(read_upload_bytes_limited(FakeUpload(b"abcde"), max_bytes=5, chunk_size=2))
        self.assertEqual(b"abcde", accepted)

        oversized = FakeUpload(b"abcdef")
        with self.assertRaisesRegex(ValueError, "image exceeds 5 bytes"):
            asyncio.run(read_upload_bytes_limited(oversized, max_bytes=5, chunk_size=2))
        self.assertTrue(all(size <= 2 for size in oversized.read_sizes[:-1]))

