    def test_csv_index_script_dry_runs_and_indexes_poc_csv(self) -> None:
        with tempfile.TemporaryDirectory() as temp_dir:
            csv_path = Path(temp_dir) / "poc-products.csv"
            csv_path.write_text(
                "\n".join(
                    [
                        "product_id,product_name,category_name,status,display_yn,price,main_image_url,updated_at",
                        "P001,검정 우산,우산,active,Y,8500,https://img.example.test/p001.jpg,2026-05-01T00:00:00Z",
                        "P002,숨김 우산,우산,inactive,N,9000,https://img.example.test/p002.jpg,2026-05-02T00:00:00Z",
                    ]
                )
                + "\n",
                encoding="utf-8",
            )
            sync_log = Path(temp_dir) / "sync.jsonl"
            args = type(
                "Args",
                (),
                {
                    "csv": str(csv_path),
                    "mode": "reindex",
                    "since": None,
                    "engine": "local",
                    "index_name": "poc-index",
                    "marqo_url": "",
                    "marqo_model": "",
                    "sync_log": str(sync_log),
                    "validate_images": False,
                    "dry_run": True,
                },
            )()
            settings = Settings(engine_backend="local", sync_log_path=sync_log)

            dry_run = run_csv_index(args, base_settings=settings)
            self.assertTrue(dry_run["ok"])
            self.assertTrue(dry_run["dry_run"])
            self.assertEqual(2, dry_run["summary"]["total_products"])
            self.assertEqual(1, dry_run["would_index"])
            self.assertEqual(1, dry_run["would_delete"])
            self.assertFalse(dry_run["persistent_index"])
            self.assertTrue(dry_run["csv_fingerprint"]["exists"])
            self.assertRegex(dry_run["csv_fingerprint"]["digest"], r"^[0-9a-f]{64}$")

            args.dry_run = False
            indexed = run_csv_index(args, base_settings=settings)
            self.assertTrue(indexed["ok"])
            self.assertEqual(1, indexed["indexed"])
            self.assertEqual(0, indexed["failed"])
            self.assertEqual("poc-index", indexed["index"])
            self.assertEqual(1, indexed["expected_index_document_count"])
            self.assertEqual(1, indexed["post_index_document_count"])
            self.assertTrue(indexed["post_index_document_count_ok"])
            self.assertEqual(dry_run["csv_fingerprint"]["digest"], indexed["csv_fingerprint"]["digest"])
            self.assertTrue(sync_log.exists())

    def test_csv_index_reindex_fails_when_post_index_document_count_drifts(self) -> None:
        class StaleCountEngine(LocalSearchEngine):
            def health(self) -> dict[str, object]:
                return {"engine": self.name, "products": 2, "ready": True}

        with tempfile.TemporaryDirectory() as temp_dir:
            csv_path = Path(temp_dir) / "poc-products.csv"
            csv_path.write_text(
                "\n".join(
                    [
                        "product_id,product_name,category_name,status,display_yn,price,main_image_url,updated_at",
                        "P001,검정 우산,우산,active,Y,8500,https://img.example.test/p001.jpg,2026-05-01T00:00:00Z",
                    ]
                )
                + "\n",
                encoding="utf-8",
            )
            args = type(
                "Args",
                (),
                {
                    "csv": str(csv_path),
                    "mode": "reindex",
                    "since": None,
                    "engine": "local",
                    "index_name": "poc-index",
                    "marqo_url": "",
                    "marqo_model": "",
                    "sync_log": str(Path(temp_dir) / "sync.jsonl"),
                    "validate_images": False,
                    "dry_run": False,
                },
            )()
            with patch("scripts.csv_index.create_search_engine", return_value=StaleCountEngine()):
                report = run_csv_index(args, base_settings=Settings(engine_backend="local"))

        self.assertFalse(report["ok"])
        self.assertEqual(1, report["indexed"])
        self.assertEqual(1, report["expected_index_document_count"])
        self.assertEqual(2, report["post_index_document_count"])
        self.assertFalse(report["post_index_document_count_ok"])
        self.assertIn("post-index document count", report["post_index_document_count_problem"])

