    def test_operational_evidence_collector_cross_checks_primary_mall_against_mall_config(self) -> None:
        with tempfile.TemporaryDirectory() as temp_dir:
            mall_config = Path(temp_dir) / "malls.json"
            mall_config.write_text(
                json.dumps(
                    {
                        "malls": [
                            {
                                "mall_id": "shop001",
                                "enabled": True,
                                "api_key": "pk_live_shop001_abcdefghijklmnopqrstuvwxyz",
                                "allowed_origins": ["https://shop001.example.test"],
                                "product_url_template": "https://shop001.example.test/product/{product_id}",
                            },
                            {
                                "mall_id": "shop002",
                                "enabled": True,
                                "api_key": "pk_live_shop002_abcdefghijklmnopqrstuvwxyz",
                                "allowed_origins": ["https://shop002.example.test"],
                                "product_url_template": "https://shop002.example.test/product/{product_id}",
                            },
                        ]
                    }
                ),
                encoding="utf-8",
            )

            wrong_origin = input_file_validation_problems(
                {
                    "required_files": {"mall_config": str(mall_config)},
                    "file_validation_context": {
                        "expected_malls": "2",
                        "mall_id": "shop001",
                        "origin": "https://wrong.example.test",
                    },
                }
            )
            missing_mall = input_file_validation_problems(
                {
                    "required_files": {"mall_config": str(mall_config)},
                    "file_validation_context": {
                        "expected_malls": "2",
                        "mall_id": "shop999",
                        "origin": "https://shop999.example.test",
                    },
                }
            )
            wrong_api_key = input_file_validation_problems(
                {
                    "required_files": {"mall_config": str(mall_config)},
                    "file_validation_context": {
                        "expected_malls": "2",
                        "mall_id": "shop001",
                        "origin": "https://shop001.example.test",
                        "api_key_hash": api_key_hash("pk_live_wrong_shop001_abcdefghijklmnopqrstuvwxyz"),
                    },
                }
            )

            self.assertEqual(["mall_config"], [problem["name"] for problem in wrong_origin])
            self.assertIn(
                "configured origin 'https://wrong.example.test' is not allowed for mall_id 'shop001'; allowed_origins=['https://shop001.example.test']",
                wrong_origin[0]["problems"],
            )
            self.assertEqual(["mall_config"], [problem["name"] for problem in missing_mall])
            self.assertIn("configured mall_id 'shop999' is not enabled in mall_config", missing_mall[0]["problems"])
            self.assertEqual(["mall_config"], [problem["name"] for problem in wrong_api_key])
            self.assertIn(
                "configured api_key does not match mall_config api_key for mall_id 'shop001'",
                wrong_api_key[0]["problems"],
            )

