    def test_api_smoke_rejects_unsafe_target_before_requests(self) -> None:
        def unexpected_request(*args: object, **kwargs: object) -> tuple[int, dict[str, object], float]:
            raise AssertionError("smoke test should reject unsafe target before making HTTP requests")

        base_args = {
            "base_url": "https://ai.example.test",
            "mall_id": "shop001",
            "api_key": "public-shop001",
            "origin": "https://shop001.example.test",
            "invalid_api_key": "invalid-smoke-api-key",
            "invalid_origin": "https://invalid-origin.example.test",
            "invalid_admin_key": "invalid-smoke-admin-key",
            "admin_key": "prod-admin-key",
            "oversized_upload_mb": 1,
            "expect_click_rate_limit": False,
            "click_rate_limit_probe_count": 0,
        }
        cases = [
            ({"base_url": "https://user:pass@ai.example.test?token=secret"}, "--base-url must not include credentials"),
            ({"origin": "https://shop001.example.test/path"}, "--origin must include only scheme"),
            ({"invalid_origin": "https://169.254.169.254"}, "--invalid-origin must not use non-public"),
            ({"base_url": "https://10.0.0.5"}, "--base-url must not use non-public"),
            ({"origin": "https://192.168.1.5"}, "--origin must not use non-public"),
        ]

        for override, expected_error in cases:
            with self.subTest(override=override):
                args = type("Args", (), {**base_args, **override})()
                with patch("scripts.api_smoke_test.request_json", unexpected_request):
                    report = run_api_smoke(args)

                serialized = json.dumps(report, ensure_ascii=False)
                self.assertFalse(report["ok"])
                self.assertEqual("target_validation", report["checks"][0]["name"])
                self.assertIn(expected_error, report["target_validation"]["error"])
                self.assertNotIn("secret", serialized)
                self.assertNotIn("pass@", serialized)

        local_args = type("Args", (), {**base_args, "base_url": "http://localhost:8000", "allow_local_target": True})()
        target_validation = validate_api_smoke_args(local_args)
        self.assertTrue(target_validation["ok"])
        self.assertEqual("http://localhost:8000", target_validation["base_url"])

