    def test_log_tail_is_bounded_and_reads_recent_jsonl_entries(self) -> None:
        with tempfile.TemporaryDirectory() as temp_dir:
            log_path = Path(temp_dir) / "search.jsonl"
            log_path.write_text("not-json\n", encoding="utf-8")
            logger = SearchLogger(log_path)
            for index in range(5):
                logger.write({"type": "search", "index": index})

            self.assertEqual([3, 4], [entry["index"] for entry in logger.tail(2)])
            self.assertEqual([4], [entry["index"] for entry in logger.tail(0)])
            self.assertEqual([0, 1, 2, 3, 4], [entry["index"] for entry in logger.tail(1000000)])
            self.assertEqual(1, normalize_tail_limit(-10))
            self.assertEqual(1000, normalize_tail_limit(1000000))

            large_log_path = Path(temp_dir) / "large-search.jsonl"
            large_log_path.write_text(
                "".join(json.dumps({"type": "search", "index": index}, ensure_ascii=False) + "\n" for index in range(1105)),
                encoding="utf-8",
            )
            large_tail = SearchLogger(large_log_path).tail(1000000)
            self.assertEqual(1000, len(large_tail))
            self.assertEqual(105, large_tail[0]["index"])
            self.assertEqual(1104, large_tail[-1]["index"])

