    def test_search_logger_writes_valid_jsonl_under_concurrency(self) -> None:
        with tempfile.TemporaryDirectory() as temp_dir:
            log_path = Path(temp_dir) / "search.jsonl"
            logger = SearchLogger(log_path)

            def write_entry(index: int) -> None:
                logger.write({"type": "search", "index": index, "q": f"우산 {index}"})

            with ThreadPoolExecutor(max_workers=10) as pool:
                list(pool.map(write_entry, range(100)))

            lines = log_path.read_text(encoding="utf-8").splitlines()
            entries = [json.loads(line) for line in lines]
            self.assertEqual(100, len(entries))
            self.assertEqual(set(range(100)), {entry["index"] for entry in entries})
            status = logger.status()
            self.assertEqual(100, status["write_events"])
            self.assertEqual(0, status["write_errors"])
            self.assertGreater(status["write_total_ms"], 0)
            self.assertGreater(status["write_max_ms"], 0)
            self.assertFalse(status["buffer_open"])

    def test_search_logger_can_keep_buffer_open_for_request_bursts(self) -> None:
        with tempfile.TemporaryDirectory() as temp_dir:
            log_path = Path(temp_dir) / "search.jsonl"
            logger = SearchLogger(log_path, keep_open_seconds=60)

            for index in range(3):
                logger.write({"type": "search", "index": index})

            self.assertEqual([0, 1, 2], [entry["index"] for entry in logger.tail(10)])
            status = logger.status()
            self.assertEqual(60, status["keep_open_seconds"])
            self.assertEqual(3, status["write_events"])
            self.assertEqual(1, status["output_opens"])
            self.assertGreaterEqual(status["output_reuses"], 2)
            self.assertEqual(0, status["output_closes"])
            self.assertEqual(0, status["idle_closes"])
            self.assertTrue(status["buffer_open"])

            logger.close()
            closed_status = logger.status()
            self.assertFalse(closed_status["buffer_open"])
            self.assertEqual(1, closed_status["output_closes"])

    def test_search_logger_isolates_write_failures_and_reports_status(self) -> None:
        with tempfile.TemporaryDirectory() as temp_dir:
            log_path = Path(temp_dir) / "search.jsonl"
            logger = SearchLogger(log_path)

            with patch.object(search_service_module.os, "open", side_effect=OSError("disk full")):
                logger.write({"type": "search", "index": 1})

            status = logger.status()
            self.assertEqual(1, status["write_errors"])
            self.assertEqual("OSError", status["last_write_error_type"])
            self.assertIn("disk full", status["last_write_error"])
            self.assertTrue(status["last_write_error_at"])

            logger.write({"type": "search", "index": 2})
            self.assertEqual([2], [entry["index"] for entry in logger.tail(10)])
            status = logger.status()
            self.assertEqual(1, status["write_errors"])
            self.assertEqual(1, status["write_events"])
            self.assertFalse(status["buffer_open"])

