    def test_public_api_image_rate_limit_precedes_image_cache_validation(self) -> None:
        main_module = (ROOT / "app" / "main.py").read_text(encoding="utf-8")
        image_branch = main_module.split("if parsed.has_image:", 1)[1].split("search_request = SearchRequest.model_validate", 1)[0]

        self.assertLess(
            image_branch.index("enforce_image_rate_limit"),
            image_branch.index("read_multipart_image_data_url"),
        )
        self.assertLess(
            image_branch.index("enter_image_search_slot_context"),
            image_branch.index("read_multipart_image_data_url"),
        )
        public_route = main_module.split("async def ai_search", 1)[1].split("async def click_log", 1)[0]
        preparse_branch = public_route.split("parsed = await parse_search_request", 1)[0]
        self.assertLess(
            preparse_branch.index("validate_public_access_headers"),
            preparse_branch.index("enforce_search_client_rate_limit"),
        )
        self.assertIn("await run_in_threadpool(enforce_search_client_rate_limit, request)", preparse_branch)
        self.assertIn("validate_multipart_content_length", preparse_branch)
        self.assertNotIn("enter_image_search_slot_context", preparse_branch)
        self.assertIn(
            "result = await run_in_threadpool(service.search, search_request, acquire_image_search_slot)",
            public_route,
        )
        multipart_parser = main_module.split("async def parse_search_request", 1)[1].split(
            "async def read_multipart_image_data_url",
            1,
        )[0]
        self.assertIn("validate_multipart_content_length", multipart_parser)
        self.assertNotIn("upload_bytes_to_data_url", multipart_parser)
        self.assertNotIn("validate_image_bytes", multipart_parser)

