    def test_read_json_object_limits_stream_without_content_length(self) -> None:
        from app.request_body import read_json_object_limited

        class FakeStreamingRequest:
            def __init__(self, chunks):
                self.chunks = chunks

            async def stream(self):  # type: ignore[no-untyped-def]
                for chunk in self.chunks:
                    yield chunk

        parsed = asyncio.run(read_json_object_limited(FakeStreamingRequest([b'{"ok":', b"true}"]), max_bytes=32))
        self.assertEqual({"ok": True}, parsed)

        with self.assertRaisesRegex(ValueError, "JSON body exceeds 12 bytes"):
            asyncio.run(read_json_object_limited(FakeStreamingRequest([b'{"payload":"', b"x" * 32]), max_bytes=12))

