    def test_image_validation_normalizes_exif_orientation(self) -> None:
        image = validate_image_bytes(make_oriented_jpeg_bytes(), max_bytes=1024 * 1024)

        self.assertTrue(image.normalized)
        self.assertEqual((40, 20), (image.width, image.height))
        payload = image.data_url.split(",", 1)[1]
        normalized_raw = base64.b64decode(payload)
        from PIL import Image

        with Image.open(io.BytesIO(normalized_raw)) as normalized:
            self.assertEqual((40, 20), normalized.size)
            self.assertNotEqual(6, normalized.getexif().get(274))

