    def test_image_validation_accepts_common_jpg_mime_aliases(self) -> None:
        jpeg = make_jpeg_bytes()
        image = validate_image_bytes(
            jpeg,
            max_bytes=1024 * 1024,
            declared_mime_type="image/jpg; charset=binary",
        )
        data_url = "data:image/pjpeg;base64," + base64.b64encode(jpeg).decode("ascii")
        from_data_url = validate_image_base64(data_url, max_bytes=1024 * 1024)
        uppercase_data_url = "DATA:IMAGE/PJPEG;BASE64," + base64.b64encode(jpeg).decode("ascii")
        from_uppercase_data_url = validate_image_base64(uppercase_data_url, max_bytes=1024 * 1024)

        self.assertEqual("image/jpeg", image.mime_type)
        self.assertTrue(image.data_url.startswith("data:image/jpeg;base64,"))
        self.assertEqual("image/jpeg", from_data_url.mime_type)
        self.assertEqual("image/jpeg", from_uppercase_data_url.mime_type)

