    def test_image_url_check_report_groups_failures_warnings_and_retries(self) -> None:
        with tempfile.TemporaryDirectory() as temp_dir:
            csv_path = Path(temp_dir) / "products.csv"
            csv_path.write_text(
                "\n".join(
                    [
                        "product_id,product_name,category_name,status,display_yn,price,main_image_url",
                        "P001,워터마크 우산,우산,active,Y,1000,https://images.example.test/p001_watermark.jpg",
                        "P002,404 우산,우산,active,Y,1000,https://images.example.test/missing.jpg",
                        "P003,MIME 우산,우산,active,Y,1000,https://images.example.test/html-as-image.jpg",
                        "P004,비공개 우산,우산,active,Y,1000,https://token@images.example.test/private.jpg",
                    ]
                )
                + "\n",
                encoding="utf-8",
            )
            args = type(
                "Args",
                (),
                {
                    "csv": str(csv_path),
                    "limit": 0,
                    "concurrency": 3,
                    "timeout_seconds": 10,
                    "retry_count": 2,
                    "retry_delay_seconds": 0.25,
                    "max_mb": 5,
                    "min_dimension": 16,
                    "max_failures": 50,
                    "max_warnings": 50,
                },
            )()

            def fake_validate(product: ProductDocument) -> ImageProbeResult:
                if product.product_id == "P001":
                    return ImageProbeResult(
                        True,
                        product.product_id,
                        product.image_url,
                        attempts=2,
                        warnings=("possible_watermark", "placeholder_or_sample_image"),
                    )
                if product.product_id == "P002":
                    return ImageProbeResult(False, product.product_id, product.image_url, "image download failed: HTTP 404")
                if product.product_id == "P003":
                    return ImageProbeResult(
                        False,
                        product.product_id,
                        product.image_url,
                        "declared image type text/html does not match image/png",
                        attempts=2,
                    )
                return ImageProbeResult(
                    False,
                    product.product_id,
                    product.image_url,
                    "image URL must be an absolute safe http(s) URL",
                )

            with patch("scripts.image_url_check.ProductImageProbe.validate", side_effect=fake_validate), patch(
                "scripts.image_url_check.load_settings",
                return_value=Settings(),
            ):
                report = run_image_url_check(args)

        self.assertFalse(report["ok"])
        self.assertEqual(4, report["checked"])
        self.assertEqual(
            {"http_4xx": 1, "mime_mismatch": 1, "unsafe_image_url": 1},
            report["failure_category_counts"],
        )
        self.assertEqual({"placeholder_or_sample_image": 1, "possible_watermark": 1}, report["warning_type_counts"])
        self.assertEqual(1, report["blocking_warning_count"])
        self.assertEqual({"placeholder_or_sample_image": 1}, report["blocking_warning_type_counts"])
        self.assertEqual({"max": 2, "retried_successes": 1, "retried_failures": 1}, report["attempts"])
        failure_categories = {failure["product_id"]: failure["category"] for failure in report["failures"]}
        self.assertEqual("http_4xx", failure_categories["P002"])
        self.assertEqual("mime_mismatch", failure_categories["P003"])
        self.assertEqual("unsafe_image_url", failure_categories["P004"])
        self.assertEqual(2, next(warning for warning in report["warnings"] if warning["product_id"] == "P001")["attempts"])
        self.assertEqual(
            ["placeholder_or_sample_image"],
            next(warning for warning in report["blocking_warnings"] if warning["product_id"] == "P001")["warnings"],
        )

    def test_rate_limit_helper_tracks_independent_ip_and_mall_buckets(self) -> None:
        buckets: dict[str, list[float]] = {}

        self.assertEqual((True, 1), record_rate_limit_hit(buckets, "ip:1.2.3.4", 2, now=100.0))
        self.assertEqual((True, 2), record_rate_limit_hit(buckets, "ip:1.2.3.4", 2, now=101.0))
        self.assertEqual((False, 2), record_rate_limit_hit(buckets, "ip:1.2.3.4", 2, now=102.0))
        self.assertEqual((True, 1), record_rate_limit_hit(buckets, "mall:shop001", 1, now=102.0))
        self.assertEqual((False, 1), record_rate_limit_hit(buckets, "mall:shop001", 1, now=103.0))
        self.assertEqual((True, 1), record_rate_limit_hit(buckets, "ip:1.2.3.4", 2, now=200.0))

    def test_rate_limit_helper_treats_zero_as_disabled(self) -> None:
        buckets: dict[str, list[float]] = {}

        self.assertEqual((True, 0), record_rate_limit_hit(buckets, "ip:1.2.3.4", 0, now=100.0))
        self.assertEqual((True, 0), record_rate_limit_hit(buckets, "ip:1.2.3.4", 0, now=101.0))
        self.assertEqual({}, buckets)

    def test_rate_limit_helper_prunes_current_bucket_in_place(self) -> None:
        stamps = [90.0, 120.0]
        buckets: dict[str, list[float]] = {"ip:1.2.3.4": stamps}

        self.assertEqual((True, 2), record_rate_limit_hit(buckets, "ip:1.2.3.4", 3, now=151.0))

        self.assertIs(stamps, buckets["ip:1.2.3.4"])
        self.assertEqual([120.0, 151.0], buckets["ip:1.2.3.4"])

    def test_rate_limit_bucket_store_periodically_prunes_stale_buckets(self) -> None:
        store = RateLimitBucketStore(max_buckets=10, prune_interval_seconds=1.0)
        store.buckets.update(
            {
                "ip:expired": [90.0],
                "ip:active": [120.0],
            }
        )

        self.assertEqual((True, 1), store.hit("ip:new", 5, now=180.0, window_seconds=60))
        status = store.status()

        self.assertNotIn("ip:expired", store.buckets)
        self.assertIn("ip:active", store.buckets)
        self.assertIn("ip:new", store.buckets)
        self.assertEqual(2, status["bucket_count"])
        self.assertEqual(1, status["pruned_buckets"])
        self.assertEqual(1.0, status["prune_interval_seconds"])

    def test_rate_limit_helper_prunes_expired_and_caps_high_cardinality_buckets(self) -> None:
        buckets: dict[str, list[float]] = {
            "expired:1": [1.0],
            "recent:1": [95.0],
            "recent:2": [96.0],
        }

        removed = prune_rate_limit_buckets(buckets, now=200.0, window_seconds=60, max_buckets=10)
        self.assertEqual(3, removed)
        self.assertEqual({}, buckets)

        capped: dict[str, list[float]] = {}
        for index in range(5):
            allowed, _ = record_rate_limit_hit(
                capped,
                f"ip:203.0.113.{index}",
                5,
                now=300.0 + index,
                max_buckets=3,
            )
            self.assertTrue(allowed)

        self.assertEqual(3, len(capped))
        self.assertIn("ip:203.0.113.4", capped)
        self.assertNotIn("ip:203.0.113.0", capped)

    def test_redis_rate_limiter_fallback_caps_high_cardinality_buckets(self) -> None:
        class FailingRedisClient:
            def incr(self, key: str) -> int:  # noqa: ARG002
                raise OSError("redis unavailable")

            def expire(self, key: str, seconds: int) -> None:  # noqa: ARG002
                return None

        limiter = object.__new__(RedisRateLimiter)
        limiter.client = FailingRedisClient()
        limiter.key_prefix = "hai"
        limiter.fallback_max_buckets = 3

        for index in range(6):
            allowed, _ = limiter.hit(f"search:ip:203.0.113.{index}", 5, now=400.0 + index)
            self.assertTrue(allowed)

        status = limiter.status()
        self.assertEqual(6, status["fallback_events"])
        self.assertEqual(3, status["fallback_bucket_count"])
        self.assertEqual(3, status["fallback_max_buckets"])

    def test_redis_rate_limiter_backoff_skips_repeated_unavailable_redis_calls(self) -> None:
        class FailingRedisClient:
            def __init__(self):
                self.calls = 0

            def eval(self, script: str, key_count: int, key: str, ttl: int) -> int:  # noqa: ARG002
                self.calls += 1
                raise OSError("redis unavailable")

        client = FailingRedisClient()
        limiter = object.__new__(RedisRateLimiter)
        limiter.client = client
        limiter.key_prefix = "hai"
        limiter.fallback_max_buckets = 100
        limiter.fallback_prune_interval_seconds = 1.0
        limiter.redis_failure_backoff_seconds = 30.0

        self.assertEqual((True, 1), limiter.hit("search:ip:203.0.113.1", 5, now=100.0))
        self.assertEqual((True, 1), limiter.hit("search:ip:203.0.113.2", 5, now=100.1))

        status = limiter.status()
        self.assertEqual(1, client.calls)
        self.assertEqual(2, status["fallback_events"])
        self.assertEqual(1, status["fallback_skipped_redis_events"])
        self.assertTrue(status["redis_backoff_active"])
        self.assertEqual(1, status["redis_backoff_failure_events"])
        self.assertEqual(1, status["redis_backoff_skipped_operations"])

    def test_request_client_ip_uses_forwarded_headers_only_from_trusted_proxy(self) -> None:
        settings = Settings(trusted_proxy_ips=("127.0.0.1", "10.0.0.0/24"))

        self.assertEqual(
            "203.0.113.42",
            resolve_client_ip(
                "127.0.0.1",
                {"X-Forwarded-For": "203.0.113.42, 127.0.0.1"},
                settings,
            ),
        )
        self.assertEqual(
            "198.51.100.5",
            resolve_client_ip("10.0.0.15", {"X-Real-IP": "198.51.100.5"}, settings),
        )
        self.assertEqual(
            "198.51.100.10",
            resolve_client_ip(
                "198.51.100.10",
                {"X-Forwarded-For": "203.0.113.42"},
                settings,
            ),
        )
        self.assertEqual(
            "127.0.0.1",
            resolve_client_ip("127.0.0.1", {"X-Forwarded-For": "not-an-ip"}, settings),
        )

    def test_request_client_ip_accepts_standard_forwarded_header_from_trusted_proxy(self) -> None:
        settings = Settings(trusted_proxy_ips=("127.0.0.1", "10.0.0.0/24"))

        self.assertEqual(
            "203.0.113.43",
            resolve_client_ip("127.0.0.1", {"Forwarded": 'for="203.0.113.43:49152";proto=https'}, settings),
        )
        self.assertEqual(
            "2001:db8::1",
            resolve_client_ip("10.0.0.15", {"Forwarded": 'for="[2001:db8::1]";proto=https'}, settings),
        )
        self.assertEqual(
            "127.0.0.1",
            resolve_client_ip("127.0.0.1", {"Forwarded": "for=_hidden;proto=https"}, settings),
        )
        self.assertEqual(
            "198.51.100.10",
            resolve_client_ip("198.51.100.10", {"Forwarded": "for=203.0.113.43"}, settings),
        )

