    def test_cors_origins_reject_non_origin_values(self) -> None:
        for value in [
            "https://shop001.example.test/search",
            "https://shop001.example.test?x=1",
            "https://user:pass@shop001.example.test",
            "ftp://shop001.example.test",
        ]:
            with self.subTest(value=value):
                with self.assertRaisesRegex(ValueError, "HAEORUM_CORS_ORIGINS values must be origins"):
                    parse_cors_origins(value)

        with self.assertRaisesRegex(ValueError, "HAEORUM_CORS_ORIGINS wildcard must not be combined"):
            parse_cors_origins("*,https://shop001.example.test")

    def test_marqo_url_validation_accepts_internal_endpoint_shape(self) -> None:
        self.assertEqual("http://localhost:8882", validate_marqo_url_value("http://localhost:8882/"))
        self.assertEqual("http://marqo-api:8882", validate_marqo_url_value("http://marqo-api:8882"))

        for value, expected in [
            ("marqo-api:8882", r"MARQO_URL must be an absolute HTTP\(S\) URL"),
            ("http://user:pass@marqo-api:8882", r"MARQO_URL must be an absolute HTTP\(S\) URL"),
            ("http://marqo-api:8882?token=secret", r"MARQO_URL must be an absolute HTTP\(S\) URL"),
            ("http://marqo-api:8882#secret", r"MARQO_URL must be an absolute HTTP\(S\) URL"),
            ("http://marqo-api:bad", "MARQO_URL has an invalid port"),
            ("http://marqo-api:8882\\bad", r"MARQO_URL must be an absolute HTTP\(S\) URL"),
            ("http://169.254.169.254:8882", "MARQO_URL must not use link-local or unspecified hosts"),
            ("http://0.0.0.0:8882", "MARQO_URL must not use link-local or unspecified hosts"),
        ]:
            with self.subTest(value=value):
                with self.assertRaisesRegex(ValueError, expected):
                    validate_marqo_url_value(value)

