            ("redis://redis:bad/0", "HAEORUM_REDIS_URL has an invalid port"),
            ("redis://redis:6379/cache", r"HAEORUM_REDIS_URL path must be /<database-number>"),
            ("redis://redis:6379/0#secret", "HAEORUM_REDIS_URL must not include URL params or fragments"),
            ("redis://redis:6379/0\\bad", "HAEORUM_REDIS_URL must be a Redis URL"),
