    def test_mssql_connection_string_validation_requires_readonly_tls_shape(self) -> None:
        parsed = validate_mssql_connection_string_value(
            "Driver={ODBC Driver 18 for SQL Server};"
            "Server=tcp:db.example.internal,1433;"
            "Database=HaeorumGift;"
            "UID=readonly;"
            "PWD=secret;"
            "Encrypt=yes;"
            "TrustServerCertificate=no;"
            "ApplicationIntent=ReadOnly"
        )

        self.assertEqual("yes", parsed["encrypt"])
        self.assertEqual("no", parsed["trustservercertificate"])
        self.assertEqual("ReadOnly", parsed["applicationintent"])

        for value, expected in [
            ("...", "HAEORUM_MSSQL_READONLY_CONNECTION_STRING must not be a placeholder"),
            (
                "Driver={ODBC Driver 18 for SQL Server};Database=db;UID=readonly;PWD=secret;"
                "Encrypt=yes;TrustServerCertificate=no;ApplicationIntent=ReadOnly",
                "must include: server",
            ),
            (
                "Driver={ODBC Driver 18 for SQL Server};Server=db;Database=db;UID=readonly;PWD=secret;"
                "TrustServerCertificate=no;ApplicationIntent=ReadOnly",
                "must include: encrypt",
            ),
            (
                "Driver={ODBC Driver 18 for SQL Server};Server=db;Database=db;UID=readonly;PWD=secret;"
                "Encrypt=no;TrustServerCertificate=no;ApplicationIntent=ReadOnly",
                "must set Encrypt=yes",
            ),
            (
                "Driver={ODBC Driver 18 for SQL Server};Server=db;Database=db;UID=readonly;PWD=secret;"
                "Encrypt=yes;TrustServerCertificate=yes;ApplicationIntent=ReadOnly",
                "must set TrustServerCertificate=no",
            ),
            (
                "Driver={ODBC Driver 18 for SQL Server};Server=db;Database=db;UID=readonly;PWD=secret;"
                "Encrypt=yes;TrustServerCertificate=no;ApplicationIntent=ReadWrite",
                "must set ApplicationIntent=ReadOnly",
            ),
        ]:
            with self.subTest(value=value):
                with self.assertRaisesRegex(ValueError, expected):
                    validate_mssql_connection_string_value(value)

