    def test_env_check_validates_deployment_env_file(self) -> None:
        with tempfile.TemporaryDirectory() as temp_dir:
            root = Path(temp_dir)
            mall_config = root / "malls.json"
            mall_config.write_text(
                json.dumps(
                    {
                        "malls": [
                            {
                                "mall_id": "shop001",
                                "api_key": "pk_live_shop001_abcdefghijklmnopqrstuvwxyz",
                                "product_url_template": "https://shop001.example.test/product/{product_id}",
                                "allowed_origins": ["https://shop001.example.test"],
                            }
                        ]
                    }
                ),
                encoding="utf-8",
            )
            query_synonyms = root / "query-synonyms.json"
            query_synonyms.write_text(json.dumps({"synonyms": {"bag": ["pouch"]}}), encoding="utf-8")
            env_path = root / "haeorum.env"
            base_env = {
                "HAEORUM_ENV": "production",
                "HAEORUM_SEARCH_ENGINE": "marqo",
                "MARQO_URL": "http://marqo.internal:8882",
                "HAEORUM_MARQO_MODEL": "Marqo/marqo-ecommerce-embeddings-L",
                "HAEORUM_EMBEDDING_BACKEND": "qwen",
                "HAEORUM_QWEN_EMBEDDING_URL": "http://qwen-embedding:8098",
                "HAEORUM_QWEN_EMBEDDING_PROXY_API_KEY": "internal-qwen-proxy-key-123456",
                "HAEORUM_QWEN_EMBEDDING_DIMENSIONS": "2048",
                "HAEORUM_QWEN_MODEL": "Qwen/Qwen3-VL-Embedding-2B",
                "HAEORUM_QWEN_MIXED_QUERY_PARALLELISM": "8",
                "HAEORUM_QWEN_QUERY_RUNTIME_TEXT_CACHE_ENTRIES": "2048",
                "HAEORUM_QWEN_QUERY_RUNTIME_IMAGE_CACHE_ENTRIES": "512",
                "HAEORUM_INDEX_NAME": "haeorum-products",
                "HAEORUM_ADMIN_API_KEY": "prod-admin-key-123456",
                "HAEORUM_MALL_CONFIG_PATH": str(mall_config),
                "HAEORUM_QUERY_SYNONYM_PATH": str(query_synonyms),
                "HAEORUM_CORS_ORIGINS": "https://shop001.example.test",
                "HAEORUM_MSSQL_READONLY_CONNECTION_STRING": (
                    "Driver={ODBC Driver 18 for SQL Server};Server=db;Database=db;UID=readonly;PWD=secret;"
                    "Encrypt=yes;TrustServerCertificate=no;ApplicationIntent=ReadOnly"
                ),
                "HAEORUM_REDIS_URL": "redis://redis:6379/0",
                "HAEORUM_SEARCH_RATE_LIMIT_PER_MINUTE": "900",
                "HAEORUM_MALL_SEARCH_RATE_LIMIT_PER_MINUTE": "2000",
                "HAEORUM_IMAGE_RATE_LIMIT_PER_MINUTE": "300",
                "HAEORUM_MALL_IMAGE_RATE_LIMIT_PER_MINUTE": "600",
                "HAEORUM_MAX_IMAGE_MB": "5",
                "HAEORUM_MAX_IMAGE_DIMENSION": "1600",
                "HAEORUM_MIN_IMAGE_DIMENSION": "16",
                "HAEORUM_CATEGORY_SUGGESTION_LIMIT": "15",
                "HAEORUM_SEARCH_MAX_CONCURRENCY": "64",
                "HAEORUM_SEARCH_QUEUE_TIMEOUT_SECONDS": "2",
                "HAEORUM_IMAGE_SEARCH_MAX_CONCURRENCY": "8",
                "HAEORUM_IMAGE_SEARCH_QUEUE_TIMEOUT_SECONDS": "2",
                "HAEORUM_API_THREADPOOL_TOKENS": "96",
                "HAEORUM_BACKEND_RETRY_AFTER_MAX_SECONDS": "2",
                "HAEORUM_BACKEND_CIRCUIT_FAILURE_THRESHOLD": "5",
                "HAEORUM_BACKEND_CIRCUIT_COOLDOWN_SECONDS": "5",
                "HAEORUM_BACKEND_CIRCUIT_HALF_OPEN_MAX_CALLS": "1",
                "MARQO_API_WORKERS": "2",
                "MARQO_API_KEEPALIVE_TIMEOUT": "75",
                "MARQO_API_GZIP_MINIMUM_SIZE": "1024",
                "MARQO_MAX_CONCURRENT_SEARCH": "100",
                "VESPA_POOL_SIZE": "128",
                "VESPA_SEARCH_TIMEOUT_MS": "5000",
                "MARQO_INFERENCE_POOL_SIZE": "128",
                "HAEORUM_TRUSTED_PROXY_IPS": "127.0.0.1,10.20.0.0/16",
                "HAEORUM_SYNC_INTERVAL_SECONDS": "3600",
            }

            def write_env(values: dict[str, str]) -> None:
                env_path.write_text(
                    "\n".join(f"{name}={value}" for name, value in values.items()) + "\n",
                    encoding="utf-8",
                )
                if os.name == "posix":
                    env_path.chmod(0o640)

            args = type(
                "Args",
                (),
                {
                    "env_file": str(env_path),
                    "role": "api",
                    "api_server_count": 2,
                    "allow_non_production": False,
                    "skip_path_checks": False,
                },
            )()

            write_env(base_env)
            report = build_env_check_report(args)

            self.assertTrue(report["ok"])
            self.assertEqual([], report["failed_checks"])
            env_file_permissions = next(item for item in report["checks"] if item["name"] == "env_file_permissions")
            self.assertTrue(env_file_permissions["ok"])
            self.assertEqual("0640", env_file_permissions["maximum_mode"])
            boolean_settings = next(item for item in report["checks"] if item["name"] == "boolean_settings")
            self.assertTrue(boolean_settings["ok"])
            self.assertEqual([], boolean_settings["problems"])
            self.assertTrue(next(item for item in report["checks"] if item["name"] == "settings_load")["ok"])
            marqo_url = next(item for item in report["checks"] if item["name"] == "marqo_url")
            self.assertTrue(marqo_url["ok"])
