    def test_security_check_validates_sync_alert_webhook_url(self) -> None:
        valid = check_sync_alert_webhook_url("https://alerts.example.test/sync?tenant=shop001")
        self.assertTrue(valid["ok"])
        self.assertTrue(valid["configured"])
        self.assertEqual("alerts.example.test", valid["host"])
        self.assertTrue(valid["has_query"])

        missing = check_sync_alert_webhook_url("")
        self.assertTrue(missing["ok"])
        self.assertFalse(missing["configured"])

        for invalid in [
            "http://alerts.example.test/sync",
            "https://user:pass@alerts.example.test/sync",
            "https://alerts.example.test/sync#secret",
            "https://alerts.example.test/sync with-space",
            "https://alerts.example.test\\sync",
            "https://localhost./sync",
            "https://169.254.169.254/sync",
            "https://[fe80::1]/sync",
        ]:
            with self.subTest(invalid=invalid):
                report = check_sync_alert_webhook_url(invalid)
                self.assertFalse(report["ok"])
                self.assertTrue(report["configured"])

    def test_secret_env_file_permission_check_reports_posix_modes(self) -> None:
        with tempfile.TemporaryDirectory() as temp_dir:
            env_file = Path(temp_dir) / "secret.env"
            env_file.write_text("HAEORUM_ADMIN_API_KEY=prod-admin-key-123456\n", encoding="utf-8")
            if os.name == "posix":
                env_file.chmod(0o640)

            report = check_secret_file_permissions(
                env_file,
                name="env_file_permissions",
                required=True,
                max_mode=0o640,
            )

            self.assertTrue(report["ok"])
            self.assertEqual("0640", report["maximum_mode"])
            if os.name == "posix":
                env_file.chmod(0o644)
                broad = check_secret_file_permissions(
                    env_file,
                    name="env_file_permissions",
                    required=True,
                    max_mode=0o640,
                )
                self.assertFalse(broad["ok"])
                self.assertEqual("0644", broad["mode"])
                self.assertEqual("0004", broad["disallowed_mode"])

    def test_security_check_env_file_context_is_isolated(self) -> None:
        with patch.dict(
            "os.environ",
            {
                "HAEORUM_ENV": "production",
                "HAEORUM_ADMIN_API_KEY": "prod-admin-key-123456",
                "KEEP_PROCESS_ENV": "yes",
            },
            clear=True,
        ):
            with patched_security_environ({"HAEORUM_ENV": "staging"}, clear=True):
                self.assertEqual({"HAEORUM_ENV": "staging"}, dict(os.environ))
            self.assertEqual("prod-admin-key-123456", os.environ["HAEORUM_ADMIN_API_KEY"])

            with patched_security_environ({"HAEORUM_ENV": "staging"}, clear=False):
                self.assertEqual("yes", os.environ["KEEP_PROCESS_ENV"])
                self.assertEqual("staging", os.environ["HAEORUM_ENV"])
                self.assertEqual("prod-admin-key-123456", os.environ["HAEORUM_ADMIN_API_KEY"])

    def test_server_preflight_check_builds_deployment_evidence(self) -> None:
        args = type(
            "Args",
            (),
            {
                "role": "api",
                "disk_path": "/var/log/haeorum-ai-search",
                "min_cpu": 0,
                "min_memory_gb": 0,
                "min_disk_free_gb": 0,
                "min_open_files": 0,
                "require_docker": True,
                "require_compose": True,
                "require_pyodbc": True,
                "expected_odbc_driver": "ODBC Driver 18 for SQL Server",
                "allow_non_linux": False,
                "allow_unsupported_os": False,
                "timeout": 5,
            },
        )()
        system_info = {
            "platform": "Linux",
            "platform_release": "5.15.0",
            "machine": "x86_64",
            "python_version": "3.13.1",
            "python_executable": "/usr/bin/python3",
            "cpu_count": 8,
            "memory_total_bytes": 16 * 1024**3,
            "disk_free_bytes": 80 * 1024**3,
            "disk_total_bytes": 200 * 1024**3,
            "open_file_limit_soft": 65535,
            "open_file_limit_hard": 65535,
            "os_release": {"ID": "ubuntu", "VERSION_ID": "22.04"},
        }

        def fake_runner(command: list[str], timeout: int) -> dict[str, object]:
            if command == ["docker", "--version"]:
                return {"ok": True, "output": "Docker version 25.0.3, build abc"}
            if command == ["docker", "compose", "version"]:
                return {"ok": True, "output": "Docker Compose version v2.24.0"}
            return {"ok": False, "error": "unexpected command"}

        report = build_server_preflight_report(
            args,
            command_runner=fake_runner,
            module_checker=lambda module: True,
            odbc_driver_provider=lambda: ["ODBC Driver 18 for SQL Server"],
            system_info=system_info,
        )

        self.assertTrue(report["ok"])
        self.assertEqual("api", report["role"])
        supported_linux = next(check for check in report["checks"] if check["name"] == "supported_linux_release")
        self.assertTrue(supported_linux["ok"])
        self.assertEqual("ubuntu", supported_linux["id"])
        self.assertEqual("Ubuntu 20.04+", supported_linux["baseline"])
        self.assertEqual("20.04", supported_linux["minimum_version"])
        self.assertEqual((25, 0, 3), parse_version("Docker version 25.0.3, build abc"))
        self.assertTrue(version_at_least((25, 0, 3), (24, 0, 0)))

        weak_report = build_server_preflight_report(
            args,
            command_runner=fake_runner,
            module_checker=lambda module: module != "pyodbc",
            odbc_driver_provider=lambda: [],
            system_info={**system_info, "cpu_count": 2},
        )

        self.assertFalse(weak_report["ok"])
        self.assertIn("python_modules", weak_report["failed_checks"])
        self.assertIn("host_resources", weak_report["failed_checks"])
        weak_nofile_report = build_server_preflight_report(
            args,
            command_runner=fake_runner,
            module_checker=lambda module: True,
            odbc_driver_provider=lambda: ["ODBC Driver 18 for SQL Server"],
            system_info={**system_info, "open_file_limit_soft": 1024, "open_file_limit_hard": 4096},
        )
        self.assertFalse(weak_nofile_report["ok"])
        self.assertIn("host_resources", weak_nofile_report["failed_checks"])
        weak_nofile_resources = next(check for check in weak_nofile_report["checks"] if check["name"] == "host_resources")
        self.assertIn("open_file_limit_soft", weak_nofile_resources["problems"])

        old_linux_report = build_server_preflight_report(
            args,
            command_runner=fake_runner,
            module_checker=lambda module: True,
            odbc_driver_provider=lambda: ["ODBC Driver 18 for SQL Server"],
            system_info={
                **system_info,
                "os_release": {"ID": "centos", "VERSION_ID": "7"},
            },
        )

        self.assertFalse(old_linux_report["ok"])
        self.assertIn("supported_linux_release", old_linux_report["failed_checks"])

