            self.assertIn("Evidence output dir: `/var/log/haeorum-ai-search`", deploy_audit_markdown)
            self.assertIn("python scripts/api_smoke_test.py", deploy_audit_markdown)
            self.assertIn("/var/log/haeorum-ai-search/api-smoke.json", deploy_audit_markdown)
            self.assertIn("/var/log/haeorum-ai-search/quality-report.md", deploy_audit_markdown)
