            def fake_runner(command: list[str], timeout: int) -> dict[str, object]:
                payload = collector_payload_for_command(command)
                for output_option in ("--report-output", "--output", "--json-output"):
                    if output_option in command:
                        output_path = Path(str(command[command.index(output_option) + 1]))
                        output_path.parent.mkdir(parents=True, exist_ok=True)
                        output_path.write_text(
                            json.dumps(payload) + "\n",
                            encoding="utf-8",
                        )
                        break
                return {
                    "ok": True,
                    "exit_code": 0,
                    "elapsed_ms": 1.0,
                    "stdout": json.dumps(payload) + "\n",
                }

            executed = build_operational_evidence_collection_report(
                config_path,
                evidence_dir,
                timeout=5,
                dry_run=False,
                stop_on_failure=False,
                command_runner=fake_runner,
            )
            self.assertTrue(executed["ok"])
            self.assertTrue(executed["evidence_complete"])
            self.assertEqual(18, executed["status_counts"]["passed"])
            self.assertEqual([], executed["failed_steps"])
            self.assertFalse((evidence_dir / "widget-dom.json").exists())
            self.assertNotIn("widget_representative_configs", {step["name"] for step in executed["steps"]})

            def local_only_output_runner(command: list[str], timeout: int) -> dict[str, object]:
                for output_option in ("--report-output", "--output", "--json-output"):
                    if output_option in command:
                        output_path = Path(str(command[command.index(output_option) + 1]))
                        output_path.parent.mkdir(parents=True, exist_ok=True)
                        output_path.write_text(
                            json.dumps(
                                {
                                    "ok": True,
                                    "generated_at": datetime.now(timezone.utc).isoformat(),
                                    "local_only": True,
                                    "not_operational_readiness": True,
                                }
                            )
                            + "\n",
                            encoding="utf-8",
                        )
                        break
                return {"ok": True, "exit_code": 0, "elapsed_ms": 1.0, "stdout": "{\"ok\": true}\n"}

            invalid_output_collection = build_operational_evidence_collection_report(
                config_path,
                Path(temp_dir) / "invalid-output-evidence",
                timeout=5,
                dry_run=False,
                stop_on_failure=True,
                command_runner=local_only_output_runner,
            )
            self.assertFalse(invalid_output_collection["ok"])
            self.assertEqual(["mall_config_build"], invalid_output_collection["failed_steps"])
            self.assertEqual(
                "produced evidence is invalid, wrong-shape, content-invalid, dry-run, stale, simulated, local-only, or ok is not true",
                invalid_output_collection["steps"][0]["message"],
            )
            self.assertTrue(invalid_output_collection["steps"][0]["evidence_summary"]["local_only"])

            def missing_output_runner(command: list[str], timeout: int) -> dict[str, object]:
                return {"ok": True, "exit_code": 0, "elapsed_ms": 1.0, "stdout": "{\"ok\": true}\n"}

            missing_output_collection = build_operational_evidence_collection_report(
                config_path,
                Path(temp_dir) / "missing-output-evidence",
                timeout=5,
                dry_run=False,
                stop_on_failure=True,
                command_runner=missing_output_runner,
            )
            self.assertFalse(missing_output_collection["ok"])
            self.assertEqual(["mall_config_build"], missing_output_collection["failed_steps"])
            self.assertEqual("evidence file was not created", missing_output_collection["steps"][0]["message"])

            failed_calls = []

            def failing_runner(command: list[str], timeout: int) -> dict[str, object]:
                failed_calls.append(command)
                return {
                    "ok": False,
                    "exit_code": 2,
                    "elapsed_ms": 1.0,
                    "stdout_tail": "partial output",
                    "stderr_tail": "connection failed",
                }

            failed_collection = build_operational_evidence_collection_report(
                config_path,
                evidence_dir,
                timeout=5,
                dry_run=False,
                stop_on_failure=True,
                command_runner=failing_runner,
            )
            self.assertFalse(failed_collection["ok"])
            self.assertEqual(["mall_config_build"], failed_collection["failed_steps"])
            self.assertEqual(1, len(failed_collection["steps"]))
            self.assertEqual(1, len(failed_calls))
            self.assertEqual(str(evidence_dir / "mall-config-build.json"), failed_collection["steps"][0]["evidence_file"])

            def sensitive_subprocess_run(command: list[str], **kwargs: object) -> object:
                class Completed:
                    returncode = 2
                    stdout = (
                        "public=cmd-public-secret env=env-public-secret "
                        "PWD=cmd-password Authorization: Bearer bearer-secret"
                    )
                    stderr = (
                        "admin=cmd-admin-secret mssql=Driver=ODBC;PWD=env-password "
                        "url=https://user:pass@ai-search.example.test/path"
                    )

                return Completed()

            sensitive_command = [
                "python",
                "scripts/api_smoke_test.py",
                "--api-key",
                "cmd-public-secret",
                "--admin-key",
                "cmd-admin-secret",
                "--connection-string",
                "Driver=ODBC;PWD=cmd-password",
            ]
            sensitive_environment = {
                "HAEORUM_PUBLIC_API_KEY": "env-public-secret",
                "HAEORUM_MSSQL_READONLY_CONNECTION_STRING": "Driver=ODBC;PWD=env-password",
                "PATH": "safe-path",
            }
            with patch("scripts.collect_operational_evidence.subprocess.run", side_effect=sensitive_subprocess_run):
                sensitive_result = run_operational_evidence_command(
                    sensitive_command,
                    5,
                    environment=sensitive_environment,
                )
            sensitive_text = json.dumps(sensitive_result, ensure_ascii=False)
            for leaked in [
                "cmd-public-secret",
                "cmd-admin-secret",
                "env-public-secret",
                "cmd-password",
                "env-password",
                "bearer-secret",
                "user:pass",
            ]:
                self.assertNotIn(leaked, sensitive_text)
            self.assertIn("[redacted]@ai-search.example.test", sensitive_text)
            self.assertIn("***", sensitive_text)

            missing_path = Path(temp_dir) / "missing-config.json"
            missing_path.write_text(json.dumps({"base_url": "https://ai-search.example.test"}), encoding="utf-8")
            missing_evidence_dir = Path(temp_dir) / "missing-evidence"
            missing = build_operational_evidence_collection_report(
                missing_path,
                missing_evidence_dir,
                timeout=5,
                dry_run=True,
                stop_on_failure=False,
            )
            self.assertFalse(missing["ok"])
            self.assertGreater(missing["status_counts"]["skipped"], 0)

