            self.assertIn(
                {"file": "missing-evidence.sh", "token": "/var/log/haeorum-ai-search"},
                script_details["missing_required_tokens"],
            )

            with (bundle_dir / "requirements-blockers.md").open("a", encoding="utf-8") as handle:
                handle.write("\n- leaked local path: D:\\old\\workspace\\logs\n")
            with (bundle_dir / "missing-evidence.sh").open("a", encoding="utf-8") as handle:
                handle.write("\n# leaked local path: examples\\HaeorumAISearch\\logs\n")
            polluted_bundle_check = build_operational_bundle_check_report(type("Args", (), {"bundle_dir": str(bundle_dir)})())
            polluted_checks_by_name = {check["name"]: check for check in polluted_bundle_check["checks"]}
            self.assertTrue(polluted_checks_by_name["blocker_checklist_paths"]["details"]["local_path_findings"])
            self.assertTrue(polluted_checks_by_name["missing_evidence_script_paths"]["details"]["local_path_findings"])

