    def test_security_check_validates_nginx_body_size(self) -> None:
        with tempfile.TemporaryDirectory() as temp_dir:
            valid = Path(temp_dir) / "valid.conf"
            valid.write_text("server { client_max_body_size 6m; }\n", encoding="utf-8")
            too_small = Path(temp_dir) / "small.conf"
            too_small.write_text("server { client_max_body_size 4m; }\n", encoding="utf-8")
            missing_directive = Path(temp_dir) / "missing.conf"
            missing_directive.write_text("server { listen 443 ssl; }\n", encoding="utf-8")

            self.assertEqual(6 * 1024 * 1024, parse_nginx_size_to_bytes("6m"))
            self.assertEqual(512 * 1024, parse_nginx_size_to_bytes("512k"))
            self.assertTrue(check_nginx_client_max_body_size(valid, max_image_mb=5)["ok"])
            small = check_nginx_client_max_body_size(too_small, max_image_mb=5)
            self.assertFalse(small["ok"])
            self.assertEqual("4m", small["configured"])
            missing = check_nginx_client_max_body_size(missing_directive, max_image_mb=5)
            self.assertFalse(missing["ok"])
            self.assertEqual("client_max_body_size is missing", missing["message"])

