    def test_image_search_gate_limits_concurrent_image_work(self) -> None:
        gate = ImageSearchGate(max_concurrency=1, queue_timeout_seconds=0.01)

        with gate.slot():
            self.assertEqual(1, gate.status()["in_flight"])
            with self.assertRaises(ImageSearchQueueFull):
                with gate.slot():
                    pass

        self.assertEqual(1, gate.status()["queue_full_events"])
        self.assertEqual(0, gate.status()["in_flight"])
        with gate.slot():
            pass
        status = gate.status()
        self.assertEqual(2, status["acquired_events"])
        self.assertEqual(1, status["queue_full_events"])
        self.assertEqual(3, status["wait_events"])
        self.assertGreaterEqual(status["total_wait_ms"], 0)
        self.assertGreaterEqual(status["max_wait_ms"], status["last_wait_ms"])
        self.assertEqual(1, status["available_slots"])

