    def test_search_execution_gate_releases_slot_after_exception(self) -> None:
        gate = SearchExecutionGate(max_concurrency=1, queue_timeout_seconds=0.01)

        with self.assertRaisesRegex(RuntimeError, "backend failed"):
            with gate.slot():
                self.assertEqual(1, gate.status()["in_flight"])
                raise RuntimeError("backend failed")

        status = gate.status()
        self.assertEqual(0, status["in_flight"])
        self.assertEqual(1, status["available_slots"])
        self.assertEqual(1, status["acquired_events"])
        self.assertEqual(1, status["wait_events"])
        with gate.slot():
            pass
        self.assertEqual(0, gate.status()["in_flight"])
        self.assertEqual(2, gate.status()["acquired_events"])

