    def test_redis_rate_limiter_uses_fixed_window_keys(self) -> None:
        class FakeRedisClient:
            def __init__(self) -> None:
                self.values: dict[str, int] = {}
                self.expirations: dict[str, int] = {}
                self.expire_calls: list[tuple[str, int]] = []

            def incr(self, key: str) -> int:
                self.values[key] = self.values.get(key, 0) + 1
                return self.values[key]

            def expire(self, key: str, seconds: int) -> None:
                self.expirations[key] = seconds
                self.expire_calls.append((key, seconds))

        limiter = object.__new__(RedisRateLimiter)
        limiter.client = FakeRedisClient()
        limiter.key_prefix = "hai"

        self.assertEqual((True, 1), limiter.hit("ip:1.2.3.4", 2, now=120.0))
        self.assertEqual((True, 2), limiter.hit("ip:1.2.3.4", 2, now=121.0))
        self.assertEqual((False, 3), limiter.hit("ip:1.2.3.4", 2, now=122.0))
        self.assertEqual((True, 1), limiter.hit("ip:1.2.3.4", 2, now=180.0))
        self.assertIn("hai:rate-limit:ip:1.2.3.4:2", limiter.client.expirations)
        self.assertIn("hai:rate-limit:ip:1.2.3.4:3", limiter.client.expirations)
        self.assertEqual(4, len(limiter.client.expire_calls))

    def test_redis_rate_limiter_prefers_atomic_eval_for_count_and_ttl(self) -> None:
        class EvalRedisClient:
            def __init__(self) -> None:
                self.values: dict[str, int] = {}
                self.expirations: dict[str, int] = {}
                self.eval_calls: list[tuple[str, int, str, int]] = []

            def eval(self, script: str, key_count: int, key: str, ttl: int) -> int:
                self.eval_calls.append((script, key_count, key, ttl))
                self.values[key] = self.values.get(key, 0) + 1
                self.expirations[key] = ttl
                return self.values[key]

            def incr(self, key: str) -> int:  # noqa: ARG002
                raise AssertionError("eval path should not call incr directly")

            def expire(self, key: str, seconds: int) -> None:  # noqa: ARG002
                raise AssertionError("eval path should not call expire directly")

        limiter = object.__new__(RedisRateLimiter)
        limiter.client = EvalRedisClient()
        limiter.key_prefix = "hai"

        self.assertEqual((True, 1), limiter.hit("ip:1.2.3.4", 2, now=120.0))
        self.assertEqual((True, 2), limiter.hit("ip:1.2.3.4", 2, now=121.0))
        self.assertEqual(2, len(limiter.client.eval_calls))
        script, key_count, key, ttl = limiter.client.eval_calls[0]
        self.assertIn("INCR", script)
        self.assertIn("EXPIRE", script)
        self.assertEqual(1, key_count)
        self.assertEqual("hai:rate-limit:ip:1.2.3.4:2", key)
        self.assertEqual(120, ttl)

    def test_redis_rate_limiter_treats_zero_as_disabled(self) -> None:
        class FakeRedisClient:
            def __init__(self) -> None:
                self.incr_calls: list[str] = []
                self.expire_calls: list[tuple[str, int]] = []

            def incr(self, key: str) -> int:
                self.incr_calls.append(key)
                return 1

            def expire(self, key: str, seconds: int) -> None:
                self.expire_calls.append((key, seconds))

        limiter = object.__new__(RedisRateLimiter)
        limiter.client = FakeRedisClient()
        limiter.key_prefix = "hai"

        self.assertEqual((True, 0), limiter.hit("ip:1.2.3.4", 0, now=120.0))
        self.assertEqual([], limiter.client.incr_calls)
        self.assertEqual([], limiter.client.expire_calls)

    def test_redis_rate_limiter_falls_back_to_local_buckets_when_redis_fails(self) -> None:
        class FailingRedisClient:
            def incr(self, key: str) -> int:
                raise OSError("redis unavailable")

            def expire(self, key: str, seconds: int) -> None:
                raise AssertionError("expire should not run after failed incr")

        limiter = object.__new__(RedisRateLimiter)
        limiter.client = FailingRedisClient()
        limiter.key_prefix = "hai"

        self.assertEqual((True, 1), limiter.hit("ip:1.2.3.4", 2, now=120.0))
        self.assertEqual((True, 2), limiter.hit("ip:1.2.3.4", 2, now=121.0))
        self.assertEqual((False, 2), limiter.hit("ip:1.2.3.4", 2, now=122.0))
        self.assertEqual((True, 1), limiter.hit("mall:shop001", 1, now=122.0))
        self.assertEqual((False, 1), limiter.hit("mall:shop001", 1, now=123.0))
        self.assertEqual((True, 1), limiter.hit("ip:1.2.3.4", 2, now=182.0))
        status = limiter.status()
        self.assertEqual("redis", status["backend"])
        self.assertTrue(status["redis_enabled"])
        self.assertEqual(6, status["fallback_events"])
        self.assertTrue(status["fallback_active"])
        self.assertEqual(2, status["fallback_bucket_count"])
        self.assertEqual(10000, status["fallback_max_buckets"])
        self.assertEqual(1.0, status["fallback_prune_interval_seconds"])
        self.assertEqual(1, status["fallback_pruned_buckets"])
        self.assertEqual(0, status["fallback_skipped_redis_events"])
        self.assertEqual(0, status["redis_backoff_skipped_operations"])
        self.assertEqual("redis unavailable", status["last_error"])

    def test_search_service_cache_can_be_injected_for_shared_cache(self) -> None:
        class CountingEngine(LocalSearchEngine):
            def __init__(self, products):
                super().__init__(products)
                self.search_count = 0

            def search(self, query):  # type: ignore[no-untyped-def]
                self.search_count += 1
                return super().search(query)

        with tempfile.TemporaryDirectory() as temp_dir:
            engine = CountingEngine(
                [
                    ProductDocument(
                        product_id="P001",
                        name="검정 우산",
                        category="우산",
                        status="active",
                    )
                ]
            )
            settings = Settings(
                engine_backend="local",
                index_name="test",
                search_log_path=Path(temp_dir) / "search.jsonl",
                cache_ttl_seconds=30,
            )
            service = AISearchService(engine, settings, cache=MemorySearchCache(settings.cache_ttl_seconds))

            first = service.search(SearchRequest(mall_id="shop001", q="우산", limit=5))
            second = service.search(SearchRequest(mall_id="shop001", q="우산", limit=5))

            self.assertEqual(1, engine.search_count)
            self.assertEqual(first.top[0].product_id, second.top[0].product_id)
            self.assertIsNot(first, second)
            self.assertIsNot(first.meta, second.meta)
            entries = service.logger.tail(10)
            self.assertEqual([False, True], [entry["cached"] for entry in entries])

