    def test_marqo_qwen_query_vector_rejects_invalid_precomputed_cache_vectors(self) -> None:
        with tempfile.TemporaryDirectory() as temp_dir:
            cache_path = Path(temp_dir) / "query-cache.json"

            def write_cache(vector: list[object], *, text: str = "우산") -> None:
                cache_path.write_text(
                    json.dumps({"items": [{"text": text, "vector": vector}]}, ensure_ascii=False),
                    encoding="utf-8",
                )

            write_cache([0.1])

            with self.assertRaisesRegex(ValueError, "expected 2"):
                MarqoSearchEngine(
                    "http://localhost:8882",
                    "test",
                    embedding_backend="qwen",
                    qwen_embedding_dimensions=2,
                    qwen_query_embedding_cache_path=cache_path,
                )

            write_cache([0.1, "x"])

            with self.assertRaisesRegex(ValueError, "is not numeric"):
                MarqoSearchEngine(
                    "http://localhost:8882",
                    "test",
                    embedding_backend="qwen",
                    qwen_embedding_dimensions=2,
                    qwen_query_embedding_cache_path=cache_path,
                )

            write_cache([0.1, "nan"])

            with self.assertRaisesRegex(ValueError, "is not finite"):
                MarqoSearchEngine(
                    "http://localhost:8882",
                    "test",
                    embedding_backend="qwen",
                    qwen_embedding_dimensions=2,
                    qwen_query_embedding_cache_path=cache_path,
                )

            write_cache([0.1, "0.2"], text="우산 umbrella 3단 장우산")
            engine = MarqoSearchEngine(
                "http://localhost:8882",
                "test",
                embedding_backend="qwen",
                qwen_embedding_dimensions=2,
                qwen_query_embedding_cache_path=cache_path,
            )

            vector, _field, source = engine.qwen_query_vector(EngineQuery(q="우산"))

            self.assertEqual([0.1, 0.2], vector)
            self.assertEqual("text_to_image_cache", source)

