    def test_marqo_qwen_query_vector_coalesces_concurrent_text_embedding_misses(self) -> None:
        class SlowCountingQwenMarqoSearchEngine(MarqoSearchEngine):
            def __init__(self):
                super().__init__("http://localhost:8882", "test", embedding_backend="qwen")
                self.embed_calls = 0
                self.lock = threading.Lock()

            def qwen_embed_query_texts(self, texts: list[str], **_: object) -> list[list[float]]:
                with self.lock:
                    self.embed_calls += 1
                    embed_call = self.embed_calls
                time.sleep(0.05)
                vector = [0.0] * 2048
                vector[0] = float(embed_call)
                return [vector for _ in texts]

        engine = SlowCountingQwenMarqoSearchEngine()
        barrier = threading.Barrier(12)

        def vector_once(index: int) -> tuple[list[float], str, str]:
            barrier.wait(timeout=10)
            return engine.qwen_query_vector(EngineQuery(q="우산", limit=index + 1))

        with ThreadPoolExecutor(max_workers=12) as pool:
            results = list(pool.map(vector_once, range(12)))

        vectors = [item[0] for item in results]
        self.assertEqual(1, engine.embed_calls)
        self.assertEqual({1.0}, {vector[0] for vector in vectors})
        self.assertEqual({"qwen_image_vector"}, {item[1] for item in results})
        status = engine.qwen_query_vector_status()
        self.assertEqual(1, status["runtime_text_entries"])
        self.assertEqual(0, status["runtime_image_entries"])
        self.assertGreaterEqual(status["wait_events"], 1)
        self.assertEqual(0, status["wait_timeouts"])

