    def test_marqo_search_uses_configured_timeout_and_retries_transient_errors(self) -> None:
        class FlakyMarqoSearchEngine(MarqoSearchEngine):
            def __init__(self):
                super().__init__(
                    "http://marqo.example.test",
                    "products",
                    search_timeout_seconds=0.25,
                    search_retry_count=1,
                    search_retry_delay_seconds=0,
                )
                self.calls: list[tuple[str, float]] = []

            def _request(self, method, path, payload=None, timeout=60):  # type: ignore[no-untyped-def]
                self.calls.append((path, float(timeout)))
                if len(self.calls) == 1:
                    raise urllib.error.URLError("temporary marqo outage")
                return (
                    200,
                    {
                        "hits": [
                            {
                                "_id": "P-UMBRELLA",
                                "product_id": "P-UMBRELLA",
                                "product_name": "검정 우산",
                                "category_name": "우산",
                                "status": "active",
                                "display_yn": "Y",
                                "_score": 0.91,
                            }
                        ]
                    },
                    1.0,
                )

        engine = FlakyMarqoSearchEngine()
        hits = engine.search(EngineQuery(q="우산", limit=1))

        self.assertEqual(["P-UMBRELLA"], [hit.document.product_id for hit in hits])
        self.assertEqual([("/indexes/products/search", 0.25), ("/indexes/products/search", 0.25)], engine.calls)

