    def test_search_service_coalesces_concurrent_identical_cache_misses(self) -> None:
        class SlowCountingEngine(LocalSearchEngine):
            def __init__(self, products):
                super().__init__(products)
                self.search_count = 0
                self.lock = threading.Lock()

            def search(self, query):  # type: ignore[no-untyped-def]
                with self.lock:
                    self.search_count += 1
                time.sleep(0.05)
                return super().search(query)

        with tempfile.TemporaryDirectory() as temp_dir:
            engine = SlowCountingEngine(
                [
                    ProductDocument(
                        product_id="P001",
                        name="검정 우산",
                        category="우산",
                        status="active",
                    )
                ]
            )
            settings = Settings(
                engine_backend="local",
                index_name="test",
                search_log_path=Path(temp_dir) / "search.jsonl",
                cache_ttl_seconds=30,
            )
            service = AISearchService(engine, settings, cache=MemorySearchCache(settings.cache_ttl_seconds))
            barrier = threading.Barrier(20)

            def search_once(_: int) -> str:
                barrier.wait()
                result = service.search(SearchRequest(mall_id="shop001", q="우산", limit=5))
                return result.top[0].product_id

            with ThreadPoolExecutor(max_workers=20) as pool:
                product_ids = list(pool.map(search_once, range(20)))

            self.assertEqual(["P001"] * 20, product_ids)
            self.assertEqual(1, engine.search_count)
            entries = service.logger.tail(25)
            self.assertEqual(1, sum(1 for entry in entries if entry["cached"] is False))
            self.assertEqual(19, sum(1 for entry in entries if entry["cached"] is True))

    def test_search_service_rejects_singleflight_wait_timeout_without_duplicate_backend_call(self) -> None:
        class BlockingCountingEngine(LocalSearchEngine):
            def __init__(self, products):
                super().__init__(products)
                self.search_count = 0
                self.lock = threading.Lock()
                self.first_started = threading.Event()

            def search(self, query):  # type: ignore[no-untyped-def]
                with self.lock:
                    self.search_count += 1
                    search_count = self.search_count
                if search_count == 1:
                    self.first_started.set()
                    time.sleep(0.15)
                return super().search(query)

        with tempfile.TemporaryDirectory() as temp_dir:
            engine = BlockingCountingEngine(
                [
                    ProductDocument(
                        product_id="P001",
                        name="검정 우산",
                        category="우산",
                        status="active",
                    )
                ]
            )
            settings = Settings(
                engine_backend="local",
                index_name="test",
                search_log_path=Path(temp_dir) / "search.jsonl",
                cache_ttl_seconds=30,
                cache_miss_wait_seconds=0.01,
            )
            service = AISearchService(engine, settings, cache=MemorySearchCache(settings.cache_ttl_seconds))
            request = SearchRequest(mall_id="shop001", q="우산", limit=5)

            with ThreadPoolExecutor(max_workers=1) as pool:
                first = pool.submit(service.search, request)
                self.assertTrue(engine.first_started.wait(timeout=1.0))
                with self.assertRaisesRegex(SearchCacheMissInFlight, "identical search is still running"):
                    service.search(request)
                first_result = first.result(timeout=2.0)

            self.assertEqual("P001", first_result.top[0].product_id)
            self.assertEqual(1, engine.search_count)
            status = service.singleflight_status()
            self.assertEqual(0, status["in_flight"])
            self.assertEqual(1, status["wait_events"])
            self.assertEqual(1, status["wait_timeouts"])
            self.assertGreaterEqual(status["max_wait_ms"], 1)
            entries = service.logger.tail(10)
            self.assertEqual(1, sum(1 for entry in entries if entry["cached"] is False))

    def test_search_service_shares_singleflight_backend_failures(self) -> None:
        class FailingEngine(LocalSearchEngine):
            def __init__(self, products):
                super().__init__(products)
                self.search_count = 0
                self.lock = threading.Lock()

            def search(self, query):  # type: ignore[no-untyped-def]
                with self.lock:
                    self.search_count += 1
                time.sleep(0.05)
                raise RuntimeError("backend unavailable")

        with tempfile.TemporaryDirectory() as temp_dir:
            engine = FailingEngine(
                [
                    ProductDocument(
                        product_id="P001",
                        name="검정 우산",
                        category="우산",
                        status="active",
                    )
                ]
            )
