    def test_search_service_waits_for_distributed_cache_miss_owner(self) -> None:
        class SlowCountingEngine(LocalSearchEngine):
            def __init__(self, products):
                super().__init__(products)
                self.search_count = 0
                self.lock = threading.Lock()

            def search(self, query):  # type: ignore[no-untyped-def]
                with self.lock:
                    self.search_count += 1
                time.sleep(0.05)
                return super().search(query)

        class DistributedMemorySearchCache(MemorySearchCache):
            def __init__(self, ttl_seconds: int):
                super().__init__(ttl_seconds)
                self.claimed: set[str] = set()
                self.claim_lock = threading.Lock()
                self.lock_claims = 0
                self.lock_contention_events = 0

            def claim_miss_owner(self, key: str, lock_seconds: float) -> bool:  # noqa: ARG002
                with self.claim_lock:
                    if key in self.claimed:
                        self.lock_contention_events += 1
                        return False
                    self.claimed.add(key)
                    self.lock_claims += 1
                    return True

            def release_miss_owner(self, key: str) -> None:
                with self.claim_lock:
                    self.claimed.discard(key)

        with tempfile.TemporaryDirectory() as temp_dir:
            engine = SlowCountingEngine(
                [
                    ProductDocument(
                        product_id="P001",
                        name="검정 우산",
                        category="우산",
                        status="active",
                    )
                ]
            )
            cache = DistributedMemorySearchCache(30)
            settings = Settings(
                engine_backend="local",
                index_name="test",
                search_log_path=Path(temp_dir) / "search.jsonl",
                cache_ttl_seconds=30,
                cache_miss_wait_seconds=1.0,
                cache_miss_poll_seconds=0.005,
            )
            services = [
                AISearchService(engine, settings, cache=cache),
                AISearchService(engine, settings, cache=cache),
            ]
            barrier = threading.Barrier(2)

            def search_once(index: int) -> str:
                barrier.wait()
                result = services[index].search(SearchRequest(mall_id="shop001", q="우산", limit=5))
                return result.top[0].product_id

            with ThreadPoolExecutor(max_workers=2) as pool:
                product_ids = list(pool.map(search_once, range(2)))

            self.assertEqual(["P001", "P001"], product_ids)
            self.assertEqual(1, engine.search_count)
            self.assertEqual(1, cache.lock_claims)
            self.assertEqual(1, cache.lock_contention_events)
            cache_status = cache.status()
            self.assertEqual(1, cache_status["lock_wait_events"])
            self.assertEqual(0, cache_status["lock_wait_timeouts"])
            self.assertGreater(cache_status["lock_total_wait_ms"], 0)
            entries = services[0].logger.tail(10)
            self.assertEqual(1, sum(1 for entry in entries if entry["cached"] is False))
            self.assertEqual(1, sum(1 for entry in entries if entry["cached"] is True))

    def test_search_service_rejects_distributed_cache_miss_wait_timeout_without_duplicate_backend_call(self) -> None:
        class BlockingCountingEngine(LocalSearchEngine):
            def __init__(self, products):
                super().__init__(products)
                self.search_count = 0
                self.lock = threading.Lock()
                self.first_started = threading.Event()

            def search(self, query):  # type: ignore[no-untyped-def]
                with self.lock:
                    self.search_count += 1
                    search_count = self.search_count
                if search_count == 1:
                    self.first_started.set()
                    time.sleep(0.15)
                return super().search(query)

        class DistributedMemorySearchCache(MemorySearchCache):
            def __init__(self, ttl_seconds: int):
                super().__init__(ttl_seconds)
                self.claimed: set[str] = set()
                self.claim_lock = threading.Lock()
                self.lock_claims = 0
                self.lock_contention_events = 0

            def claim_miss_owner(self, key: str, lock_seconds: float) -> bool:  # noqa: ARG002
                with self.claim_lock:
                    if key in self.claimed:
                        self.lock_contention_events += 1
                        return False
                    self.claimed.add(key)
                    self.lock_claims += 1
                    return True

            def release_miss_owner(self, key: str) -> None:
                with self.claim_lock:
                    self.claimed.discard(key)

            def status(self) -> dict[str, object]:
                status = super().status()
                status["lock_claims"] = self.lock_claims
                status["lock_contention_events"] = self.lock_contention_events
                return status

        with tempfile.TemporaryDirectory() as temp_dir:
            engine = BlockingCountingEngine(
                [
                    ProductDocument(
                        product_id="P001",
                        name="검정 우산",
                        category="우산",
                        status="active",
                    )
                ]
            )
            cache = DistributedMemorySearchCache(30)
            settings = Settings(
                engine_backend="local",
                index_name="test",
                search_log_path=Path(temp_dir) / "search.jsonl",
                cache_ttl_seconds=30,
                cache_miss_wait_seconds=0.01,
                cache_miss_poll_seconds=0.005,
            )
            owner_service = AISearchService(engine, settings, cache=cache)
            follower_service = AISearchService(engine, settings, cache=cache)
            request = SearchRequest(mall_id="shop001", q="우산", limit=5)

            with ThreadPoolExecutor(max_workers=1) as pool:
                owner = pool.submit(owner_service.search, request)
                self.assertTrue(engine.first_started.wait(timeout=1.0))
                with self.assertRaisesRegex(SearchCacheMissInFlight, "another API worker"):
                    follower_service.search(request)
                owner_result = owner.result(timeout=2.0)

            self.assertEqual("P001", owner_result.top[0].product_id)
            self.assertEqual(1, engine.search_count)
            cache_status = cache.status()
            self.assertEqual(1, cache_status["lock_claims"])
            self.assertGreaterEqual(cache_status["lock_contention_events"], 2)
            self.assertEqual(1, cache_status["lock_wait_events"])
            self.assertEqual(1, cache_status["lock_wait_timeouts"])
            self.assertGreaterEqual(cache_status["lock_max_wait_ms"], 1)

    def test_search_service_bypasses_singleflight_when_cache_is_disabled(self) -> None:
        class SlowCountingEngine(LocalSearchEngine):
            def __init__(self, products):
                super().__init__(products)
                self.search_count = 0
                self.active = 0
                self.max_active = 0
                self.lock = threading.Lock()

            def search(self, query):  # type: ignore[no-untyped-def]
                with self.lock:
                    self.search_count += 1
                    self.active += 1
                    self.max_active = max(self.max_active, self.active)
                try:
                    time.sleep(0.05)
                    return super().search(query)
                finally:
                    with self.lock:
                        self.active -= 1

        with tempfile.TemporaryDirectory() as temp_dir:
            engine = SlowCountingEngine(
                [
                    ProductDocument(
                        product_id="P001",
                        name="검정 우산",
                        category="우산",
                        status="active",
                    )
                ]
            )
            settings = Settings(
                engine_backend="local",
                index_name="test",
                search_log_path=Path(temp_dir) / "search.jsonl",
                cache_ttl_seconds=0,
            )
            service = AISearchService(engine, settings, cache=MemorySearchCache(settings.cache_ttl_seconds))
            barrier = threading.Barrier(8)

            def search_once(_: int) -> str:
                barrier.wait()
                result = service.search(SearchRequest(mall_id="shop001", q="우산", limit=5))
                return result.top[0].product_id

            with ThreadPoolExecutor(max_workers=8) as pool:
                product_ids = list(pool.map(search_once, range(8)))

            self.assertEqual(["P001"] * 8, product_ids)
            self.assertEqual(8, engine.search_count)
            self.assertGreaterEqual(engine.max_active, 2)
            entries = service.logger.tail(10)
            self.assertEqual(8, sum(1 for entry in entries if entry["cached"] is False))
            self.assertEqual(0, sum(1 for entry in entries if entry["cached"] is True))

    def test_search_service_only_materializes_returned_result_items(self) -> None:
        class ManyHitsEngine(LocalSearchEngine):
            name = "local"

            def search(self, query):  # type: ignore[no-untyped-def]
                return [
                    EngineHit(
                        document=ProductDocument(
                            product_id=f"P{index:03d}",
                            name=f"우산 상품 {index}",
                            category=f"카테고리{index % 20}",
                            price=1000 + index,
                            status="active",
                            mall_id="shop001",
                        ),
                        score=max(0.01, 1.0 - (index * 0.001)),
                        source_scores={"text": max(0.01, 1.0 - (index * 0.001))},
                    )
                    for index in range(100)
                ]

        class CountingItemService(AISearchService):
            def __init__(self, *args, **kwargs):  # type: ignore[no-untyped-def]
                super().__init__(*args, **kwargs)
                self.materialized_product_ids: list[str] = []

            def _to_item(self, hit, mall_id):  # type: ignore[no-untyped-def]
                self.materialized_product_ids.append(hit.document.product_id)
                return super()._to_item(hit, mall_id)

        with tempfile.TemporaryDirectory() as temp_dir:
            settings = Settings(
                engine_backend="local",
                index_name="test",
                search_log_path=Path(temp_dir) / "search.jsonl",
                cache_ttl_seconds=0,
                max_offset=100,
            )
            service = CountingItemService(ManyHitsEngine(), settings, cache=MemorySearchCache(0))

            result = service.search(SearchRequest(mall_id="shop001", q="우산", limit=5, offset=10))

        self.assertEqual(["P000", "P001", "P002"], [item.product_id for item in result.top])
        self.assertEqual(["P013", "P014", "P015", "P016", "P017"], [item.product_id for item in result.items])
        self.assertTrue(result.meta.has_more)
        self.assertEqual(15, result.meta.next_offset)
        self.assertEqual(
            ["P000", "P001", "P002", "P013", "P014", "P015", "P016", "P017"],
            service.materialized_product_ids,
        )
        self.assertLess(len(service.materialized_product_ids), 100)
        self.assertGreaterEqual(len(result.suggested_categories), 10)

    def test_sync_clears_shared_search_cache_after_index_mutation(self) -> None:
        class CountingEngine(LocalSearchEngine):
            def __init__(self, products):
                super().__init__(products)
                self.search_count = 0

            def search(self, query):  # type: ignore[no-untyped-def]
                self.search_count += 1
                return super().search(query)

        with tempfile.TemporaryDirectory() as temp_dir:
            csv_path = Path(temp_dir) / "products.csv"
            csv_path.write_text(
                "\n".join(
                    [
                        "product_id,product_name,category_name,status,display_yn,price",
                        "P001,숨김 우산,우산,inactive,N,8500",
                    ]
                ),
                encoding="utf-8",
            )
            cache = MemorySearchCache(30)
            settings = Settings(
                engine_backend="local",
                index_name="test",
                product_csv_path=csv_path,
                search_log_path=Path(temp_dir) / "search.jsonl",
                sync_log_path=Path(temp_dir) / "sync.jsonl",
                cache_ttl_seconds=30,
            )
            engine = CountingEngine(
                [
                    ProductDocument(
                        product_id="P001",
                        name="검정 우산",
                        category="우산",
                        status="active",
                    )
                ]
            )
            service = AISearchService(engine, settings, SearchLogger(settings.search_log_path), cache=cache)

            first = service.search(SearchRequest(mall_id="shop001", q="우산", limit=5))
            cached = service.search(SearchRequest(mall_id="shop001", q="우산", limit=5))
            self.assertEqual("P001", first.top[0].product_id)
            self.assertEqual("P001", cached.top[0].product_id)
            self.assertEqual(1, engine.search_count)
            self.assertEqual(1, cache.status()["entry_count"])
            self.assertEqual(0, cache.status()["clear_errors"])

            sync = SyncService(engine, CsvProductSource(csv_path), settings, search_cache=cache)
            result = sync.sync_changed()

            self.assertEqual(0, result.failed)
            self.assertEqual(1, result.deleted)
            self.assertEqual(0, cache.status()["entry_count"])
            sync_events = sync.logger.tail(20)
            cache_events = [entry for entry in sync_events if entry.get("type") == "search_cache_cleared"]
            self.assertEqual(1, len(cache_events))
