    def test_redis_search_cache_failures_are_cache_misses(self) -> None:
        class FakeRedisClient:
            def __init__(self):
                self.deleted: list[str] = []
                self.raise_on_get = False
                self.raise_on_set = False
                self.raw = '{"not":"a search response"}'

            def get(self, key: str) -> str:
                if self.raise_on_get:
                    raise OSError("redis unavailable")
                return self.raw

            def delete(self, key: str) -> None:
                self.deleted.append(key)

            def setex(self, key: str, seconds: int, value: str) -> None:
                if self.raise_on_set:
                    raise OSError("redis unavailable")

        with tempfile.TemporaryDirectory() as temp_dir:
            service = self.make_service(
                [
                    ProductDocument(
                        product_id="P001",
                        name="검정 우산",
                        category="우산",
                        status="active",
                    )
                ],
                Path(temp_dir) / "search.jsonl",
            )
            response = service.search(SearchRequest(mall_id="shop001", q="우산", limit=5))
            cache = object.__new__(RedisSearchCache)
            cache.client = FakeRedisClient()
            cache.key_prefix = "hai"
            cache.ttl_seconds = 30

            self.assertIsNone(cache.get("corrupt"))
            self.assertEqual(1, len(cache.client.deleted))

            cache.client.raise_on_get = True
            self.assertIsNone(cache.get("unavailable"))

            cache.client.raise_on_set = True
            cache.set("unavailable", response)
            status = cache.status()
            self.assertEqual("redis", status["backend"])
            self.assertEqual(3, status["error_count"])
            self.assertEqual(1, status["get_errors"])
            self.assertEqual(1, status["set_errors"])
            self.assertEqual(1, status["decode_errors"])
            self.assertEqual(0, status["delete_errors"])
            self.assertEqual("set", status["last_error_operation"])

    def test_redis_search_cache_backoff_skips_repeated_unavailable_redis_calls(self) -> None:
        class FailingRedisClient:
            def __init__(self):
                self.get_calls = 0
                self.setex_calls = 0

            def get(self, key: str) -> str:  # noqa: ARG002
                self.get_calls += 1
                raise OSError("redis unavailable")

            def setex(self, key: str, seconds: int, value: str) -> None:  # noqa: ARG002
                self.setex_calls += 1
                raise OSError("redis unavailable")

        cache = object.__new__(RedisSearchCache)
        cache.client = FailingRedisClient()
        cache.key_prefix = "hai"
        cache.ttl_seconds = 30
        cache.redis_failure_backoff_seconds = 30.0

        self.assertIsNone(cache.get("first"))
        self.assertIsNone(cache.get("second"))

        status = cache.status()
        self.assertEqual(1, cache.client.get_calls)
        self.assertEqual(0, cache.client.setex_calls)
        self.assertEqual(1, status["get_errors"])
        self.assertEqual(1, status["error_count"])
        self.assertTrue(status["redis_backoff_active"])
        self.assertEqual(1, status["redis_backoff_failure_events"])
        self.assertEqual(1, status["redis_backoff_skipped_operations"])

    def test_redis_clients_configure_socket_timeouts_and_failure_backoff(self) -> None:
        class FakeRedisModule:
            class Redis:
                calls: list[tuple[str, dict[str, object]]] = []

                @staticmethod
                def from_url(redis_url: str, **kwargs: object) -> object:
                    FakeRedisModule.Redis.calls.append((redis_url, kwargs))
                    return object()

        with patch.dict(sys.modules, {"redis": FakeRedisModule}):
            cache = RedisSearchCache(
                "redis://redis:6379/0",
                "hai",
                30,
                socket_timeout_seconds=0.2,
                socket_connect_timeout_seconds=0.3,
                failure_backoff_seconds=1.5,
            )
            limiter = RedisRateLimiter(
                "redis://redis:6379/0",
                "hai",
                socket_timeout_seconds=0.2,
                socket_connect_timeout_seconds=0.3,
                failure_backoff_seconds=1.5,
            )

        self.assertEqual(2, len(FakeRedisModule.Redis.calls))
        for _, kwargs in FakeRedisModule.Redis.calls:
            self.assertEqual(0.2, kwargs["socket_timeout"])
            self.assertEqual(0.3, kwargs["socket_connect_timeout"])
            self.assertTrue(kwargs["socket_keepalive"])
            self.assertEqual(30, kwargs["health_check_interval"])
            self.assertFalse(kwargs["retry_on_timeout"])
        self.assertEqual(1.5, cache.status()["redis_backoff_seconds"])
        self.assertEqual(1.5, limiter.status()["redis_backoff_seconds"])

