    def test_redis_search_cache_coordinates_distributed_cache_misses(self) -> None:
        class FakeRedisClient:
            def __init__(self):
                self.values: dict[str, str] = {}
                self.deleted: list[str] = []

            def set(self, key: str, value: str, nx: bool = False, px: int | None = None) -> bool:  # noqa: ARG002
                if nx and key in self.values:
                    return False
                self.values[key] = value
                return True

            def get(self, key: str) -> str | None:
                return self.values.get(key)

            def delete(self, *keys: str) -> int:
                deleted = 0
                for key in keys:
                    if key in self.values:
                        deleted += 1
                        self.values.pop(key, None)
                        self.deleted.append(key)
                return deleted

            def eval(self, script: str, key_count: int, key: str, token: str) -> int:  # noqa: ARG002
                if self.values.get(key) != token:
                    return 0
                return self.delete(key)

        cache = object.__new__(RedisSearchCache)
        cache.client = FakeRedisClient()
        cache.key_prefix = "hai"
        cache.ttl_seconds = 30

        self.assertTrue(cache.claim_miss_owner("same-query", 3.0))
        self.assertFalse(cache.claim_miss_owner("same-query", 3.0))
        cache.release_miss_owner("same-query")
        self.assertTrue(cache.claim_miss_owner("same-query", 3.0))
        cache.release_miss_owner("same-query")

        status = cache.status()
        self.assertEqual(2, status["lock_claims"])
        self.assertEqual(1, status["lock_contention_events"])
        self.assertEqual(0, status["lock_errors"])
        self.assertEqual(0, status["lock_release_errors"])

    def test_redis_search_cache_clear_deletes_prefixed_keys_and_reports_failures(self) -> None:
        class FakeRedisClient:
            def __init__(self):
                self.keys = [
                    "hai:search-cache:aaa",
                    "hai:search-cache:bbb",
                    "other:search-cache:ccc",
                ]
                self.deleted: list[str] = []
                self.raise_on_scan = False

            def scan_iter(self, match: str, count: int = 1000):  # type: ignore[no-untyped-def]
                if self.raise_on_scan:
                    raise OSError("redis scan unavailable")
                prefix = match[:-1]
                for key in self.keys:
                    if key.startswith(prefix):
                        yield key

            def delete(self, *keys: str) -> int:
                self.deleted.extend(keys)
                return len(keys)

        cache = object.__new__(RedisSearchCache)
        cache.client = FakeRedisClient()
        cache.key_prefix = "hai"
        cache.ttl_seconds = 30

        report = cache.clear()

        self.assertTrue(report["ok"])
        self.assertEqual(2, report["scanned"])
        self.assertEqual(2, report["cleared"])
        self.assertEqual(["hai:search-cache:aaa", "hai:search-cache:bbb"], cache.client.deleted)

        cache.client.raise_on_scan = True
        failed = cache.clear()
        self.assertFalse(failed["ok"])
        self.assertEqual("clear", cache.status()["last_error_operation"])
        self.assertEqual(1, cache.status()["clear_errors"])

