    def test_image_singleflight_waiters_do_not_hold_image_compute_context(self) -> None:
        validated_image = validate_image_bytes(PNG_BYTES, max_bytes=1024)
        engine_entered = threading.Event()
        release_engine = threading.Event()
        validation_count = 0
        validation_count_lock = threading.Lock()
        active_contexts = 0
        active_contexts_lock = threading.Lock()

        class BlockingImageEngine(LocalSearchEngine):
            def __init__(self, products):
                super().__init__(products)
                self.search_count = 0

            def search(self, query):  # type: ignore[no-untyped-def]
                self.search_count += 1
                engine_entered.set()
                release_engine.wait(timeout=2)
                return super().search(query)

        class CountingContext:
            def __enter__(self) -> None:
                nonlocal active_contexts
                with active_contexts_lock:
                    active_contexts += 1

            def __exit__(self, exc_type, exc, traceback) -> bool:  # type: ignore[no-untyped-def]
                nonlocal active_contexts
                with active_contexts_lock:
                    active_contexts -= 1
                return False

        def validate_image(*args, **kwargs):  # type: ignore[no-untyped-def]
            nonlocal validation_count
            with validation_count_lock:
                validation_count += 1
            return validated_image

        with tempfile.TemporaryDirectory() as temp_dir:
            engine = BlockingImageEngine(
                [
                    ProductDocument(
                        product_id="P001",
                        name="검정 우산",
                        category="우산",
                        status="active",
                        extra={"image_hash": validated_image.sha256},
                    )
                ]
            )
            service = AISearchService(
                engine,
                Settings(
                    engine_backend="local",
                    index_name="test",
                    search_log_path=Path(temp_dir) / "search.jsonl",
                    cache_ttl_seconds=30,
                    cache_miss_wait_seconds=1.0,
                ),
            )
            request = SearchRequest(mall_id="shop001", image_base64=base64.b64encode(PNG_BYTES).decode("ascii"))
            results: list[SearchResponse] = []
            errors: list[BaseException] = []

            def run_search() -> None:
                try:
                    results.append(service.search(request, lambda: CountingContext()))
                except BaseException as exc:
                    errors.append(exc)

            with patch("app.search_service.validate_image_base64", side_effect=validate_image):
                first = threading.Thread(target=run_search)
                second = threading.Thread(target=run_search)
                first.start()
                self.assertTrue(engine_entered.wait(timeout=1))
                second.start()
                deadline = time.time() + 1
                while time.time() < deadline:
                    with validation_count_lock:
                        if validation_count >= 1:
                            break
                    time.sleep(0.01)
                with active_contexts_lock:
                    active_while_waiting = active_contexts
                release_engine.set()
                first.join(timeout=2)
                second.join(timeout=2)

        self.assertEqual([], errors)
        self.assertEqual(2, len(results))
        self.assertEqual(1, engine.search_count)
        self.assertEqual(1, active_while_waiting)
        self.assertGreaterEqual(service.singleflight_status()["wait_events"], 1)

    def test_image_validation_singleflight_coalesces_parallel_duplicate_uploads(self) -> None:
        validated_image = validate_image_bytes(PNG_BYTES, max_bytes=1024)
        validation_started = threading.Event()
        release_validation = threading.Event()
        validation_count = 0
        validation_count_lock = threading.Lock()

        class CountingEngine(LocalSearchEngine):
            def __init__(self, products):
                super().__init__(products)
                self.search_count = 0

            def search(self, query):  # type: ignore[no-untyped-def]
                self.search_count += 1
                return super().search(query)

        def validate_image(*args, **kwargs):  # type: ignore[no-untyped-def]
            nonlocal validation_count
            with validation_count_lock:
                validation_count += 1
            validation_started.set()
            release_validation.wait(timeout=2)
            return validated_image

        with tempfile.TemporaryDirectory() as temp_dir:
            engine = CountingEngine(
                [
                    ProductDocument(
                        product_id="P001",
                        name="검정 우산",
                        category="우산",
                        status="active",
                        extra={"image_hash": validated_image.sha256},
                    )
                ]
            )
            service = AISearchService(
                engine,
                Settings(
                    engine_backend="local",
                    index_name="test",
                    search_log_path=Path(temp_dir) / "search.jsonl",
                    cache_ttl_seconds=30,
                    cache_miss_wait_seconds=1.0,
                ),
            )
            request = SearchRequest(mall_id="shop001", image_base64=base64.b64encode(PNG_BYTES).decode("ascii"))
            results: list[SearchResponse] = []
            errors: list[BaseException] = []

            def run_search() -> None:
                try:
                    results.append(service.search(request))
                except BaseException as exc:
                    errors.append(exc)

            with patch("app.search_service.validate_image_base64", side_effect=validate_image):
                first = threading.Thread(target=run_search)
                second = threading.Thread(target=run_search)
                first.start()
                self.assertTrue(validation_started.wait(timeout=1))
                second.start()
                time.sleep(0.05)
                release_validation.set()
                first.join(timeout=2)
                second.join(timeout=2)

        self.assertEqual([], errors)
        self.assertEqual(2, len(results))
        self.assertEqual(1, validation_count)
        self.assertEqual(1, engine.search_count)
        status = service.image_validation_status()
        self.assertGreaterEqual(status["wait_events"], 1)
        self.assertEqual(0, status["wait_timeouts"])

