    def test_inactive_duplicate_product_id_delete_failures_keep_document_identity(self) -> None:
        class PartialDeleteFailureEngine(LocalSearchEngine):
            def __init__(self, products, failed_document_id):  # type: ignore[no-untyped-def]
                super().__init__(products)
                self.failed_document_id = failed_document_id

            def delete_products(self, product_ids):  # type: ignore[no-untyped-def]
                deleted = 0
                failed = []
                for product_id in product_ids:
                    if product_id == self.failed_document_id:
                        failed.append({"document_id": product_id, "reason": "marqo delete failed"})
                        continue
                    deleted += int(super().delete_products([product_id]).get("deleted", 0))
                return {"deleted": deleted, "failed": len(failed), "failed_products": failed}

        with tempfile.TemporaryDirectory() as temp_dir:
            csv_path = Path(temp_dir) / "products.csv"
            sync_log = Path(temp_dir) / "sync.jsonl"
            csv_path.write_text(
                "\n".join(
                    [
                        "product_id,product_name,category_name,status,display_yn,price,mall_id",
                        "P001,1호점 숨김 우산,우산,inactive,N,8500,shop001",
                        "P001,2호점 숨김 우산,우산,inactive,N,8500,shop002",
                    ]
                ),
                encoding="utf-8",
            )
            failed_document_id = product_document_id("shop002", "P001")
            engine = PartialDeleteFailureEngine(
                [
                    ProductDocument(product_id="P001", name="1호점 기존 우산", category="우산", status="active", mall_id="shop001"),
                    ProductDocument(product_id="P001", name="2호점 기존 우산", category="우산", status="active", mall_id="shop002"),
                ],
                failed_document_id,
            )
            settings = Settings(
                engine_backend="local",
                index_name="test",
                product_csv_path=csv_path,
                sync_log_path=sync_log,
            )
            sync = SyncService(engine, CsvProductSource(csv_path), settings)

            result = sync.reindex_all()
            shop001 = engine.search(EngineQuery(q="우산", mall_id="shop001", strict_mall_filter=True, limit=10))
            shop002 = engine.search(EngineQuery(q="우산", mall_id="shop002", strict_mall_filter=True, limit=10))
            entries = [json.loads(line) for line in sync_log.read_text(encoding="utf-8").splitlines()]
            product_events = [entry for entry in entries if entry.get("action") == "delete_from_index"]
            requested = [entry for entry in product_events if entry.get("outcome") == "requested"]
            failed = [entry for entry in product_events if entry.get("outcome") == "failed"]

            self.assertEqual(1, result.deleted)
            self.assertEqual(1, result.failed)
            self.assertEqual([], shop001)
            self.assertEqual(["2호점 기존 우산"], [hit.document.name for hit in shop002])
            self.assertEqual(["shop001"], [entry.get("mall_id") for entry in requested])
            self.assertEqual(["shop002"], [entry.get("mall_id") for entry in failed])
            self.assertEqual(failed_document_id, failed[0]["details"]["document_id"])
            self.assertEqual("P001", failed[0]["product_id"])

