    def test_sync_logs_product_level_upsert_failures(self) -> None:
        class PartiallyFailingEngine(LocalSearchEngine):
            def upsert_products(self, products):  # type: ignore[no-untyped-def]
                product_list = list(products)
                accepted = [product for product in product_list if product.product_id != "P002"]
                super().upsert_products(accepted)
                return {
                    "indexed": len(accepted),
                    "failed": 1,
                    "failed_products": [{"product_id": "P002", "reason": "vectorization failed"}],
                }

        with tempfile.TemporaryDirectory() as temp_dir:
            csv_path = Path(temp_dir) / "products.csv"
            sync_log = Path(temp_dir) / "sync.jsonl"
            csv_path.write_text(
                "\n".join(
                    [
                        "product_id,product_name,category_name,status,display_yn,price",
                        "P001,정상 우산,우산,active,Y,8500",
                        "P002,색인 실패 우산,우산,active,Y,9000",
                    ]
                ),
                encoding="utf-8",
            )
            settings = Settings(
                engine_backend="local",
                index_name="test",
                product_csv_path=csv_path,
                sync_log_path=sync_log,
            )
            sync = SyncService(PartiallyFailingEngine([]), CsvProductSource(csv_path), settings)

            result = sync.reindex_all()
            log_text = sync_log.read_text(encoding="utf-8")

            self.assertEqual(1, result.indexed)
            self.assertEqual(1, result.failed)
            self.assertIn("sync_product_failed", log_text)
            self.assertIn("upsert_to_index", log_text)
            self.assertIn("P002", log_text)
            self.assertIn("vectorization failed", log_text)

    def test_sync_logs_source_fetch_failures(self) -> None:
        class FailingSource:
            def fetch_all(self):  # type: ignore[no-untyped-def]
                raise RuntimeError("MSSQL connection failed")

            def fetch_updated(self, since=None):  # type: ignore[no-untyped-def]
                raise RuntimeError("MSSQL connection failed")

            def fetch_one(self, product_id, mall_id=None):  # type: ignore[no-untyped-def]
                raise RuntimeError("MSSQL connection failed")

        with tempfile.TemporaryDirectory() as temp_dir:
            sync_log = Path(temp_dir) / "sync.jsonl"
            settings = Settings(engine_backend="local", index_name="test", sync_log_path=sync_log)
            sync = SyncService(LocalSearchEngine([]), FailingSource(), settings)

            result = sync.reindex_all()
            entries = [json.loads(line) for line in sync_log.read_text(encoding="utf-8").splitlines()]

            self.assertEqual(1, result.failed)
            self.assertEqual("MSSQL connection failed", result.status.last_error)
            self.assertEqual("sync_batch_failed", entries[0]["type"])
            self.assertEqual("fetch_products", entries[0]["action"])
            self.assertIn("MSSQL connection failed", entries[0]["message"])

    def test_sync_service_rejects_overlapping_runs_with_lock_file(self) -> None:
        with tempfile.TemporaryDirectory() as temp_dir:
            csv_path = Path(temp_dir) / "products.csv"
            sync_log = Path(temp_dir) / "sync.jsonl"
            csv_path.write_text(
                "\n".join(
                    [
                        "product_id,product_name,category_name,status,display_yn,price",
                        "P001,검정 우산,우산,active,Y,8500",
                    ]
                ),
                encoding="utf-8",
            )
            settings = Settings(
                engine_backend="local",
                index_name="test",
                product_csv_path=csv_path,
                sync_log_path=sync_log,
            )
            engine = LocalSearchEngine([])
            sync = SyncService(engine, CsvProductSource(csv_path), settings)
            lock_path = sync_log.with_name(sync_log.name + ".lock")
            lock_path.write_text('{"mode":"reindex"}\n', encoding="utf-8")

            busy = sync.reindex_all()

            self.assertEqual(1, busy.failed)
            self.assertIn("sync operation already running", busy.status.last_error or "")
            self.assertTrue(lock_path.exists())
            self.assertEqual([], engine.search(EngineQuery(q="우산", limit=5)))

            lock_path.unlink()
            success = sync.reindex_all()

            self.assertEqual(0, success.failed)
            self.assertFalse(lock_path.exists())
            self.assertEqual(["P001"], [hit.document.product_id for hit in engine.search(EngineQuery(q="우산", limit=5))])

    def test_sync_service_recovers_stale_lock_file(self) -> None:
        with tempfile.TemporaryDirectory() as temp_dir:
            csv_path = Path(temp_dir) / "products.csv"
            sync_log = Path(temp_dir) / "sync.jsonl"
            csv_path.write_text(
                "\n".join(
                    [
                        "product_id,product_name,category_name,status,display_yn,price",
                        "P001,검정 우산,우산,active,Y,8500",
                    ]
                ),
                encoding="utf-8",
            )
            settings = Settings(
                engine_backend="local",
                index_name="test",
                product_csv_path=csv_path,
                sync_log_path=sync_log,
                sync_lock_stale_seconds=1,
            )
            engine = LocalSearchEngine([])
            sync = SyncService(engine, CsvProductSource(csv_path), settings)
            lock_path = sync_log.with_name(sync_log.name + ".lock")
            lock_path.write_text(
                '{"mode":"reindex","pid":999999,"started_at":"2000-01-01T00:00:00+00:00"}\n',
                encoding="utf-8",
            )

            result = sync.reindex_all()

            self.assertEqual(0, result.failed)
            self.assertFalse(lock_path.exists())
            self.assertEqual(["P001"], [hit.document.product_id for hit in engine.search(EngineQuery(q="우산", limit=5))])

