    def test_mssql_wrapped_queries_support_cte_sources(self) -> None:
        cte_query = (
            "WITH changed AS ("
            "SELECT product_id, product_name, updated_at FROM dbo.v_ai_search_products"
            ") SELECT product_id, product_name, updated_at FROM changed"
        )
        export_sql, export_params = build_export_query(cte_query, limit=25, since="2026-05-01T00:00:00Z")

        self.assertTrue(export_sql.startswith("WITH changed AS (SELECT product_id"))
        self.assertIn("SELECT TOP (25) * FROM (SELECT product_id, product_name, updated_at FROM changed) AS ai_products", export_sql)
        self.assertNotIn("FROM (WITH", export_sql)
        self.assertIn("WHERE updated_at >= ?", export_sql)
        self.assertTrue(export_sql.endswith("ORDER BY product_id"))
        self.assertEqual([datetime(2026, 5, 1, 0, 0)], export_params)

        class CapturingMssqlSource(MssqlProductSource):
            def __init__(self) -> None:
                super().__init__("Driver={ODBC Driver 18 for SQL Server};Server=example;", cte_query)
                self.captured: list[tuple[str, list[object] | None]] = []

            def _fetch(self, query, params=None):  # type: ignore[no-untyped-def]
                self.captured.append((query, params))
                return []

        source = CapturingMssqlSource()
        source.fetch_updated("2026-05-01T09:00:00+09:00")
        source.fetch_one("P001")

        self.assertNotIn("FROM (WITH", source.captured[0][0])
        self.assertIn("WHERE updated_at >= ?", source.captured[0][0])
        self.assertEqual([datetime(2026, 5, 1, 0, 0)], source.captured[0][1])
        self.assertIn("WHERE product_id = ?", source.captured[1][0])
        self.assertEqual(["P001"], source.captured[1][1])

