    def test_product_image_probe_rejects_unsafe_urls_before_fetch(self) -> None:
        unsafe_urls = [
            "https://localhost./p001.jpg",
            "https://shop.localhost./p001.jpg",
            "http://127.0.0.1/p001.jpg",
            "http://[fe80::1]/p001.jpg",
            "https://shop.localhost/p001.jpg",
            "http://169.254.169.254/latest/meta-data",
            "http://10.0.0.5/private.jpg",
            "http://172.16.0.5/private.jpg",
            "http://192.168.1.5/private.jpg",
            "http://100.64.0.5/private.jpg",
            "http://203.0.113.5/private.jpg",
            "https://token@images.example.test/p001.jpg",
            "data:image/png;base64,AAAA",
        ]
        with patch("app.image_probe.open_image_request") as image_open:
            for index, image_url in enumerate(unsafe_urls, start=1):
                with self.subTest(image_url=image_url):
                    product = ProductDocument(
                        product_id=f"P{index:03d}",
                        name="검정 우산",
                        category="우산",
                        status="active",
                        main_image_url=image_url,
                    )
                    result = ProductImageProbe(max_bytes=1024 * 1024, retry_count=1).validate(product)
                    self.assertFalse(result.ok)
                    self.assertIn("safe http(s)", result.message or "")
            image_open.assert_not_called()

    def test_product_image_probe_rejects_unsafe_redirect_targets(self) -> None:
        class Headers:
            def get(self, name: str, default: str = "") -> str:
                return "image/png"

        class RedirectedResponse:
            headers = Headers()

            def __init__(self, url: str):
                self.url = url

            def __enter__(self):  # type: ignore[no-untyped-def]
                return self

            def __exit__(self, exc_type, exc, traceback):  # type: ignore[no-untyped-def]
                return False

            def geturl(self) -> str:
                return self.url

            def read(self, size: int) -> bytes:
                return PNG_BYTES

        product = ProductDocument(
            product_id="P001",
            name="검정 우산",
            category="우산",
            status="active",
            main_image_url="https://images.example.test/p001.jpg",
        )
        with patch(
            "app.image_probe.open_image_request",
            return_value=RedirectedResponse("http://169.254.169.254/latest/meta-data"),
        ) as image_open:
            result = ProductImageProbe(max_bytes=1024 * 1024, retry_count=1).validate(product)

        self.assertFalse(result.ok)
        self.assertEqual(1, image_open.call_count)
        self.assertIn("redirected", result.message or "")
        self.assertIn("safe http(s)", result.message or "")
        self.assertFalse(is_retryable_message(result.message))

        handler = SafeImageRedirectHandler()
        request = urllib.request.Request("https://images.example.test/p001.jpg")
        with self.assertRaises(UnsafeImageRedirectError):
            handler.redirect_request(
                request,
                None,
                302,
                "Found",
                {},
                "http://169.254.169.254/latest/meta-data",
            )

    def test_product_image_probe_rejects_dns_resolution_to_non_public_network(self) -> None:
        request = urllib.request.Request("https://cdn.example.test/p001.jpg")
        private_resolution = [
            (socket.AF_INET, socket.SOCK_STREAM, 6, "", ("10.0.0.5", 443)),
            (socket.AF_INET, socket.SOCK_STREAM, 6, "", ("192.168.1.5", 443)),
        ]
        with patch("app.image_probe.socket.getaddrinfo", return_value=private_resolution):
            with patch("app.image_probe.IMAGE_OPENER.open") as opener:
                with self.assertRaisesRegex(UnsafeImageHostError, "non-public"):
                    open_image_request(request, 10)
                opener.assert_not_called()

        public_resolution = [(socket.AF_INET, socket.SOCK_STREAM, 6, "", ("8.8.8.8", 443))]
        with patch("app.image_probe.socket.getaddrinfo", return_value=public_resolution):
            with patch("app.image_probe.IMAGE_OPENER.open", return_value="ok") as opener:
                self.assertEqual("ok", open_image_request(request, 10))
                opener.assert_called_once()

        with self.assertRaisesRegex(UnsafeImageHostError, "non-public"):
            validate_image_url_resolves_to_public_network(
                "https://cdn.example.test/p001.jpg",
                resolver=lambda *args, **kwargs: private_resolution,
            )

        handler = SafeImageRedirectHandler()
        with patch("app.image_probe.socket.getaddrinfo", return_value=private_resolution):
            with self.assertRaisesRegex(UnsafeImageHostError, "non-public"):
                handler.redirect_request(
                    urllib.request.Request("https://images.example.test/p001.jpg"),
                    None,
                    302,
                    "Found",
                    {},
                    "https://cdn.example.test/p001.jpg",
                )

    def test_public_http_request_dns_guard_rejects_non_public_resolution(self) -> None:
        private_resolution = [
            (socket.AF_INET, socket.SOCK_STREAM, 6, "", ("10.0.0.5", 443)),
            (socket.AF_INET, socket.SOCK_STREAM, 6, "", ("192.168.1.5", 443)),
        ]
        public_resolution = [(socket.AF_INET, socket.SOCK_STREAM, 6, "", ("93.184.216.34", 443))]

        with self.assertRaisesRegex(UnsafePublicHttpTargetError, "non-public address"):
            validate_http_url_resolves_to_public_network(
                "https://api.example.test/search",
                resolver=lambda *args, **kwargs: private_resolution,
            )

        self.assertEqual(
            ["93.184.216.34"],
            validate_http_url_resolves_to_public_network(
                "https://api.example.test/search",
                resolver=lambda *args, **kwargs: public_resolution,
            ),
        )

        handler = SafePublicHTTPRedirectHandler(resolver=lambda *args, **kwargs: private_resolution)
        with self.assertRaisesRegex(UnsafePublicHttpTargetError, "non-public address"):
            handler.redirect_request(
                urllib.request.Request("https://api.example.test/search"),
                None,
                302,
                "Found",
                {},
                "https://redirect.example.test/internal",
            )

