    def test_sync_status_restores_latest_result_from_shared_log(self) -> None:
        with tempfile.TemporaryDirectory() as temp_dir:
            csv_path = Path(temp_dir) / "products.csv"
            sync_log = Path(temp_dir) / "sync.jsonl"
            csv_path.write_text(
                "\n".join(
                    [
                        "product_id,product_name,category_name,status,display_yn,price",
                        "P001,검정 우산,우산,active,Y,8500",
                        "P002,비노출 우산,우산,inactive,N,1000",
                    ]
                ),
                encoding="utf-8",
            )
            settings = Settings(
                engine_backend="local",
                index_name="test",
                product_csv_path=csv_path,
                sync_log_path=sync_log,
            )
            sync = SyncService(
                LocalSearchEngine(
                    [
                        ProductDocument(
                            product_id="P002",
                            name="비노출 우산",
                            category="우산",
                            status="active",
                        )
                    ]
                ),
                CsvProductSource(csv_path),
                settings,
            )

            result = sync.reindex_all()
            SyncLogger(sync_log).write_image_failure(
                ImageProbeResult(False, "P003", "https://images.example.test/p003.jpg", "download failed")
            )
            fresh_service = SyncService(LocalSearchEngine([]), CsvProductSource(csv_path), settings)
            with patch.object(Path, "read_text", side_effect=AssertionError("full sync log read")):
                status = fresh_service.current_status()

            self.assertEqual("reindex", status.last_mode)
            self.assertEqual(1, status.indexed)
            self.assertEqual(1, status.deleted)
            self.assertEqual(0, status.failed)
            self.assertEqual("local", status.engine)
            self.assertEqual("test", status.index)
            self.assertEqual(result.status.last_finished_at, status.last_finished_at)

