    def test_sync_logger_latest_successful_result_ignores_failed_runs(self) -> None:
        with tempfile.TemporaryDirectory() as temp_dir:
            csv_path = Path(temp_dir) / "products.csv"
            sync_log = Path(temp_dir) / "sync.jsonl"
            csv_path.write_text(
                "\n".join(
                    [
                        "product_id,product_name,category_name,status,display_yn,price",
                        "P001,검정 우산,우산,active,Y,8500",
                    ]
                ),
                encoding="utf-8",
            )
            settings = Settings(
                engine_backend="local",
                index_name="test",
                product_csv_path=csv_path,
                sync_log_path=sync_log,
            )
            service = SyncService(LocalSearchEngine([]), CsvProductSource(csv_path), settings)
            success = service.reindex_all()
            failed = success.model_copy(deep=True)
            failed.mode = "sync"
            failed.failed = 1
            failed.status.failed = 1
            failed.status.last_error = "temporary failure"
            service.logger.write(failed)

            latest = service.logger.latest_successful_result({"sync", "reindex"})

            self.assertIsNotNone(latest)
            self.assertEqual("reindex", latest.mode)
            self.assertEqual(success.status.last_started_at, latest.status.last_started_at)

    def test_sync_failure_triggers_notifier(self) -> None:
        class FailingEngine(LocalSearchEngine):
            def upsert_products(self, products):  # type: ignore[no-untyped-def]
                raise RuntimeError("marqo unavailable")

        class FakeNotifier:
            def __init__(self) -> None:
                self.results = []

            def notify(self, result) -> bool:  # type: ignore[no-untyped-def]
                self.results.append(result)
                return True

        with tempfile.TemporaryDirectory() as temp_dir:
            csv_path = Path(temp_dir) / "products.csv"
            csv_path.write_text(
                "\n".join(
                    [
                        "product_id,product_name,category_name,status,display_yn,price",
                        "P001,검정 우산,우산,active,Y,8500",
                    ]
                ),
                encoding="utf-8",
            )
            settings = Settings(
                engine_backend="local",
                index_name="test",
                product_csv_path=csv_path,
                sync_log_path=Path(temp_dir) / "sync.jsonl",
            )
            notifier = FakeNotifier()
            sync = SyncService(FailingEngine(), CsvProductSource(csv_path), settings, notifier=notifier)

            result = sync.reindex_all()

            self.assertEqual(1, result.failed)
            self.assertIn("marqo unavailable", result.status.last_error or "")
            self.assertEqual(1, len(notifier.results))
            self.assertEqual("reindex", notifier.results[0].mode)

    def test_sync_failure_notifier_posts_webhook_payload(self) -> None:
        class FakeResponse:
            def __enter__(self):  # type: ignore[no-untyped-def]
                return self

            def __exit__(self, exc_type, exc, traceback):  # type: ignore[no-untyped-def]
                return False

            def read(self) -> bytes:
                return b"ok"

        with tempfile.TemporaryDirectory() as temp_dir:
            csv_path = Path(temp_dir) / "products.csv"
            csv_path.write_text(
                "\n".join(
                    [
                        "product_id,product_name,category_name,status,display_yn,price",
                        "P001,검정 우산,우산,active,Y,8500",
                    ]
                ),
                encoding="utf-8",
            )
            settings = Settings(engine_backend="local", index_name="test", product_csv_path=csv_path)
            sync = SyncService(LocalSearchEngine([]), CsvProductSource(csv_path), settings)
            result = sync.reindex_all()
            result.failed = 1
            result.status.failed = 1
            result.status.last_error = "forced failure"

            with patch("app.sync.urllib.request.urlopen", return_value=FakeResponse()) as urlopen:
                notifier = SyncFailureNotifier("https://alerts.example.test/sync", timeout_seconds=2)
                sent = notifier.notify(result)

            self.assertTrue(sent)
            request = urlopen.call_args.args[0]
            payload = json.loads(request.data.decode("utf-8"))
            self.assertEqual("https://alerts.example.test/sync", request.full_url)
            self.assertEqual("sync_failed", payload["type"])
            self.assertEqual("reindex", payload["mode"])
            self.assertEqual(1, payload["failed"])
            self.assertEqual("forced failure", payload["status"]["last_error"])

    def test_admin_metrics_summarizes_logs_sync_engine_and_disk(self) -> None:
        with tempfile.TemporaryDirectory() as temp_dir:
            search_log = Path(temp_dir) / "search.jsonl"
            error_log = Path(temp_dir) / "error.jsonl"
            sync_log = Path(temp_dir) / "sync.jsonl"
            csv_path = Path(temp_dir) / "products.csv"
            csv_path.write_text(
                "\n".join(
                    [
                        "product_id,product_name,category_name,status,display_yn,price",
                        "P001,검정 우산,우산,active,Y,8500",
                    ]
                ),
                encoding="utf-8",
            )
            settings = Settings(
                engine_backend="local",
                index_name="test-products",
                product_csv_path=csv_path,
                search_log_path=search_log,
                error_log_path=error_log,
                sync_log_path=sync_log,
                low_score_threshold=1.1,
            )
            engine = LocalSearchEngine(
                [
                    ProductDocument(
                        product_id="P001",
                        name="검정 우산",
                        category="우산",
                        status="active",
                    )
                ]
            )
            service = AISearchService(engine, settings, SearchLogger(search_log))
            service.search(SearchRequest(mall_id="shop001", q="우산", limit=5))
            service.search(SearchRequest(mall_id="shop001", q="우산", limit=5))
            image_b64 = base64.b64encode(PNG_BYTES).decode("ascii")
            service.search(SearchRequest(mall_id="shop001", image_base64=image_b64, limit=5))
            service.log_click({"mall_id": "shop001", "product_id": "P001", "position": 1})
            error_logger = SearchLogger(error_log)
            error_logger.write(
                {
                    "type": "api_error",
                    "timestamp": "2026-05-19T00:00:00Z",
                    "method": "POST",
                    "path": "/api/ai-search",
                    "status_code": 429,
                    "detail": "image search rate limit exceeded for client",
                }
            )
            sync = SyncService(engine, CsvProductSource(csv_path), settings)
            sync_result = sync.reindex_all()
            sync.logger.write_product_event(
                "reindex",
                "P404",
                action="upsert_to_index",
                outcome="failed",
                reason="vectorization failed",
            )
            sync.logger.write_sync_failure("reindex", "acquire_sync_lock", "sync operation already running")
            sync.logger.write_cache_invalidation(
                sync_result,
                ok=False,
                report={"backend": "redis", "error": "redis scan unavailable"},
            )

            rate_limiter = object.__new__(RedisRateLimiter)
            rate_limiter.client = type(
                "FailingRedisClient",
                (),
                {
                    "incr": lambda self, key: (_ for _ in ()).throw(OSError("redis unavailable")),
                    "expire": lambda self, key, seconds: None,
                },
            )()
            rate_limiter.key_prefix = "hai"
            rate_limiter.hit("search:ip:127.0.0.1", 10, now=120.0)
            search_gate = SearchExecutionGate(max_concurrency=4, queue_timeout_seconds=0.25)
            image_gate = ImageSearchGate(max_concurrency=2, queue_timeout_seconds=0.5)

            search_cache = type(
                "FailingSearchCache",
                (),
                {
                    "status": lambda self: {
                        "backend": "redis",
                        "redis_enabled": True,
                        "ttl_seconds": 30,
                        "error_count": 3,
                        "get_errors": 1,
                    "set_errors": 1,
                    "decode_errors": 0,
                    "delete_errors": 0,
                    "clear_errors": 1,
                    "last_error": "redis unavailable",
                    "last_error_operation": "set",
                }
                },
            )()

            metrics = build_admin_metrics(
                settings,
                engine,
                service.logger,
                error_logger,
                sync,
                limit=100,
                rate_limiter=rate_limiter,
                search_cache=search_cache,
                search_singleflight=service,
                search_execution_gate=search_gate,
                image_search_gate=image_gate,
            )

            self.assertTrue(metrics["engine"]["ok"])
            self.assertTrue(str(metrics["process"]["instance_id"]))
            self.assertEqual("local", metrics["engine"]["backend"])
            self.assertEqual("redis", metrics["rate_limit"]["backend"])
            self.assertEqual(1, metrics["rate_limit"]["fallback_events"])
            self.assertTrue(metrics["rate_limit"]["fallback_active"])
            self.assertEqual(10000, metrics["rate_limit"]["fallback_max_buckets"])
            self.assertEqual(1.0, metrics["rate_limit"]["fallback_prune_interval_seconds"])
            self.assertEqual(0, metrics["rate_limit"]["fallback_pruned_buckets"])
            self.assertEqual("redis unavailable", metrics["rate_limit"]["last_error"])
            self.assertEqual(300, metrics["rate_limit"]["limits"]["search_per_minute"])
            self.assertEqual(20, metrics["rate_limit"]["limits"]["image_per_minute"])
            self.assertEqual("redis", metrics["cache"]["backend"])
            self.assertEqual(3, metrics["cache"]["error_count"])
            self.assertEqual("set", metrics["cache"]["last_error_operation"])
            self.assertTrue(metrics["singleflight"]["enabled"])
            self.assertEqual(settings.cache_miss_wait_seconds, metrics["singleflight"]["wait_timeout_seconds"])
            self.assertEqual(0, metrics["singleflight"]["in_flight"])
            self.assertEqual(0, metrics["singleflight"]["wait_events"])
            self.assertEqual(0, metrics["singleflight"]["wait_timeouts"])
            self.assertTrue(metrics["image_validation"]["enabled"])
            self.assertEqual(settings.cache_miss_wait_seconds, metrics["image_validation"]["wait_timeout_seconds"])
