    def test_admin_metrics_reports_isolated_log_write_failures(self) -> None:
        with tempfile.TemporaryDirectory() as temp_dir:
            search_log = Path(temp_dir) / "search.jsonl"
            error_log = Path(temp_dir) / "error.jsonl"
            sync_log = Path(temp_dir) / "sync.jsonl"
            csv_path = Path(temp_dir) / "products.csv"
            csv_path.write_text("product_id,product_name\n", encoding="utf-8")
            settings = Settings(
                engine_backend="local",
                product_csv_path=csv_path,
                search_log_path=search_log,
                error_log_path=error_log,
                sync_log_path=sync_log,
            )
            engine = LocalSearchEngine([])
            search_logger = SearchLogger(search_log)
            error_logger = SearchLogger(error_log)
            sync = SyncService(engine, CsvProductSource(csv_path), settings)

            with patch.object(search_service_module.os, "open", side_effect=OSError("read-only filesystem")):
                search_logger.write({"type": "search", "index": 1})

            metrics = build_admin_metrics(settings, engine, search_logger, error_logger, sync)
            self.assertEqual(1, metrics["logs"]["search"]["write_errors"])
            self.assertEqual(0, metrics["logs"]["search"]["write_events"])
            self.assertEqual("OSError", metrics["logs"]["search"]["last_write_error_type"])
            self.assertIn("read-only filesystem", metrics["logs"]["search"]["last_write_error"])
            self.assertEqual(0, metrics["logs"]["error"]["write_errors"])
            self.assertEqual(0, metrics["logs"]["error"]["write_events"])
            self.assertIn("search_log_write_errors", {item["code"] for item in metrics["alerts"]})
            prometheus = metrics_to_prometheus(metrics)
            self.assertIn('haeorum_log_write_error_events{log="search"', prometheus)
            self.assertIn('haeorum_log_write_events{log="search"', prometheus)
            self.assertRegex(prometheus, r'haeorum_log_write_error_events\{[^}]*log="search"[^}]*\} 1')
            self.assertRegex(prometheus, r'haeorum_log_write_events\{[^}]*log="search"[^}]*\} 0')

    def test_search_cache_metrics_are_normalized_when_cache_status_is_missing_or_failing(self) -> None:
        settings = Settings(redis_url="redis://cache.example.test:6379/0", cache_ttl_seconds=45)

        none_summary = search_cache_summary(None, settings)
        self.assertEqual("none", none_summary["backend"])
        self.assertTrue(none_summary["redis_enabled"])
        self.assertEqual(45, none_summary["ttl_seconds"])
        self.assertEqual(0, none_summary["get_errors"])
        self.assertEqual(0, none_summary["set_errors"])
        self.assertEqual(0, none_summary["decode_errors"])
        self.assertEqual(0, none_summary["delete_errors"])
        self.assertEqual(0, none_summary["clear_errors"])
        self.assertEqual(0, none_summary["lock_errors"])
        self.assertEqual(0, none_summary["lock_release_errors"])
        self.assertEqual(0, none_summary["lock_claims"])
        self.assertEqual(0, none_summary["lock_contention_events"])
        self.assertEqual(0, none_summary["error_count"])
        self.assertEqual(0, none_summary["evictions"])

        memory_summary = search_cache_summary(
            MemorySearchCache(30, max_entries=2),
            Settings(cache_ttl_seconds=30, cache_max_entries=2),
        )
        self.assertEqual("memory", memory_summary["backend"])
        self.assertFalse(memory_summary["redis_enabled"])
        self.assertEqual(2, memory_summary["max_entries"])
        self.assertEqual(0, memory_summary["evictions"])

        class FailingCache:
            def status(self) -> dict[str, object]:
                raise RuntimeError("redis status unavailable")

        failing_summary = search_cache_summary(FailingCache(), settings)
        self.assertEqual("FailingCache", failing_summary["backend"])
        self.assertEqual(1, failing_summary["error_count"])
        self.assertEqual(0, failing_summary["clear_errors"])
        self.assertEqual("status", failing_summary["last_error_operation"])
        self.assertIn("redis status unavailable", failing_summary["last_error"])

    def test_image_search_queue_metrics_are_normalized(self) -> None:
        settings = Settings(image_search_max_concurrency=4, image_search_queue_timeout_seconds=1.5)
