        self.assertFalse(failing_summary["enabled"])
        self.assertFalse(failing_summary["runtime_available"])
        self.assertEqual("search queue status unavailable", failing_summary["last_error"])
        self.assertEqual(0, failing_summary["in_flight"])
        self.assertEqual(0, failing_summary["wait_events"])

