    def test_logs_bound_large_nested_values(self) -> None:
        with tempfile.TemporaryDirectory() as temp_dir:
            log_path = Path(temp_dir) / "search.jsonl"
            logger = SearchLogger(log_path)
            deep: object = "deep-secret"
            for _ in range(10):
                deep = {"child": deep}
            detail = {
                "items": [{"message": f"payload {index}"} for index in range(105)],
                "large": "x" * 1500,
                "deep": deep,
            }
            detail.update({f"k{index}": index for index in range(105)})

            logger.write({"type": "api_error", "detail": detail})

            text = log_path.read_text(encoding="utf-8")
            entry = logger.tail(1)[0]

            self.assertLess(len(text), 8000)
            self.assertNotIn("deep-secret", text)
            self.assertEqual(101, len(entry["detail"]["items"]))
            self.assertEqual("...[truncated 5 items]", entry["detail"]["items"][-1])
            self.assertEqual(8, entry["detail"]["__truncated_keys__"])
            self.assertTrue(entry["detail"]["large"].endswith("...[truncated]"))
            cursor = entry["detail"]["deep"]
            while isinstance(cursor, dict):
                cursor = cursor["child"]
            self.assertEqual("[truncated-depth]", cursor)

