    def test_marqo_http_client_reuses_thread_local_connection(self) -> None:
        class FakeResponse:
            def __init__(self, status: int, payload: dict[str, object]):
                self.status = status
                self.payload = payload

            def read(self) -> bytes:
                return json.dumps(self.payload).encode("utf-8")

        class FakeConnection:
            instances: list["FakeConnection"] = []

            def __init__(self, host: str, port: int | None = None, timeout: int | float = 60):
                self.host = host
                self.port = port
                self.timeout = timeout
                self.requests: list[tuple[str, str, bytes | None, dict[str, str]]] = []
                FakeConnection.instances.append(self)

            def request(self, method: str, target: str, body: bytes | None = None, headers: dict[str, str] | None = None) -> None:
                self.requests.append((method, target, body, dict(headers or {})))

            def getresponse(self) -> FakeResponse:
                return FakeResponse(200, {"ok": True, "request_count": len(self.requests)})

            def close(self) -> None:
                pass

        with patch("app.engine.http.client.HTTPConnection", FakeConnection):
            engine = MarqoSearchEngine("http://marqo.example.test:8882/api", "products")
            first = engine._request("GET", "/indexes/products/stats", timeout=3)
            second = engine._request("POST", "/indexes/products/search", {"q": "우산"}, timeout=5)

        self.assertEqual(1, len(FakeConnection.instances))
        connection = FakeConnection.instances[0]
        self.assertEqual(("marqo.example.test", 8882), (connection.host, connection.port))
        self.assertEqual(5, connection.timeout)
        self.assertEqual(200, first[0])
        self.assertEqual(200, second[0])
        self.assertEqual(["/api/indexes/products/stats", "/api/indexes/products/search"], [item[1] for item in connection.requests])
        self.assertIsNone(connection.requests[0][2])
        self.assertEqual({"q": "우산"}, json.loads((connection.requests[1][2] or b"{}").decode("utf-8")))
        self.assertEqual("keep-alive", connection.requests[1][3]["Connection"])
        self.assertEqual(2, engine._marqo_http.stats()["requests_started"])
        self.assertEqual(2, engine._marqo_http.stats()["request_attempts"])
        self.assertEqual(1, engine._marqo_http.stats()["connections_opened"])
        self.assertEqual(1, engine._marqo_http.stats()["connection_reuses"])

