    def test_marqo_health_fails_closed_when_qwen_health_mismatches_runtime_contract(self) -> None:
        class FakeQwenHealthMarqoSearchEngine(MarqoSearchEngine):
            def __init__(self, qwen_health: dict[str, object]):
                super().__init__(
                    "http://marqo.example.test",
                    "products",
                    embedding_backend="qwen",
                    qwen_embedding_dimensions=2048,
                    qwen_model="Qwen/Qwen3-VL-Embedding-2B",
                )
                self.qwen_health = qwen_health

            def _request(self, method: str, path: str, payload: object = None, timeout: int = 60):
                if path == "/":
                    return 200, {"message": "ok"}, 1.0
                if path.endswith("/stats"):
                    return 200, {"numberOfDocuments": 300}, 1.0
                raise AssertionError(path)

            def _qwen_request(self, method: str, path: str, payload: object = None, timeout: int = 60):
                assert path == "/health"
                return 200, self.qwen_health, 1.0

        healthy = FakeQwenHealthMarqoSearchEngine(
            {
                "ready": True,
                "model": "Qwen/Qwen3-VL-Embedding-2B",
                "dimensions": 2048,
                "loadError": None,
            }
        ).health()
        mismatched = FakeQwenHealthMarqoSearchEngine(
            {
                "ready": True,
                "model": "Qwen/Qwen3-VL-Embedding-2B-old",
                "dimensions": 1024,
                "loadError": None,
            }
        ).health()

        self.assertTrue(healthy["ok"])
        self.assertTrue(healthy["ready"])
        self.assertFalse(mismatched["ok"])
        self.assertFalse(mismatched["ready"])
        self.assertIn("qwen_health.model", mismatched["qwen_health_problems"])
        self.assertIn("qwen_health.dimensions", mismatched["qwen_health_problems"])

    def test_qwen_embedding_response_validation_blocks_bad_vectors_before_marqo(self) -> None:
        class FakeQwenMarqoSearchEngine(MarqoSearchEngine):
            def __init__(self, response: dict[str, object]):
                super().__init__(
                    "http://marqo.example.test",
                    "products",
                    embedding_backend="qwen",
                    qwen_embedding_dimensions=2,
                )
                self.response = response

            def _qwen_request(self, method: str, path: str, payload: object = None, timeout: int = 60):
                return 200, self.response, 1.0

        with self.assertRaisesRegex(ValueError, "must contain an embeddings list"):
            FakeQwenMarqoSearchEngine({}).qwen_embed_query_texts(["우산"])
        with self.assertRaisesRegex(ValueError, "returned 0 embeddings; expected 1"):
            FakeQwenMarqoSearchEngine({"embeddings": []}).qwen_embed_query_texts(["우산"])
        with self.assertRaisesRegex(ValueError, "has 1 dimensions; expected 2"):
            FakeQwenMarqoSearchEngine({"embeddings": [[0.1]]}).qwen_embed_query_texts(["우산"])
        with self.assertRaisesRegex(ValueError, "is not finite"):
            FakeQwenMarqoSearchEngine({"embeddings": [[0.1, float("nan")]]}).qwen_embed_images(["image"])
        self.assertEqual(
            [[1.0, 2.0]],
            FakeQwenMarqoSearchEngine({"embeddings": [[1, "2"]]}).qwen_embed_product_texts(["우산"]),
        )

    def test_qwen_marqo_payload_routes_text_and_image_to_split_vectors(self) -> None:
        class FakeQwenMarqoSearchEngine(MarqoSearchEngine):
            def qwen_embed_query_texts(self, texts: list[str], **_: object) -> list[list[float]]:
                self.last_texts = texts
                self.text_calls = getattr(self, "text_calls", [])
                self.text_calls.append(list(texts))
                return [[0.1, 0.2]]

            def qwen_embed_images(self, images: list[str], **_: object) -> list[list[float]]:
                self.last_images = images
                self.image_calls = getattr(self, "image_calls", [])
                self.image_calls.append(list(images))
                return [[0.3, 0.4]]

        engine = FakeQwenMarqoSearchEngine(
            "http://marqo.example.test",
            "products",
            embedding_backend="qwen",
            qwen_embedding_dimensions=2,
        )
        text_payload = engine.build_search_payload(
            EngineQuery(q="호텔 수건", inferred_categories=("타올",), query_synonyms={"수건": ("타올",)})
        )
        image_payload = engine.build_search_payload(EngineQuery(image_data_url="data:image/png;base64,AAAA"))
        mixed_payload = engine.build_search_payload(
            EngineQuery(
                q="노란 우산",
                image_data_url="data:image/png;base64,BBBB",
                text_weight=0.4,
                image_weight=0.6,
            )
        )

        self.assertEqual(["qwen_image_vector"], text_payload["searchableAttributes"])
        self.assertEqual([0.1, 0.2], text_payload["context"]["tensor"][0]["vector"])
        self.assertIn("호텔 수건 타올", engine.text_calls[0][0])
        self.assertIn("_haeorumAuxTextPayload", text_payload)
        self.assertEqual(0.12, text_payload["_haeorumAuxTextWeight"])
        text_auxiliary_payload = text_payload["_haeorumAuxTextPayload"]
        self.assertEqual(["qwen_text_vector"], text_auxiliary_payload["searchableAttributes"])
        self.assertEqual([0.1, 0.2], text_auxiliary_payload["context"]["tensor"][0]["vector"])
        self.assertEqual("qwen_text_vector", text_auxiliary_payload["_haeorumVectorField"])
        self.assertTrue(str(text_auxiliary_payload["_haeorumVectorSource"]).startswith("text_auxiliary"))
        self.assertEqual(["qwen_image_vector"], image_payload["searchableAttributes"])
        self.assertNotIn("_haeorumAuxTextPayload", image_payload)
        self.assertEqual([0.3, 0.4], image_payload["context"]["tensor"][0]["vector"])
        self.assertEqual(["data:image/png;base64,AAAA"], engine.image_calls[0])
        self.assertEqual(["qwen_image_vector"], mixed_payload["searchableAttributes"])
        self.assertIn("_haeorumAuxTextPayload", mixed_payload)
        self.assertEqual(["qwen_text_vector"], mixed_payload["_haeorumAuxTextPayload"]["searchableAttributes"])
        self.assertEqual([0.1, 0.2], mixed_payload["context"]["tensor"][0]["vector"])
        self.assertEqual(0.4, mixed_payload["context"]["tensor"][0]["weight"])
        self.assertEqual([0.3, 0.4], mixed_payload["context"]["tensor"][1]["vector"])
        self.assertEqual(0.6, mixed_payload["context"]["tensor"][1]["weight"])
        self.assertIn("노란", engine.text_calls[1][0])
        self.assertIn("우산", engine.text_calls[1][0])
        self.assertEqual(["data:image/png;base64,BBBB"], engine.image_calls[1])
        self.assertEqual("qwen_image_vector", mixed_payload["_haeorumVectorField"])
        self.assertEqual("text_to_image+image", mixed_payload["_haeorumVectorSource"])
        self.assertNotIn(SEARCH_TEXT_FIELD, text_payload["attributesToRetrieve"])
        self.assertFalse(text_payload["_haeorumRerankText"])

        text_only_weight_payload = engine.build_search_payload(
            EngineQuery(
                q="노란 우산",
                image_data_url="data:image/png;base64,CCCC",
                text_weight=1.0,
                image_weight=0.0,
            )
        )
        self.assertEqual(["qwen_image_vector"], text_only_weight_payload["searchableAttributes"])
        self.assertEqual(1.0, text_only_weight_payload["context"]["tensor"][0]["weight"])
        self.assertEqual(2, len(engine.text_calls))
        self.assertEqual(2, len(engine.image_calls))

