    def test_qwen_text_auxiliary_score_blends_with_image_candidates(self) -> None:
        engine = MarqoSearchEngine(
            "http://marqo.example.test",
            "products",
            embedding_backend="qwen",
            qwen_embedding_dimensions=2,
            text_auxiliary_weight=0.2,
        )
        hits = [
            EngineHit(
                document=ProductDocument(
                    product_id="P001",
                    name="노란 접이식 부채",
                    category="부채",
                    status="active",
                    mall_id="shop001",
                ),
                score=0.60,
                source_scores={"marqo": 0.60, "text_to_image": 0.60, "qwen_image_vector": 0.60},
            ),
            EngineHit(
                document=ProductDocument(
                    product_id="P002",
                    name="손 선풍기",
                    category="선풍기",
                    status="active",
                    mall_id="shop001",
                ),
                score=0.62,
                source_scores={"marqo": 0.62, "text_to_image": 0.62, "qwen_image_vector": 0.62},
            ),
        ]
        auxiliary_data = {
            "hits": [
                {
                    "_id": product_document_id("shop001", "P001"),
                    "product_id": "P001",
                    "product_name": "노란 접이식 부채",
                    "category_name": "부채",
                    "status": "active",
                    "display_yn": "Y",
                    "mall_id": "shop001",
                    "_score": 0.90,
                },
                {
                    "_id": product_document_id("shop001", "P002"),
                    "product_id": "P002",
                    "product_name": "손 선풍기",
                    "category_name": "선풍기",
                    "status": "active",
                    "display_yn": "Y",
                    "mall_id": "shop001",
                    "_score": 0.40,
                },
            ]
        }

        boosted = engine.apply_text_auxiliary_scores(
            hits,
            auxiliary_data,
            auxiliary_weight=0.2,
            auxiliary_field="qwen_text_vector",
            auxiliary_source="text_auxiliary",
        )

        self.assertEqual(["P001", "P002"], [hit.document.product_id for hit in boosted])
        self.assertAlmostEqual(0.66, boosted[0].score)
        self.assertAlmostEqual(0.576, boosted[1].score)
        self.assertEqual(0.9, boosted[0].source_scores["text_auxiliary"])
        self.assertEqual(0.9, boosted[0].source_scores["qwen_text_vector"])
        self.assertEqual(0.6, boosted[0].source_scores["marqo_primary"])

