    def test_marqo_upsert_deletes_legacy_product_id_document_after_composite_upsert(self) -> None:
        class FakeMarqoSearchEngine(MarqoSearchEngine):
            def __init__(self):
                super().__init__("http://marqo.example.test", "products")
                self.requests = []
                self._index_checked = True

            def _request(self, method, path, payload=None, timeout=60):  # type: ignore[no-untyped-def]
                self.requests.append((method, path, payload, timeout))
                if path.endswith("/documents/delete-batch"):
                    return 200, {"items": [{"_id": item, "status": 200} for item in payload]}, 1.0
                return 200, {"items": [{"_id": doc["_id"], "status": 200} for doc in payload["documents"]]}, 1.0

        engine = FakeMarqoSearchEngine()

        result = engine.upsert_products(
            [
                ProductDocument(
                    product_id="P001",
                    name="복합키 우산",
                    category="우산",
                    status="active",
                    mall_id="shop001",
                )
            ]
        )
        delete_requests = [request for request in engine.requests if request[1] == "/indexes/products/documents/delete-batch"]

        self.assertEqual(1, result["indexed"])
        self.assertEqual(1, result["legacy_deleted"])
        self.assertEqual([["P001"]], [request[2] for request in delete_requests])

