        self.assertEqual(product_count, result["delete_batch_count"])
        self.assertEqual(product_count, result["response_batch_count"])
        self.assertEqual(sample_limit, result["response_retained_count"])
        self.assertTrue(result["responses_truncated"])
        self.assertEqual(sample_limit, len(result["response"]["responses"]))
        self.assertEqual(1, result["response"]["responses"][0]["batch"])
        self.assertEqual(product_count, result["response"]["last_response"]["batch"])

