    def test_qwen_product_embedding_retries_transient_embedding_failure(self) -> None:
        class FlakyQwenMarqoSearchEngine(MarqoSearchEngine):
            def __init__(self):
                super().__init__(
                    "http://marqo.example.test",
                    "products",
                    embedding_backend="qwen",
                    qwen_embedding_dimensions=2,
                    search_retry_count=1,
                    search_retry_delay_seconds=0,
                )
                self.ensure_calls = 0
                self.qwen_calls = 0
                self.marqo_calls = 0

            def ensure_index(self) -> None:
                self.ensure_calls += 1
                self._index_checked = True

            def _qwen_request(self, method, path, payload=None, timeout=60):  # type: ignore[no-untyped-def]
                self.qwen_calls += 1
                if self.qwen_calls == 1:
                    raise urllib.error.URLError("temporary qwen outage")
                inputs = list((payload or {}).get("inputs") or [])
                return 200, {"embeddings": [[0.1, 0.2] for _ in inputs]}, 1.0

            def _request(self, method, path, payload=None, timeout=60):  # type: ignore[no-untyped-def]
                self.marqo_calls += 1
                docs = list((payload or {}).get("documents") or [])
                return 200, {"items": [{"_id": doc["_id"], "status": 200} for doc in docs]}, 1.0

        engine = FlakyQwenMarqoSearchEngine()

        result = engine.upsert_products(
            [ProductDocument(product_id="P-QWEN-RETRY", name="Qwen 재시도", category="우산", status="active")]
        )

        self.assertEqual(1, result["indexed"])
        self.assertEqual(1, engine.ensure_calls)
        self.assertEqual(2, engine.qwen_calls)
        self.assertEqual(1, engine.marqo_calls)

    def test_marqo_ensure_index_only_creates_index_when_settings_returns_404(self) -> None:
        class MissingIndexMarqoSearchEngine(MarqoSearchEngine):
            def __init__(self):
                super().__init__("http://marqo.example.test", "products")
                self.requests = []

            def _request(self, method, path, payload=None, timeout=60):  # type: ignore[no-untyped-def]
                self.requests.append((method, path, payload, timeout))
                if method == "GET" and path == "/indexes/products/settings":
                    raise BackendRequestError("index not found", status_code=404, service="marqo")
                return 200, {"index": "created"}, 1.0

        engine = MissingIndexMarqoSearchEngine()

        engine.ensure_index()

        self.assertTrue(engine._index_checked)
        self.assertEqual(
            ["GET /indexes/products/settings", "POST /indexes/products"],
            [f"{method} {path}" for method, path, _, _ in engine.requests],
        )

    def test_marqo_ensure_index_does_not_create_index_on_transient_settings_failure(self) -> None:
        class FailingSettingsMarqoSearchEngine(MarqoSearchEngine):
            def __init__(self):
                super().__init__("http://marqo.example.test", "products")
                self.requests = []

            def _request(self, method, path, payload=None, timeout=60):  # type: ignore[no-untyped-def]
                self.requests.append((method, path, payload, timeout))
                if method == "GET" and path == "/indexes/products/settings":
                    raise BackendRequestError("Marqo unavailable", status_code=500, service="marqo")
                return 200, {"index": "created"}, 1.0

        engine = FailingSettingsMarqoSearchEngine()

        with self.assertRaisesRegex(BackendRequestError, "Marqo unavailable"):
            engine.ensure_index()

        self.assertFalse(engine._index_checked)
        self.assertEqual(
            ["GET /indexes/products/settings"] * (engine.search_retry_count + 1),
            [f"{method} {path}" for method, path, _, _ in engine.requests],
        )

    def test_marqo_health_caches_admin_backend_probes(self) -> None:
        class FakeMarqoSearchEngine(MarqoSearchEngine):
            def __init__(self, cache_seconds: float):
                super().__init__(
                    "http://marqo.example.test",
                    "products",
                    admin_metrics_health_cache_seconds=cache_seconds,
                )
                self.requests = []

            def _request(self, method, path, payload=None, timeout=60):  # type: ignore[no-untyped-def]
                self.requests.append((method, path, payload, timeout))
                if method == "GET" and path == "/":
                    return 200, {"ready": True}, 1.0
                if method == "GET" and path == "/indexes/products/stats":
                    return 200, {"numberOfDocuments": len(self.requests)}, 2.0
                raise AssertionError(f"unexpected request: {method} {path}")

        cached = FakeMarqoSearchEngine(cache_seconds=30.0)

        first = cached.health()
        second = cached.health()

        self.assertEqual(["GET /", "GET /indexes/products/stats"], [f"{method} {path}" for method, path, _, _ in cached.requests])
        self.assertFalse(first["health_cache"]["hit"])
        self.assertTrue(second["health_cache"]["hit"])
        self.assertTrue(second["health_cache"]["enabled"])
        self.assertEqual(30.0, second["health_cache"]["ttl_seconds"])
        self.assertEqual(first["stats"], second["stats"])
        self.assertEqual(30.0, second["request_policy"]["admin_metrics_health_cache_seconds"])

        uncached = FakeMarqoSearchEngine(cache_seconds=0.0)
        uncached.health()
        uncached.health()

        self.assertEqual(
            ["GET /", "GET /indexes/products/stats", "GET /", "GET /indexes/products/stats"],
            [f"{method} {path}" for method, path, _, _ in uncached.requests],
        )
        self.assertFalse(uncached.health()["health_cache"]["enabled"])

