    def test_marqo_resource_qwen_contract_blocks_wrong_model_or_dimensions(self) -> None:
        health = {
            "ok": True,
            "data": {
                "ready": True,
                "model": "Qwen/Qwen3-VL-Embedding-2B",
                "dimensions": 2048,
                "loadError": None,
            },
        }
        probe = {
            "ok": True,
            "data": {
                "model": "Qwen/Qwen3-VL-Embedding-2B",
                "dimensions": 2048,
                "count": 1,
                "embedding_sample_dimensions": 2048,
            },
        }
        image_probe = {
            "ok": True,
            "data": {
                "model": "Qwen/Qwen3-VL-Embedding-2B",
                "dimensions": 2048,
                "count": 1,
                "embedding_sample_dimensions": 2048,
            },
        }
        healthy = qwen_embedding_contract(
            health,
            probe,
            image_probe,
            expected_model="Qwen/Qwen3-VL-Embedding-2B",
            expected_dimensions=2048,
        )
        stale = qwen_embedding_contract(
            {
                **health,
                "data": {**health["data"], "model": "Qwen/Qwen3-VL-Embedding-2B-old"},
            },
            {
                **probe,
                "data": {**probe["data"], "embedding_sample_dimensions": 1024},
            },
            {
                **image_probe,
                "data": {**image_probe["data"], "embedding_sample_dimensions": 1024},
            },
            expected_model="Qwen/Qwen3-VL-Embedding-2B",
            expected_dimensions=2048,
        )

        self.assertTrue(healthy["ok"])
        self.assertFalse(stale["ok"])
        self.assertIn("qwen_health.model", stale["problems"])
        self.assertIn("qwen_embedding_probe.dimensions", stale["problems"])
        self.assertIn("qwen_image_embedding_probe.dimensions", stale["problems"])

