    def test_mall_config_controls_url_template_and_api_key(self) -> None:
        with tempfile.TemporaryDirectory() as temp_dir:
            path = Path(temp_dir) / "malls.json"
            path.write_text(
                """
                {
                  "malls": [
                    {
                      "mall_id": "shop001",
                      "api_key": "public-shop001",
                      "product_url_template": "https://gift.example.test/{mall_id}/items/{product_id}",
                      "allowed_origins": ["HTTPS://SHOP001.EXAMPLE.TEST:443/"]
                    },
                    {
                      "mall_id": "disabled",
                      "api_key": "disabled-key",
                      "enabled": "false"
                    }
                  ]
                }
                """,
                encoding="utf-8",
            )
            malls = load_mall_configs(path)
            self.assertEqual(("https://shop001.example.test",), malls["shop001"].allowed_origins)
            settings = Settings(
                engine_backend="local",
                index_name="test-products",
                malls=malls,
                search_log_path=Path(temp_dir) / "search.jsonl",
            )
            service = AISearchService(
                LocalSearchEngine(
                    [
                        ProductDocument(
                            product_id="P001",
                            name="검정 우산",
                            category="우산",
                            status="active",
                        )
                    ]
                ),
                settings,
            )

            validate_mall_access(settings, "shop001", "public-shop001", origin="https://shop001.example.test")
            validate_public_header_access(settings, "public-shop001", origin="https://shop001.example.test")
            with self.assertRaisesRegex(PublicAccessError, "invalid API key"):
                validate_public_header_access(settings, "wrong", origin="https://shop001.example.test")
            with self.assertRaisesRegex(PublicAccessError, "origin is required"):
                validate_public_header_access(settings, "public-shop001")
            with self.assertRaisesRegex(PublicAccessError, "origin is not allowed"):
                validate_public_header_access(settings, "public-shop001", origin="https://evil.example.test")
            with self.assertRaises(PublicAccessError):
                validate_mall_access(settings, "shop001", "wrong", origin="https://shop001.example.test")
            with self.assertRaisesRegex(PublicAccessError, "origin is required"):
                validate_mall_access(settings, "shop001", "public-shop001")
            with self.assertRaisesRegex(PublicAccessError, "origin is not allowed"):
                validate_mall_access(settings, "shop001", "public-shop001", origin="https://evil.example.test")
            with self.assertRaises(PublicAccessError):
                validate_mall_access(settings, "disabled", "disabled-key", origin="https://shop001.example.test")
            validate_click_product_url(settings, "shop001", "https://gift.example.test/shop001/items/P001", "P001")
            validate_click_product_url(settings, "shop001", "https://gift.example.test:443/shop001/items/P001", "P001")
            with self.assertRaisesRegex(PublicAccessError, "product_url is not allowed for mall"):
                validate_click_product_url(settings, "shop001", "https://evil.example.test/items/P001", "P001")
            with self.assertRaisesRegex(PublicAccessError, "product URL template"):
                validate_click_product_url(settings, "shop001", "https://gift.example.test/admin/items/P001", "P001")
            with self.assertRaisesRegex(PublicAccessError, "product_url must contain product_id"):
                validate_click_product_url(settings, "shop001", "https://gift.example.test/shop001/items/P999", "P001")

            query_template_settings = Settings(
                malls={
                    "shop001": MallConfig(
                        mall_id="shop001",
                        api_key="public-shop001",
                        product_url_template="https://gift.example.test/product_view.asp?p_idx={product_id}",
                        allowed_origins=("https://shop001.example.test",),
                    )
                }
            )
            validate_click_product_url(
                query_template_settings,
                "shop001",
                "https://gift.example.test/product_view.asp?p_idx=P001",
                "P001",
            )
            with self.assertRaisesRegex(PublicAccessError, "product URL template"):
                validate_click_product_url(
                    query_template_settings,
                    "shop001",
                    "https://gift.example.test/product_view.asp?wrong_param=P001",
                    "P001",
                )

            result = service.search(SearchRequest(mall_id="shop001", q="우산", limit=5))
            self.assertEqual("https://gift.example.test/shop001/items/P001", result.top[0].product_url)

            encoded_service = AISearchService(
                LocalSearchEngine(
                    [
                        ProductDocument(
                            product_id="P/001?color=black#main &redirect=https://evil.example.test",
                            name="인코딩 우산",
                            category="우산",
                            status="active",
                        )
                    ]
                ),
                settings,
            )
            encoded_result = encoded_service.search(SearchRequest(mall_id="shop001", q="인코딩", limit=5))
            self.assertEqual(
                "https://gift.example.test/shop001/items/"
                "P%2F001%3Fcolor%3Dblack%23main%20%26redirect%3Dhttps%3A%2F%2Fevil.example.test",
                encoded_result.top[0].product_url,
            )

            relative_service = AISearchService(
                LocalSearchEngine(
                    [
                        ProductDocument(
                            product_id="P002",
                            name="상대 URL 우산",
                            category="우산",
                            status="active",
                            product_url="/legacy/item.asp?p_idx={product_id}",
                        )
                    ]
                ),
                settings,
            )
            relative_result = relative_service.search(SearchRequest(mall_id="shop001", q="상대", limit=5))
            self.assertEqual("https://gift.example.test/legacy/item.asp?p_idx=P002", relative_result.top[0].product_url)

            unsafe_service = AISearchService(
                LocalSearchEngine(
                    [
                        ProductDocument(
                            product_id="P003",
                            name="위험 URL 우산",
                            category="우산",
                            status="active",
                            product_url="//evil.example.test/item/{product_id}",
                        )
                    ]
                ),
                settings,
            )
            unsafe_result = unsafe_service.search(SearchRequest(mall_id="shop001", q="위험", limit=5))
            self.assertEqual("https://gift.example.test/shop001/items/P003", unsafe_result.top[0].product_url)

            absolute_service = AISearchService(
                LocalSearchEngine(
                    [
                        ProductDocument(
                            product_id="P004",
                            name="같은 도메인 우산",
                            category="우산",
                            status="active",
                            product_url="https://gift.example.test/custom/item.asp?p_idx={product_id}",
                        ),
                        ProductDocument(
                            product_id="P005",
                            name="외부 도메인 우산",
                            category="우산",
                            status="active",
                            product_url="https://evil.example.test/item/{product_id}",
                        ),
                        ProductDocument(
                            product_id="P006",
                            name="다운그레이드 우산",
                            category="우산",
                            status="active",
                            product_url="http://gift.example.test/custom/item.asp?p_idx={product_id}",
                        ),
                    ]
                ),
                settings,
            )
            same_domain_result = absolute_service.search(SearchRequest(mall_id="shop001", q="같은", limit=5))
            external_result = absolute_service.search(SearchRequest(mall_id="shop001", q="외부", limit=5))
            downgrade_result = absolute_service.search(SearchRequest(mall_id="shop001", q="다운그레이드", limit=5))
            self.assertEqual("https://gift.example.test/custom/item.asp?p_idx=P004", same_domain_result.top[0].product_url)
            self.assertEqual("https://gift.example.test/shop001/items/P005", external_result.top[0].product_url)
            self.assertEqual("https://gift.example.test/shop001/items/P006", downgrade_result.top[0].product_url)

    def test_public_header_access_uses_cached_api_key_origin_index(self) -> None:
        malls = {
            f"shop{index:04d}": MallConfig(
                mall_id=f"shop{index:04d}",
                api_key=f"pk-live-shop{index:04d}-{'x' * 24}",
                allowed_origins=(f"https://shop{index:04d}.example.test",),
                product_url_template=f"https://shop{index:04d}.example.test/product/{{product_id}}",
            )
            for index in range(1, 1701)
        }
        settings = Settings(malls=malls)

        first_index = public_header_access_index(settings)
        second_index = public_header_access_index(settings)

        self.assertIs(first_index, second_index)
        self.assertEqual(1700, first_index.enabled_count)
        self.assertEqual(
            frozenset({"https://shop1700.example.test"}),
            first_index.origins_by_api_key["pk-live-shop1700-" + "x" * 24],
        )
        validate_public_header_access(
            settings,
            "pk-live-shop1700-" + "x" * 24,
            origin="https://shop1700.example.test",
        )
        with self.assertRaisesRegex(PublicAccessError, "invalid API key"):
            validate_public_header_access(settings, "wrong", origin="https://shop1700.example.test")
        with self.assertRaisesRegex(PublicAccessError, "origin is not allowed"):
            validate_public_header_access(
                settings,
                "pk-live-shop1700-" + "x" * 24,
                origin="https://shop0001.example.test",
            )

