    def test_search_response_maps_raw_engine_scores_to_percent_range(self) -> None:
        class RawScoreEngine(LocalSearchEngine):
            name = "raw-score"

            def search(self, query: EngineQuery) -> list[EngineHit]:
                return [
                    EngineHit(
                        ProductDocument(
                            product_id="P001",
                            name="추천 우산",
                            category="우산",
                            status="active",
                        ),
                        score=8.0,
                        source_scores={"raw": 8.0},
                    ),
                    EngineHit(
                        ProductDocument(
                            product_id="P002",
                            name="일반 우산",
                            category="우산",
                            status="active",
                        ),
                        score=0.5,
                        source_scores={"raw": 0.5},
                    ),
                ]

        with tempfile.TemporaryDirectory() as temp_dir:
            service = AISearchService(
                RawScoreEngine([]),
                Settings(
                    engine_backend="local",
                    index_name="test-products",
                    search_log_path=Path(temp_dir) / "search.jsonl",
                ),
            )

            result = service.search(SearchRequest(mall_id="shop001", q="추천", limit=5))

            self.assertEqual(0.888889, result.top[0].score)
            self.assertEqual(88.9, result.top[0].score_percent)
            self.assertEqual(0.5, result.top[1].score)
            self.assertEqual(50.0, result.top[1].score_percent)
            self.assertEqual({"raw": 8.0}, result.top[0].source_scores)

