    def test_mall_config_loader_rejects_invalid_origin_and_url_template(self) -> None:
        with tempfile.TemporaryDirectory() as temp_dir:
            cases = [
                (
                    "invalid-origin.json",
                    """
                    {
                      "malls": [
                        {
                          "mall_id": "shop001",
                          "api_key": "public-shop001",
                          "product_url_template": "https://gift.example.test/{mall_id}/items/{product_id}",
                          "allowed_origins": ["https://shop001.example.test/path"]
                        }
                      ]
                    }
                    """,
                    "allowed_origins values must be origins such as https://shop.example.com",
                ),
                (
                    "missing-product-id.json",
                    """
                    {
                      "malls": [
                        {
                          "mall_id": "shop001",
                          "api_key": "public-shop001",
                          "product_url_template": "https://gift.example.test/static"
                        }
                      ]
                    }
                    """,
                    "product_url_template must contain {product_id}",
                ),
                (
                    "dangerous-template.json",
                    """
                    {
                      "malls": [
                        {
                          "mall_id": "shop001",
                          "api_key": "public-shop001",
                          "product_url_template": "javascript:alert({product_id})"
                        }
                      ]
                    }
                    """,
                    "product_url_template must format to an http(s) URL",
                ),
                (
                    "unsafe-template.json",
                    """
                    {
                      "malls": [
                        {
                          "mall_id": "shop001",
                          "api_key": "public-shop001",
                          "product_url_template": "https://shop.localhost./items/{product_id}"
                        }
                      ]
                    }
                    """,
                    "product_url_template must format to a safe public http(s) URL",
                ),
            ]
            for filename, content, expected_message in cases:
                with self.subTest(filename=filename):
                    path = Path(temp_dir) / filename
                    path.write_text(content, encoding="utf-8")
                    with self.assertRaises(ValueError) as ctx:
                        load_mall_configs(path)
                    self.assertIn(expected_message, str(ctx.exception))

