    def test_mall_config_builder_creates_valid_config_from_xlsx_export(self) -> None:
        with tempfile.TemporaryDirectory() as temp_dir:
            xlsx_path = Path(temp_dir) / "malls.xlsx"
            rows = [
                ["site_id", "domain", "api_key", "allowed_origins", "hide_prices"],
                ["shop001", "shop001.haeorumgift.com", "public-shop001", "", "Y"],
                ["shop002", "https://shop002.haeorumgift.com/home", "public-shop002", "", "N"],
            ]
            sheet_rows = []
            for row_index, row in enumerate(rows, start=1):
                cells = []
                for column_index, value in enumerate(row):
                    column = chr(ord("A") + column_index)
                    cells.append(f'<c r="{column}{row_index}" t="inlineStr"><is><t>{value}</t></is></c>')
                sheet_rows.append(f'<row r="{row_index}">{"".join(cells)}</row>')
            with zipfile.ZipFile(xlsx_path, "w") as workbook:
                workbook.writestr(
                    "xl/workbook.xml",
                    (
                        '<workbook xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main" '
                        'xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships">'
                        '<sheets><sheet name="malls" sheetId="1" r:id="rId1"/></sheets></workbook>'
                    ),
                )
                workbook.writestr(
                    "xl/_rels/workbook.xml.rels",
                    (
                        '<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">'
                        '<Relationship Id="rId1" '
                        'Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/worksheet" '
                        'Target="worksheets/sheet1.xml"/></Relationships>'
                    ),
                )
                workbook.writestr(
                    "xl/worksheets/sheet1.xml",
                    (
                        '<worksheet xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main">'
                        f'<sheetData>{"".join(sheet_rows)}</sheetData></worksheet>'
                    ),
                )

            report = build_mall_config_from_csv(xlsx_path, sort_by_mall_id=True, min_count=2)
            config_path = Path(temp_dir) / "malls.json"
            config_path.write_text(json.dumps(report["config"], ensure_ascii=False), encoding="utf-8")
            malls = load_mall_configs(config_path)

            self.assertTrue(report["ok"])
            self.assertEqual(2, report["mall_count"])
            self.assertEqual(("https://shop001.haeorumgift.com",), malls["shop001"].allowed_origins)
            self.assertTrue(malls["shop001"].hide_prices)
            self.assertEqual(("https://shop002.haeorumgift.com",), malls["shop002"].allowed_origins)

