    def test_backend_json_client_recovers_stale_keep_alive_connection_once(self) -> None:
        class FakeResponse:
            status = 200

            def read(self) -> bytes:
                return b'{"ok":true}'

            def getheader(self, name: str) -> str:
                return "keep-alive" if name.lower() == "connection" else ""

        class FakeConnection:
            instances: list["FakeConnection"] = []

            def __init__(self, host: str, port: int | None = None, timeout: int | float | None = None):
                self.requests: list[tuple[str, str]] = []
                self.closed = False
                FakeConnection.instances.append(self)

            def request(self, method: str, path: str, body: bytes | None = None, headers: dict[str, str] | None = None) -> None:
                self.requests.append((method, path))

            def getresponse(self) -> FakeResponse:
                if self is FakeConnection.instances[0]:
                    raise http.client.RemoteDisconnected("stale pooled connection")
                return FakeResponse()

            def close(self) -> None:
                self.closed = True

        client = BackendJsonHttpClient("http://backend.example.test/base", "Marqo")
        with patch("app.engine.http.client.HTTPConnection", FakeConnection):
            status, data, _elapsed = client.request("POST", "/search", {"q": "우산"}, timeout=3)

        self.assertEqual(200, status)
        self.assertEqual({"ok": True}, data)
        self.assertEqual(2, len(FakeConnection.instances))
        self.assertTrue(FakeConnection.instances[0].closed)
        self.assertEqual([("POST", "/base/search")], FakeConnection.instances[0].requests)
        self.assertEqual([("POST", "/base/search")], FakeConnection.instances[1].requests)
        stats = client.stats()
        self.assertEqual("thread_local_keep_alive", stats["connection_reuse"])
        self.assertEqual("http://backend.example.test/base", stats["base_url"])
        self.assertEqual("marqo", stats["service"])
        self.assertEqual(1, stats["requests_started"])
        self.assertEqual(2, stats["request_attempts"])
        self.assertEqual(1, stats["responses_received"])
        self.assertEqual(0, stats["error_responses"])
        self.assertEqual(2, stats["connections_opened"])
        self.assertEqual(0, stats["connection_reuses"])
        self.assertEqual(1, stats["stale_reconnects"])
        self.assertEqual(0, stats["connection_close_responses"])
        self.assertGreaterEqual(stats["total_elapsed_ms"], 0)
        self.assertGreaterEqual(stats["max_elapsed_ms"], 0)
        self.assertEqual(stats["last_elapsed_ms"], stats["max_elapsed_ms"])
        self.assertGreater(stats["total_request_body_bytes"], 0)
        self.assertEqual(stats["max_request_body_bytes"], stats["last_request_body_bytes"])
        self.assertEqual("RemoteDisconnected: stale pooled connection", stats["last_error"])

    def test_backend_json_client_requests_gzip_and_tracks_response_bytes(self) -> None:
        payload = b'{"ok":true,"items":[1,2,3]}'
        compressed = gzip.compress(payload)

        class FakeResponse:
            status = 200

            def read(self) -> bytes:
                return compressed

            def getheader(self, name: str) -> str:
                headers = {
                    "connection": "keep-alive",
                    "content-encoding": "gzip",
                }
                return headers.get(name.lower(), "")

        class FakeConnection:
            instances: list["FakeConnection"] = []

            def __init__(self, host: str, port: int | None = None, timeout: int | float | None = None):
                self.headers: dict[str, str] = {}
                FakeConnection.instances.append(self)

            def request(self, method: str, path: str, body: bytes | None = None, headers: dict[str, str] | None = None) -> None:
                self.headers = dict(headers or {})

            def getresponse(self) -> FakeResponse:
                return FakeResponse()

            def close(self) -> None:
                pass

        client = BackendJsonHttpClient("http://backend.example.test", "Marqo")
        with patch("app.engine.http.client.HTTPConnection", FakeConnection):
            status, data, _elapsed = client.request("GET", "/search", timeout=3)

        self.assertEqual(200, status)
        self.assertEqual({"ok": True, "items": [1, 2, 3]}, data)
        self.assertIn("gzip", FakeConnection.instances[0].headers["Accept-Encoding"])
        stats = client.stats()
        self.assertEqual(1, stats["gzip_responses"])
        self.assertEqual(len(compressed), stats["total_response_body_bytes"])
        self.assertEqual(len(payload), stats["total_decoded_response_body_bytes"])
        self.assertEqual(len(compressed), stats["last_response_body_bytes"])
        self.assertEqual(len(payload), stats["last_decoded_response_body_bytes"])

