    def test_marqo_retry_policy_respects_bounded_retry_after(self) -> None:
        engine = MarqoSearchEngine(
            "http://backend.example.test",
            "products",
            backend_retry_after_max_seconds=1.5,
        )
        attempts = 0

        def call() -> tuple[int, dict[str, object], float]:
            nonlocal attempts
            attempts += 1
            if attempts == 1:
                raise BackendRequestError(
                    "rate limited",
                    status_code=429,
                    service="marqo",
                    retry_after_seconds=7.0,
                )
            return 200, {"ok": True}, 0.0

        with patch("app.engine.time.sleep") as sleep:
            status, data, _elapsed = engine._call_with_retries(
                call,
                retry_count=1,
                retry_delay_seconds=0.1,
            )

        self.assertEqual(200, status)
        self.assertEqual({"ok": True}, data)
        self.assertEqual(2, attempts)
        sleep.assert_called_once_with(1.5)

