        self.assertIn("product URL prefix", message)

        bad_score = {**response, "top": [{**item, "score": 1.1}]}
        ok, message = validate_search_response(bad_score, payload)
        self.assertFalse(ok)
        self.assertIn("score must be 0..1", message)

        repeated_top_item = {**response, "items": [item]}
        ok, message = validate_search_response(repeated_top_item, payload)
        self.assertFalse(ok)
        self.assertIn("exclude top", message)

        duplicate_categories = {**response, "suggested_categories": ["우산", "우산"]}
        ok, message = validate_search_response(duplicate_categories, payload)
