    def test_load_test_mixed_traffic_payloads_track_mode_counts(self) -> None:
        args = type(
            "Args",
            (),
            {
                "base_url": "https://ai.example.test",
                "origin": "https://shop001.example.test",
                "scenario": "mixed-traffic",
                "traffic_mix": "text=70,image=10,mixed=20",
                "requests": 100,
                "active_users": 100,
                "mall_id": "shop001",
                "limit": 20,
            },
        )()

        payloads, mode_counts, mix_percent = build_payloads(args, "data:image/png;base64,AAAA")

        self.assertEqual(100, len(payloads))
        self.assertEqual({"text": 70, "image": 10, "mixed": 20}, mode_counts)
