    def test_load_test_cycles_multiple_reference_images(self) -> None:
        with tempfile.TemporaryDirectory() as temp_dir:
            first_image_path = Path(temp_dir) / "reference-a.png"
            second_image_path = Path(temp_dir) / "reference-b.png"
            first_image_path.write_bytes(make_png_bytes(48, 40))
            second_image_path.write_bytes(make_png_bytes(40, 48))
            image_args = type(
                "Args",
                (),
                {
                    "mode": "mixed",
                    "scenario": "single",
                    "image_file": str(first_image_path),
                    "additional_image_file": [str(second_image_path)],
                    "image_files": "",
                    "image_max_mb": 1,
                },
            )()

            image_data_urls, image_input = image_data_urls_for_args(image_args)

            payload_args = type(
                "Args",
                (),
                {
                    "scenario": "single",
                    "mode": "mixed",
                    "requests": 4,
                    "active_users": 4,
                    "mall_id": "shop001",
                    "limit": 20,
                },
            )()
            payloads, mode_counts, _ = build_payloads(payload_args, image_data_urls)

        self.assertEqual("files", image_input["source"])
        self.assertEqual(2, image_input["file_count"])
        self.assertEqual(2, image_input["unique_sha256_count"])
        self.assertEqual([str(first_image_path), str(second_image_path)], image_input["files"])
        self.assertEqual({"mixed": 4}, mode_counts)
        self.assertEqual(payloads[0]["image_base64"], payloads[2]["image_base64"])
        self.assertEqual(payloads[1]["image_base64"], payloads[3]["image_base64"])
        self.assertNotEqual(payloads[0]["image_base64"], payloads[1]["image_base64"])

