    def test_load_test_rejects_unsafe_target_args(self) -> None:
        base_args = {
            "base_url": "https://ai.example.test/",
            "origin": "https://shop001.example.test/",
            "scenario": "mixed-traffic",
            "traffic_mix": "text=70,image=10,mixed=20",
            "requests": 850,
            "active_users": 850,
            "concurrency": 100,
            "limit": 20,
            "p95_ms": 5000,
            "max_error_rate": 1.0,
            "api_server_count": 1,
            "image_file": "",
            "image_max_mb": 10,
        }
        args = type("Args", (), dict(base_args))()

        validate_load_test_args(args)

        self.assertEqual("https://ai.example.test", args.base_url)
        self.assertEqual("https://shop001.example.test", args.origin)

        cases = [
            ({"base_url": "https://user:pass@ai.example.test"}, "--base-url must not include credentials"),
            ({"base_url": "https://ai.example.test?debug=true"}, "--base-url must not include params"),
            ({"base_url": "https://169.254.169.254"}, "--base-url must not use non-public"),
            ({"base_url": "https://10.0.0.5"}, "--base-url must not use non-public"),
            ({"origin": "https://shop001.example.test/path"}, "--origin must include only scheme"),
            ({"origin": "https://192.168.1.5"}, "--origin must not use non-public"),
            ({"origin": "https://shop001.example.test\\bad"}, "--origin must not contain whitespace"),
        ]

        for override, expected_error in cases:
            with self.subTest(override=override):
                invalid_args = type("Args", (), {**base_args, **override})()
                with self.assertRaisesRegex(ValueError, expected_error):
                    validate_load_test_args(invalid_args)

        local_args = type(
            "Args",
            (),
            {**base_args, "base_url": "http://localhost:8000/", "origin": "http://localhost:8000", "allow_local_target": True},
        )()
        validate_load_test_args(local_args)
        self.assertEqual("http://localhost:8000", local_args.base_url)
        self.assertEqual("http://localhost:8000", local_args.origin)

