    def test_poc_dataset_builder_selects_balanced_active_products(self) -> None:
        products = [
            ProductDocument(
                product_id="U001",
                name="우산 1",
                category="우산",
                status="active",
                main_image_url="https://images.example.test/u001.jpg",
                product_url="https://shop001.example.test/product/U001",
                mall_id="shop001",
            ),
            ProductDocument(
                product_id="U002",
                name="우산 2",
                category="우산",
                status="active",
                main_image_url="https://images.example.test/u002.jpg",
                product_url="https://shop001.example.test/product/U002",
                mall_id="shop001",
            ),
            ProductDocument(
                product_id="T001",
                name="텀블러 1",
                category="텀블러",
                status="active",
                main_image_url="https://images.example.test/t001.jpg",
                product_url="https://shop001.example.test/product/T001",
                mall_id="shop001",
            ),
            ProductDocument(
                product_id="P001",
                name="볼펜 1",
                category="볼펜",
                status="active",
                main_image_url="https://images.example.test/p001.jpg",
                product_url="https://shop001.example.test/product/P001",
                mall_id="shop001",
            ),
            ProductDocument(
                product_id="H001",
                name="비노출 상품",
                category="우산",
                status="inactive",
                display_yn="N",
            ),
        ]

        selected = select_balanced(products, target_size=4, preferred_categories=["우산", "텀블러", "볼펜"])
        sample, report = build_poc_dataset(
            products,
            target_size=4,
            min_products=4,
            min_per_recommended_category=1,
            recommended_categories=["우산", "텀블러", "볼펜", "상패"],
        )

        self.assertEqual(["U001", "T001", "P001", "U002"], [product.product_id for product in selected])
        self.assertEqual(["U001", "T001", "P001", "U002"], [product.product_id for product in sample])
        self.assertFalse(report["ok"])
        self.assertEqual(4, report["selected_products"])
        self.assertEqual(1, report["minimum_per_recommended_category"])
        self.assertEqual({"볼펜": 1, "우산": 2, "텀블러": 1}, report["selected_categories"])
        self.assertEqual(["상패"], report["missing_recommended_categories"])
        self.assertEqual([], report["selected_missing_recommended_categories"])
        self.assertEqual([], report["selected_thin_recommended_categories"])
        self.assertEqual(0, report["selected_missing_product_url_count"])
        self.assertEqual(0, report["selected_missing_mall_id_count"])

