    def test_poc_dataset_builder_marks_sample_derived_dataset_as_local_only(self) -> None:
        products = CsvProductSource(ROOT / "sample_products.csv").fetch_all()

        _sample, report = build_poc_dataset(
            products,
            target_size=300,
            min_products=300,
            min_per_recommended_category=1,
            source_csv=ROOT / "sample_products.csv",
        )

        self.assertFalse(report["ok"])
        self.assertTrue(report["local_only"])
        self.assertTrue(report["not_operational_readiness"])
        self.assertTrue(report["source"]["csv_is_builtin_sample"])
        self.assertTrue(report["source"]["dataset_is_builtin_sample_derived"])
        self.assertGreater(report["selected_missing_product_url_count"], 0)
        self.assertGreater(report["selected_missing_mall_id_count"], 0)
        self.assertTrue(report["source_csv_fingerprint"]["exists"])
        self.assertRegex(report["source_csv_fingerprint"]["digest"], r"^[0-9a-f]{64}$")


